// AUTH: LOGIN (CLEAN & SAFE)
// ===============================
app.post("/api/login", async (req, res, next) => {
  try {
    await getDbInstance();
    // Accept multiple payload shapes from frontend
    const rawUsername =
      req.body?.username ??
      req.body?.userName ??
      req.body?.email ??
      req.body?.user ??
      null;
    const rawPassword = req.body?.password ?? req.body?.pass ?? null;
    const username = typeof rawUsername === "string" ? rawUsername.trim() : "";
    const password = typeof rawPassword === "string" ? rawPassword : "";
    if (!username || !password) {
      return res.status(400).json({
        success: false,
        message: "نام کاربری و کلمه عبور الزامی هستند.",
      });
    }
    // DEV bootstrap: only create the default admin if it does not exist.
    // Do not overwrite the password on every login attempt because older DB files,
    // file locks or readonly environments can turn that write into a 500.
    const isDev = process.env.NODE_ENV !== "production";
    const allowBootstrap =
      isDev && process.env.ALLOW_DEFAULT_ADMIN_BOOTSTRAP !== "false";
    if (allowBootstrap && username === "admin" && password === "password123") {
      try {
        await runAsync("INSERT OR IGNORE INTO roles (name) VALUES (?)", [
          "Admin",
        ]);
        const adminRole = await getAsync(
          "SELECT id FROM roles WHERE name = ?",
          ["Admin"],
        );
        const adminUser = await findUserByUsername("admin");
        if (!adminUser && adminRole?.id) {
          const hashed = await bcryptjs.hash("password123", 10);
          await runAsync(
            "INSERT INTO users (username, passwordHash, roleId) VALUES (?, ?, ?)",
            ["admin", hashed, adminRole.id],
          );
        }
      } catch (bootstrapError) {
        console.warn(
          "[login] default admin bootstrap skipped:",
          bootstrapError,
        );
      }
    }
    const user = await findUserByUsername(username);
    if (!user) {
      return res.status(401).json({
        success: false,
        message: "نام کاربری یا کلمه عبور نامعتبر است.",
      });
    }
    const passwordHash =
      typeof user.passwordHash === "string" ? user.passwordHash : "";
    if (!passwordHash) {
      console.error("[login] User record has no password/passwordHash:", {
        userId: user.id,
        username: user.username,
      });
      return res.status(500).json({
        success: false,
        message:
          "اطلاعات کاربر ناقص است. رمز عبور این کاربر را از تنظیمات کاربران بازنشانی کنید.",
      });
    }
    const isMatch = await verifyPasswordFlexible(password, passwordHash);
    if (!isMatch) {
      return res.status(401).json({
        success: false,
        message: "نام کاربری یا کلمه عبور نامعتبر است.",
      });
    }
    const token = generateToken();
    const avatarUrl = user.avatarPath
      ? `/uploads/avatars/${user.avatarPath}`
      : null;
    await runAsync(
      "UPDATE users SET lastLoginAt = strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc') WHERE id = ?",
      [user.id],
    );
    activeSessions[token] = {
      userId: user.id,
      username: user.username,
      roleName: user.roleName,
      firstName: user.firstName ?? null,
      lastName: user.lastName ?? null,
      avatarUrl,
      expires: Date.now() + SESSION_DURATION_MS,
    };
    return res.json({
      success: true,
      token,
      user: {
        id: user.id,
        username: user.username,
        roleName: user.roleName,
        firstName: user.firstName ?? null,
        lastName: user.lastName ?? null,
        lastLogin: new Date().toISOString(),
        dateAdded: user.dateAdded,
        avatarUrl,
      },
    });
  } catch (err) {
    console.error("[login] unexpected error", err);
    next(err);
  }
});
// Apply auth to all routes except public endpoints
app.use((req, res, next) => {
  const p = req.path || "";
  // Public endpoints:
  if (
    p === "/api/login" ||
    p === "/api/auth/login" ||
    p === "/api/auth/register" ||
    p.startsWith("/uploads") ||
    p.startsWith("/public") ||
    p === "/health" ||
    p.startsWith("/barcode") ||
    p.startsWith("/api/barcode")
  ) {
    return next();
  }
  return requireAuth(req as any, res as any, next as any);
});
