app.get("/api/me", async (req, res, next) => {
  try {
    if (!req.user)
      return res
        .status(404)
        .json({ success: false, message: "کاربر یافت نشد." });
    const row: any = await getAsync(
      `SELECT u.id, u.username, u.firstName, u.lastName, u.dateAdded, u.lastLoginAt, u.avatarPath, r.name as roleName
      FROM users u
      LEFT JOIN roles r ON r.id = u.roleId
      WHERE u.id = ?`,
      [req.user.id],
    );
    if (!row)
      return res
        .status(404)
        .json({ success: false, message: "کاربر یافت نشد." });
    return res.json({
      success: true,
      user: {
        id: row.id,
        username: row.username,
        roleName: row.roleName || req.user.roleName,
        firstName: row.firstName ?? null,
        lastName: row.lastName ?? null,
        lastLogin: row.lastLoginAt ?? null,
        dateAdded: row.dateAdded,
        avatarUrl: row.avatarPath ? `/uploads/avatars/${row.avatarPath}` : null,
      },
    });
  } catch (e) {
    next(e);
  }
});

app.put("/api/me/profile", async (req, res, next) => {
  try {
    if (!req.user)
      return res
        .status(401)
        .json({ success: false, message: "Unauthenticated" });
    const firstName =
      typeof req.body?.firstName === "string" ? req.body.firstName.trim() : "";
    const lastName =
      typeof req.body?.lastName === "string" ? req.body.lastName.trim() : "";
    const updated: any = await updateUserInDb(req.user.id, {
      firstName: firstName || null,
      lastName: lastName || null,
    });
    const token = (req.headers["authorization"] || "").split(" ")[1];
    if (token && activeSessions[token]) {
      activeSessions[token].firstName = updated.firstName ?? null;
      activeSessions[token].lastName = updated.lastName ?? null;
    }
    return res.json({
      success: true,
      message: "اطلاعات پروفایل ذخیره شد.",
      user: {
        id: updated.id,
        username: updated.username,
        roleName: updated.roleName,
        firstName: updated.firstName ?? null,
        lastName: updated.lastName ?? null,
        lastLogin: updated.lastLoginAt ?? null,
        dateAdded: updated.dateAdded,
        avatarUrl: updated.avatarPath
          ? `/uploads/avatars/${updated.avatarPath}`
          : null,
      },
    });
  } catch (e) {
    next(e);
  }
});
// تغییر رمز
app.post("/api/me/change-password", async (req, res, next) => {
  try {
    if (!req.user)
      return res
        .status(401)
        .json({ success: false, message: "Unauthenticated" });
    const { oldPassword, newPassword } = req.body as ChangePasswordPayload;
    if (!oldPassword || !newPassword || newPassword.length < 6) {
      return res.status(400).json({
        success: false,
        message: "اطلاعات ارائه‌شده برای تغییر رمز عبور نامعتبر است.",
      });
    }
    await changePasswordInDb(req.user.id, { oldPassword, newPassword });
    res.json({ success: true, message: "کلمه عبور با موفقیت تغییر کرد." });
  } catch (e) {
    next(e);
  }
});
// آپلود آواتار
const avatarStorage = multer.diskStorage({
  destination: (_, __, cb) => cb(null, avatarsDir),
  filename: (req, file, cb) =>
    cb(
      null,
      `avatar-${req.user!.id}-${Date.now()}-${Math.round(Math.random() * 1e9)}${path.extname(file.originalname)}`,
    ),
});
const avatarUpload = multer({
  storage: avatarStorage,
  limits: { fileSize: 2 * 1024 * 1024 },
  fileFilter: (_req, file: any, cb: FileFilterCallback) => {
    const ok =
      /jpeg|jpg|png|gif|webp/.test(file.mimetype) &&
      /jpeg|jpg|png|gif|webp/.test(
        path.extname(file.originalname).toLowerCase(),
      );
    ok ? cb(null, true) : cb(new Error("فرمت فایل آواتار نامعتبر است."));
  },
});
app.post(
  "/api/me/upload-avatar",
  avatarUpload.single("avatar"),
  async (req, res, next) => {
    try {
      if (!req.file)
        return res.status(400).json({
          success: false,
          message: "هیچ فایلی برای آپلود انتخاب نشده است.",
        });
      if (!req.user)
        return res
          .status(401)
          .json({ success: false, message: "Unauthenticated" });
      const existed = await getAsync(
        "SELECT avatarPath FROM users WHERE id = ?",
        [req.user.id],
      );
      if (existed?.avatarPath) {
        fs.unlink(join(avatarsDir, existed.avatarPath), () => {});
      }
      const updated = await updateAvatarPathInDb(
        req.user.id,
        req.file.filename,
      );
      const token = (req.headers["authorization"] || "").split(" ")[1];
      if (token && activeSessions[token])
        activeSessions[token].avatarUrl =
          `/uploads/avatars/${updated.avatarPath}`;
      res.json({
        success: true,
        message: "آواتار با موفقیت آپلود شد.",
        data: { avatarUrl: `/uploads/avatars/${updated.avatarPath}` },
      });
    } catch (e) {
      next(e);
    }
  },
);
