// P0: Manual inventory adjustment for a product
app.post(
  "/api/products/:id/adjust-stock",
  authorizeRole(["Admin", "Manager", "Warehouse"]),
  async (req: Request, res: Response, next: NextFunction) => {
    try {
      const productId = Number(req.params.id);
      if (!productId)
        return res
          .status(400)
          .json({ success: false, message: "شناسه محصول نامعتبر است." });
      const delta = Number(req.body?.delta);
      if (!Number.isFinite(delta) || delta === 0)
        return res
          .status(400)
          .json({ success: false, message: "delta نامعتبر است." });
      // @ts-ignore
      const userId = req.user?.id;
      const result = await adjustProductStockInDb(productId, {
        delta,
        reason: req.body?.reason,
        notes: req.body?.notes,
        createdByUserId: userId || null,
      });
      if (req.user) {
        try {
          addAuditLog(
            req.user.id,
            req.user.username,
            req.user.roleName,
            "update",
            "product",
            productId,
            `اصلاح موجودی محصول #${productId} (delta=${delta})`,
          );
        } catch {}
      }
      return res.json({ success: true, data: result });
    } catch (e) {
      next(e);
    }
  },
);
