// =====================================================
// P0: Purchases (stock-in receipts from suppliers)
// =====================================================
app.post(
  "/api/purchases",
  authorizeRole(["Admin", "Manager", "Warehouse"]),
  async (req: Request, res: Response, next: NextFunction) => {
    try {
      // @ts-ignore
      const userId = req.user?.id;
      const payload = { ...(req.body || {}), createdByUserId: userId || null };
      const data = await createPurchaseReceiptInDb(payload);
      // A
      // Inventory ledger IN (FIFO layers)
      try {
        const items = (data as any)?.items || [];
        for (const it of items) {
          if (it?.productId && it?.quantity) {
            const unitCost = Number(it?.unitCost || it?.price || 0);
            await recordInventoryInDb({
              productId: Number(it.productId),
              entryType: "in",
              quantity: Number(it.quantity),
              unitCost,
              refType: "purchase",
              refId: Number((data as any)?.id),
              entryDate: String(
                (data as any)?.purchaseDate || new Date().toISOString(),
              ),
            });
          }
        }
      } catch {}
      // Auto expense for inventory purchase (to make financial report real)
      try {
        const totalCost = Number((data as any)?.totalCost || 0);
        if (totalCost > 0) {
          let vendor: string | null = null;
          const supplierId = (data as any)?.supplierId;
          if (supplierId) {
            try {
              const sp = await getAsync(
                `SELECT name FROM partners WHERE id = ?`,
                [Number(supplierId)],
              );
              vendor = sp?.name ? String(sp.name) : null;
            } catch {}
          }
          const actor = req.user
            ? { userId: req.user.id, username: req.user.username }
            : undefined;
          await addExpenseToDb(
            {
              expenseDate: String(
                (data as any)?.purchaseDate || new Date().toISOString(),
              ),
              category: "inventory",
              title: `خرید کالا (رسید #${(data as any)?.id ?? ""})`,
              amount: totalCost,
              vendor,
              notes: (data as any)?.invoiceNumber
                ? `فاکتور: ${(data as any).invoiceNumber}`
                : null,
            } as any,
            actor as any,
          );
        }
      } catch {}
      if (req.user) {
        try {
          addAuditLog(
            req.user.id,
            req.user.username,
            req.user.roleName,
            "create",
            "purchase",
            data?.id || null,
            `ثبت رسید خرید #${data?.id ?? ""}`,
          );
        } catch {}
      }
      return res.status(201).json({ success: true, data });
    } catch (e) {
      next(e);
    }
  },
);
