// P0: Cancel invoice (soft-cancel) + Returns
app.post(
  "/api/sales-orders/:id/cancel",
  authorizeRole(["Admin", "Manager", "Salesperson"]),
  async (req: Request, res: Response, next: NextFunction) => {
    try {
      const orderId = Number(req.params.id);
      if (!orderId)
        return res
          .status(400)
          .json({ success: false, message: "شناسه فاکتور نامعتبر است." });
      // @ts-ignore
      const userId = req.user?.id;
      const result = await cancelSalesOrder(orderId, {
        reason: req.body?.reason,
      });
      if (!result)
        return res
          .status(404)
          .json({ success: false, message: "فاکتور یافت نشد." });
      if (req.user) {
        try {
          addAuditLog(
            req.user.id,
            req.user.username,
            req.user.roleName,
            "update",
            "sales_order",
            orderId,
            `ابطال فاکتور فروش #${orderId}` +
              (req.body?.reason ? ` | دلیل: ${req.body.reason}` : ""),
          );
        } catch {}
      }
      // Internal Telegram notification (sales topic) - template-based
      try {
        const who = String((req as any)?.user?.username || "").trim();
        const settings = await getAllSettingsAsObject();
        const baseUrl = String(settings.app_base_url || "").trim();
        const link = baseUrl ? `${baseUrl}/#/sales` : "";
        const tplKey = `telegram_tpl_sales_sales_order_cancelled`;
        const tpl =
          String((settings as any)[tplKey] || "").trim() ||
          `❌ فاکتور/سفارش لغو شد
شماره: {invoiceNo}
ثبت‌کننده: {who}
{link}`;
        const text = safeReplaceTemplate(tpl, {
          invoiceNo: orderId ? `#${orderId}` : "-",
          who,
          link,
          now: new Date().toISOString(),
        });
        await enqueueTelegramToTopicTargets(
          "sales",
          "SALES_ORDER_CANCELLED",
          text,
          { entityType: "sales_order", entityId: orderId },
        );
      } catch {}
      return res.json({ success: true, data: result });
    } catch (err) {
      next(err);
    }
  },
);
