app.post(
  "/api/settings/local-domain/generate-cert",
  authorizeRole(["Admin"]),
  async (req, res, next) => {
    try {
      const settings = await getAllSettingsAsObject();
      const hostname = normalizeLocalHostname(
        (req.body as any)?.hostname ?? settings.local_hostname ?? "kourosh",
      );
      const suffix = normalizeLocalSuffix(
        (req.body as any)?.suffix ??
          settings.local_domain_suffix ??
          "localhost",
      );
      const domain = buildLocalDomain(hostname, suffix);
      if (!hostname)
        return res
          .status(400)
          .json({ success: false, message: "نام میزبان محلی معتبر نیست." });
      if (!domain)
        return res
          .status(400)
          .json({ success: false, message: "دامنه محلی معتبر نیست." });

      const serverIp = getLocalDomainHostIp(suffix);
      const result = await generateLocalCertificate(domain, serverIp);
      const hostsLine = `${serverIp} ${domain}`;
      const hostsScript = buildWindowsHostsSetupBatch(domain, serverIp);
      const macHostsScript = buildMacHostsSetupCommand(domain, serverIp);
      await fs.promises.writeFile(localHostsScriptPath, hostsScript, "utf8");
      await fs.promises.writeFile(
        localMacHostsScriptPath,
        macHostsScript,
        "utf8",
      );
      try {
        await fs.promises.chmod(localMacHostsScriptPath, 0o755);
      } catch {}

      await updateMultipleSettings([
        { key: "local_hostname", value: hostname },
        { key: "local_domain_suffix", value: suffix },
        { key: "local_base_url", value: `https://${domain}` },
        { key: "local_hosts_ip", value: serverIp },
        { key: "local_hosts_line", value: hostsLine },
      ]);

      res.json({
        success: true,
        message: "گواهی محلی ساخته شد.",
        data: {
          hostname,
          suffix,
          domain,
          httpsUrl: `https://${domain}`,
          certPath: result.certPath,
          keyPath: result.keyPath,
          pfxPath: result.pfxPath,
          mode: result.mode,
          serverIp,
          hostsLine,
          hostsScriptPath: localHostsScriptPath,
          hostsScriptFileName: `setup-${domain}.bat`,
          macHostsScriptPath: localMacHostsScriptPath,
          macHostsScriptFileName: `setup-${domain}.command`,
        },
      });
    } catch (e) {
      const err = e as any;
      const msg = String(err?.message || "");
      if (
        msg.includes("openssl") ||
        msg.includes("New-SelfSignedCertificate") ||
        msg.includes("PowerShell")
      ) {
        return res.status(500).json({
          success: false,
          message:
            msg ||
            "ساخت certificate محلی با خطا در عملیات مواجه شد. OpenSSL یا PowerShell certificate cmdlet در دسترس نیست.",
        });
      }
      next(e);
    }
  },
);
