app.get("/api/settings/backup", authorizeRole(["Admin"]), (_req, res) => {
  res.download(
    DB_PATH,
    `kourosh_dashboard_backup_${new Date().toISOString().split("T")[0]}.db`,
    (err) => {
      if (err)
        res
          .status(500)
          .json({ success: false, message: "خطا در دانلود فایل پشتیبان." });
    },
  );
});
const dbUpload = multer({
  storage: multer.memoryStorage(),
  fileFilter: (_req, file: any, cb: FileFilterCallback) =>
    /\.db$/i.test(file.originalname)
      ? cb(null, true)
      : cb(new Error("فایل پشتیبان باید با فرمت .db باشد.")),
});
app.post(
  "/api/settings/restore",
  authorizeRole(["Admin"]),
  dbUpload.single("dbfile"),
  async (req, res, next) => {
    if (!req.file)
      return res
        .status(400)
        .json({ success: false, message: "فایل پشتیبان انتخاب نشده است." });
    try {
      await closeDbConnection();
      fs.writeFileSync(DB_PATH, req.file.buffer);
      await getDbInstance(true);
      res.json({ success: true, message: "پایگاه داده با موفقیت بازیابی شد." });
    } catch (e) {
      next(e);
    }
  },
);
