app.post(
  "/api/backup/restore",
  authorizeRole(["Admin"]),
  async (req, res, next) => {
    const { fileName } = req.body || {};
    if (!fileName)
      return res
        .status(400)
        .json({ success: false, message: "نام فایل بکاپ مشخص نیست." });
    try {
      const p = getBackupPath(fileName);
      await closeDbConnection();
      fs.copyFileSync(p, DB_PATH);
      await getDbInstance(true);
      res.json({
        success: true,
        message:
          "بازیابی از بکاپ با موفقیت انجام شد. لطفاً برنامه را ریستارت کنید.",
      });
    } catch (e) {
      next(e);
    }
  },
);
