app.post(
  "/api/installment-sales",
  authorizeRole(["Admin", "Manager", "Salesperson"]),
  async (req, res, next) => {
    try {
      const payload = req.body as InstallmentSalePayload;
      const errors = validateInstallmentSalePayload(payload);
      if (errors.length) {
        return res
          .status(400)
          .json({ success: false, message: errors.join(" ") });
      }
      const data = await addInstallmentSaleToDb(payload);
      try {
        if (data?.id)
          await sendCustomCustomerNotification(
            "INSTALLMENT_SALE_CREATED",
            Number(data.id),
            "both",
          );
      } catch (notifyErr) {
        console.warn("installment created notify failed:", notifyErr);
      }
      try {
        if (data?.customerId)
          await sendCustomCustomerNotification(
            "ACCOUNT_BALANCE_STATUS",
            Number(data.customerId),
            "both",
          );
      } catch {}
      if (req.user) {
        try {
          addAuditLog(
            req.user.id,
            req.user.username,
            req.user.roleName,
            "create",
            "installment_sale",
            data?.id || null,
            `ثبت فروش اقساطی #${data?.id ?? ""}`,
          );
        } catch {}
      }
      res.status(201).json({ success: true, data });
    } catch (e: any) {
      console.error("POST /api/installment-sales failed:", e?.message || e);
      return res.status(500).json({
        success: false,
        message: e?.message || "خطا در ثبت فروش اقساطی.",
      });
    }
  },
);
