app.post(
  "/api/installment-sales/check/:id/cash-payment",
  authorizeRole(["Admin", "Manager", "Salesperson"]),
  async (req, res, next) => {
    try {
      const { amount, date, notes } = req.body || {};
      const normalizedAmount = parsePositiveMoneyAmount(amount);
      if (!normalizedAmount || !date)
        return res.status(400).json({
          success: false,
          message: "مبلغ و تاریخ دریافت نقدی الزامی است.",
        });
      const isoDate = moment(
        date,
        ["jYYYY/jMM/jDD", "YYYY/MM/DD", "YYYY-MM-DD", moment.ISO_8601],
        true,
      )
        .locale("en")
        .format("YYYY-MM-DD");
      if (!moment(isoDate, "YYYY-MM-DD", true).isValid())
        return res
          .status(400)
          .json({ success: false, message: "فرمت تاریخ نامعتبر است." });
      const x = await addCheckRecoveryPaymentToDb(
        +req.params.id,
        normalizedAmount,
        isoDate,
        notes,
      );
      res.status(201).json({
        success: true,
        data: x,
        message: "دریافت نقدی بابت چک با موفقیت ثبت شد.",
      });
    } catch (e) {
      next(e);
    }
  },
);
const parsePositiveMoneyAmount = (value: any): number => {
  const normalized = Number(
    String(value ?? "")
      .replace(/[۰-۹]/g, (d) => "۰۱۲۳۴۵۶۷۸۹".indexOf(d).toString())
      .replace(/[٠-٩]/g, (d) => "٠١٢٣٤٥٦٧٨٩".indexOf(d).toString())
      .replace(/[^\d.-]/g, ""),
  );
  return Number.isFinite(normalized) && normalized > 0 ? normalized : 0;
};

app.post(
  "/api/installment-sales/payment/:paymentId/transaction",
  authorizeRole(["Admin", "Manager", "Salesperson"]),
  async (req, res, next) => {
    try {
      const { amount, date, notes } = req.body || {};
      const normalizedAmount = parsePositiveMoneyAmount(amount);
      if (!normalizedAmount || !date)
        return res
          .status(400)
          .json({ success: false, message: "مبلغ و تاریخ پرداخت الزامی است." });
      const isoDate = moment(
        date,
        ["jYYYY/jMM/jDD", "YYYY/MM/DD", "YYYY-MM-DD", moment.ISO_8601],
        true,
      )
        .locale("en")
        .format("YYYY-MM-DD");
      if (!moment(isoDate, "YYYY-MM-DD", true).isValid())
        return res
          .status(400)
          .json({ success: false, message: "فرمت تاریخ نامعتبر است." });
      // Detect "final payment" (when all installments in a sale become fully paid)
      const paymentRow = await getAsync(
        "SELECT saleId FROM installment_payments WHERE id = ?",
        [+req.params.paymentId],
      );
      const saleIdForFinal = paymentRow?.saleId
        ? Number(paymentRow.saleId)
        : null;
      let unpaidBefore = 0;
      if (saleIdForFinal) {
        const r = await getAsync(
          "SELECT COUNT(1) as cnt FROM installment_payments WHERE saleId = ? AND status != 'پرداخت شده'",
          [saleIdForFinal],
        );
        unpaidBefore = Number(r?.cnt || 0);
      }
      const x = await addInstallmentTransactionToDb(
        +req.params.paymentId,
        normalizedAmount,
        isoDate,
        notes,
      );
      try {
        await sendCustomCustomerNotification(
          "INSTALLMENT_PAYMENT_RECEIVED",
          +req.params.paymentId,
          "both",
          { amount: normalizedAmount },
        );
      } catch (notifyErr) {
        console.warn("installment payment notify failed:", notifyErr);
      }
      // Re-check unpaid installments AFTER the transaction; if it transitioned to 0 unpaid, send "INSTALLMENT_COMPLETED" SMS
      let sms: any = undefined;
      let finalizedNow = false;
      let smsAttempted = false;
      let smsSuccess = false;
      let smsError: string | undefined = undefined;
      try {
        if (saleIdForFinal && unpaidBefore > 0) {
          const r2 = await getAsync(
            "SELECT COUNT(1) as cnt FROM installment_payments WHERE saleId = ? AND status != 'پرداخت شده'",
            [saleIdForFinal],
          );
          const unpaidAfter = Number(r2?.cnt || 0);
          if (unpaidAfter === 0) {
            finalizedNow = true;
            try {
              await sendCustomCustomerNotification(
                "INSTALLMENT_SETTLED",
                Number(saleIdForFinal),
                "both",
              );
            } catch {}
            const settings = await getAllSettingsAsObject();
            const provider: string = (
              settings.sms_provider || "meli_payamak"
            ).toLowerCase();
            const s = await getInstallmentSaleDetailsForSms(saleIdForFinal);
            if (s?.customerPhoneNumber) {
              const recipientNumber = s.customerPhoneNumber;
              const tokens = [
                s.customerFullName,
                String(s.saleId),
                formatPriceForSms(s.totalPrice),
              ];
              // Provider-specific identifiers (pattern-only)
              const meliBodyId =
                settings.meli_payamak_installment_completed_pattern_id
                  ? Number(
                      settings.meli_payamak_installment_completed_pattern_id,
                    )
                  : undefined;
              const kavenegarTemplate =
                settings.kavenegar_installment_completed_template;
              const smsIrTemplateId =
                settings.sms_ir_installment_completed_template_id
                  ? Number(settings.sms_ir_installment_completed_template_id)
                  : undefined;
              const ippanelPatternCode =
                settings.ippanel_installment_completed_pattern_code;
              const telegramTemplate =
                settings.telegram_installment_completed_message;
              switch (provider) {
                case "meli_payamak": {
                  const username = settings.meli_payamak_username;
                  const password = settings.meli_payamak_password;
                  if (username && password && meliBodyId) {
                    smsAttempted = true;
                    sms = await sendMeliPayamakPatternSms(
                      recipientNumber,
                      meliBodyId,
                      tokens,
                      username,
                      password,
                    );
                    smsSuccess = !!sms;
                  }
                  break;
                }
                case "kavenegar": {
                  const apiKey = settings.kavenegar_api_key;
                  if (apiKey && kavenegarTemplate) {
                    smsAttempted = true;
                    sms = await sendKavenegarPatternSms(
                      recipientNumber,
                      kavenegarTemplate,
                      tokens,
                      apiKey,
                    );
                    smsSuccess = !!sms;
                  }
                  break;
                }
                case "sms_ir": {
                  const apiKey = settings.sms_ir_api_key;
                  if (apiKey && smsIrTemplateId) {
                    smsAttempted = true;
                    sms = await sendSmsIrPatternSms(
                      recipientNumber,
                      smsIrTemplateId,
                      tokens,
                      apiKey,
                    );
                    smsSuccess = !!sms;
                  }
                  break;
                }
                case "ippanel": {
                  const tokenAuth = settings.ippanel_token;
                  const fromNumber = settings.ippanel_from_number;
                  if (tokenAuth && fromNumber && ippanelPatternCode) {
                    smsAttempted = true;
                    sms = await sendIppanelPatternSms(
                      recipientNumber,
                      ippanelPatternCode,
                      tokens,
                      tokenAuth,
                      fromNumber,
                    );
                    smsSuccess = !!sms;
                  }
                  break;
                }
                case "telegram": {
                  setTelegramProxy((settings as any).telegram_proxy);
                  const botToken = settings.telegram_bot_token;
                  const chatId = settings.telegram_chat_id;
                  if (botToken && chatId && telegramTemplate) {
                    smsAttempted = true;
                    const values: Record<string, string> = {
                      name: tokens[0] ?? "",
                      saleId: tokens[1] ?? "",
                      total: tokens[2] ?? "",
                      amount: tokens[2] ?? "",
                    };
                    const text = sanitizeTelegramHtml(
                      renderTplHtml(
                        markdownishToHtml(String(telegramTemplate)),
                        values,
                      ),
                    );
                    sms = await sendTelegramMessage(botToken, chatId, text, {
                      parseMode: "HTML",
                    });
                    smsSuccess = !!(sms && (sms as any).success !== false);
                  }
                  break;
                }
                default:
                  break;
              }
            }
          }
        }
      } catch (err) {
        // Never fail the payment request if SMS fails
        smsError =
          err && (err as any).message
            ? String((err as any).message)
            : "SMS_FAILED";
        console.error("Failed to auto-send INSTALLMENT_COMPLETED SMS:", err);
      }
      // Log auto-sent final payment SMS (if attempted)
      if (smsAttempted && saleIdForFinal) {
        await insertSmsLog({
          reqUser: req.user,
          provider: String(
            (await getAllSettingsAsObject()).sms_provider || "meli_payamak",
          ).toLowerCase(),
          eventType: "INSTALLMENT_COMPLETED",
          entityType: "installment",
          entityId: Number(saleIdForFinal),
          recipient:
            sms && (sms as any).to
              ? String((sms as any).to)
              : (await getInstallmentSaleDetailsForSms(saleIdForFinal))
                  ?.customerPhoneNumber || "",
          patternId: undefined,
          tokens: undefined,
          success: !!(sms && (sms as any).success),
          response: sms,
          error: smsError,
        });
      }
      res.status(201).json({
        success: true,
        data: x,
        message: "پرداخت با موفقیت ثبت شد.",
        finalizedNow,
        smsAttempted,
        smsSuccess,
        smsError,
        sms,
      });
    } catch (e) {
      next(e);
    }
  },
);
