app.get(
  "/api/expenses/title-options",
  authorizeRole(["Admin", "Manager"]),
  async (_req, res) => {
    try {
      const expenseRows: any[] = await allAsync(
        `SELECT
           title,
           category,
           COALESCE(NULLIF(TRIM(vendor), ''), '') as vendor,
           COUNT(*) as count,
           COALESCE(SUM(amount),0) as total,
           MAX(expenseDate) as lastDate,
           MAX(amount) as lastAmount,
           'expense' as source
         FROM expenses
         WHERE TRIM(title) <> ''
         GROUP BY TRIM(title)
         ORDER BY date(lastDate) DESC, count DESC
         LIMIT 250`,
        [],
      );
      const recurringRows: any[] = await allAsync(
        `SELECT
           title,
           category,
           COALESCE(NULLIF(TRIM(vendor), ''), '') as vendor,
           0 as count,
           COALESCE(amount,0) as total,
           nextRunDate as lastDate,
           amount as lastAmount,
           'recurring' as source
         FROM recurring_expenses
         WHERE TRIM(title) <> ''
         ORDER BY isActive DESC, date(nextRunDate) ASC, id DESC
         LIMIT 250`,
        [],
      );
      const map = new Map<string, any>();
      for (const row of [...expenseRows, ...recurringRows]) {
        const title = String(row.title || '').trim();
        if (!title) continue;
        const key = title.toLowerCase();
        const current = map.get(key);
        if (!current) {
          map.set(key, {
            title,
            category: row.category || 'overhead',
            vendor: row.vendor || null,
            count: Number(row.count || 0),
            total: Number(row.total || 0),
            lastDate: row.lastDate || null,
            lastAmount: Number(row.lastAmount || 0),
            source: row.source || 'expense',
          });
        } else {
          current.count += Number(row.count || 0);
          current.total += Number(row.total || 0);
          if (!current.vendor && row.vendor) current.vendor = row.vendor;
          if (!current.category && row.category) current.category = row.category;
          if (!current.lastDate || String(row.lastDate || '') > String(current.lastDate || '')) {
            current.lastDate = row.lastDate;
            current.lastAmount = Number(row.lastAmount || current.lastAmount || 0);
          }
        }
      }
      const data = Array.from(map.values())
        .sort((a, b) => String(b.lastDate || '').localeCompare(String(a.lastDate || '')) || Number(b.count || 0) - Number(a.count || 0))
        .slice(0, 120);
      res.setHeader('Cache-Control', 'no-store');
      res.json({ success: true, data });
    } catch (e) {
      console.error('GET /api/expenses/title-options fallback', e);
      res.json({ success: true, data: [] });
    }
  },
);

app.get(
  "/api/expenses/title-history",
  authorizeRole(["Admin", "Manager"]),
  async (req, res) => {
    try {
      const title = String(req.query.title || '').trim();
      if (!title) return res.json({ success: true, data: null });
      let rows: any[] = await allAsync(
        `SELECT * FROM expenses WHERE TRIM(title) = TRIM(?) ORDER BY date(expenseDate) DESC, id DESC LIMIT 24`,
        [title],
      );
      if (!rows.length) {
        rows = await allAsync(
          `SELECT * FROM expenses WHERE title LIKE ? ORDER BY date(expenseDate) DESC, id DESC LIMIT 24`,
          [`%${title}%`],
        );
      }
      const exactStats: any = await getAsync(
        `SELECT COUNT(*) as count, COALESCE(SUM(amount),0) as total, MAX(expenseDate) as lastDate, MAX(amount) as lastAmount
         FROM expenses WHERE TRIM(title) = TRIM(?)`,
        [title],
      );
      const stats = Number(exactStats?.count || 0) > 0
        ? exactStats
        : {
            count: rows.length,
            total: rows.reduce((sum, row) => sum + Number(row.amount || 0), 0),
            lastDate: rows[0]?.expenseDate || null,
            lastAmount: rows[0]?.amount || 0,
          };
      const recurringRows: any[] = await allAsync(
        `SELECT * FROM recurring_expenses WHERE TRIM(title) = TRIM(?) ORDER BY isActive DESC, date(nextRunDate) ASC, id DESC LIMIT 8`,
        [title],
      );
      const first = rows[0] || recurringRows[0] || {};
      const data = {
        title,
        category: first.category || 'overhead',
        vendor: first.vendor || null,
        count: Number(stats?.count || 0),
        total: Number(stats?.total || 0),
        lastDate: stats?.lastDate || first.nextRunDate || null,
        lastAmount: Number(stats?.lastAmount || first.amount || 0),
        items: rows,
        recurring: recurringRows,
      };
      res.setHeader('Cache-Control', 'no-store');
      res.json({ success: true, data });
    } catch (e) {
      console.error('GET /api/expenses/title-history fallback', e);
      res.json({ success: true, data: null });
    }
  },
);

app.get(
  "/api/expenses/dashboard",
  authorizeRole(["Admin", "Manager"]),
  async (req, res) => {
    try {
      const categoryMeta = [
        {
          value: "rent",
          label: "اجاره و ملک",
          icon: "fa-solid fa-house",
          chart: "#e11d48",
        },
        {
          value: "salary",
          label: "حقوق و دستمزد",
          icon: "fa-solid fa-user-tie",
          chart: "#2563eb",
        },
        {
          value: "inventory",
          label: "خرید کالا",
          icon: "fa-solid fa-boxes-stacked",
          chart: "#059669",
        },
        {
          value: "marketing",
          label: "بازاریابی",
          icon: "fa-solid fa-bullhorn",
          chart: "#7c3aed",
        },
        {
          value: "logistics",
          label: "حمل و نقل",
          icon: "fa-solid fa-truck-fast",
          chart: "#ea580c",
        },
        {
          value: "utilities",
          label: "قبوض و زیرساخت",
          icon: "fa-solid fa-plug-circle-bolt",
          chart: "#0891b2",
        },
        {
          value: "software",
          label: "نرم‌افزار و اشتراک",
          icon: "fa-solid fa-display",
          chart: "#4f46e5",
        },
        {
          value: "repair",
          label: "تعمیرات و تجهیزات",
          icon: "fa-solid fa-screwdriver-wrench",
          chart: "#d97706",
        },
        {
          value: "tax",
          label: "مالیات و عوارض",
          icon: "fa-solid fa-file-invoice-dollar",
          chart: "#475569",
        },
        {
          value: "loan",
          label: "وام و اقساط",
          icon: "fa-solid fa-hand-holding-dollar",
          chart: "#9333ea",
        },
        {
          value: "overhead",
          label: "سایر هزینه‌ها",
          icon: "fa-solid fa-receipt",
          chart: "#64748b",
        },
      ];
      const metaFor = (category: string) =>
        categoryMeta.find((x) => x.value === category) ||
        categoryMeta[categoryMeta.length - 1];

      const fromQ = String(req.query.from || "");
      const toQ = String(req.query.to || "");
      const category = String(req.query.category || "all");
      const from = fromQ
        ? moment(fromQ).startOf("day")
        : moment().startOf("month");
      const to = toQ ? moment(toQ).endOf("day") : moment().endOf("day");
      const fromKey = from.format("YYYY-MM-DD");
      const toKey = to.format("YYYY-MM-DD");
      const days = Math.max(
        1,
        to.clone().startOf("day").diff(from.clone().startOf("day"), "days") + 1,
      );

      const where: string[] = [
        "date(expenseDate) >= date(?)",
        "date(expenseDate) <= date(?)",
      ];
      const params: any[] = [fromKey, toKey];
      if (category && category !== "all") {
        where.push("category = ?");
        params.push(category);
      }
      const whereSql = `WHERE ${where.join(" AND ")}`;

      const totalRow: any = await getAsync(
        `SELECT COALESCE(SUM(amount),0) as total, COUNT(*) as count, COALESCE(AVG(amount),0) as avgPerRecord FROM expenses ${whereSql}`,
        params,
      );
      const todayParams = [moment().format("YYYY-MM-DD")];
      const todayWhere =
        category && category !== "all"
          ? "WHERE date(expenseDate) = date(?) AND category = ?"
          : "WHERE date(expenseDate) = date(?)";
      const todayRow: any = await getAsync(
        `SELECT COALESCE(SUM(amount),0) as total FROM expenses ${todayWhere}`,
        category && category !== "all"
          ? [...todayParams, category]
          : todayParams,
      );

      const prevTo = from.clone().subtract(1, "day").endOf("day");
      const prevFrom = prevTo
        .clone()
        .subtract(days - 1, "days")
        .startOf("day");
      const prevWhere: string[] = [
        "date(expenseDate) >= date(?)",
        "date(expenseDate) <= date(?)",
      ];
      const prevParams: any[] = [
        prevFrom.format("YYYY-MM-DD"),
        prevTo.format("YYYY-MM-DD"),
      ];
      if (category && category !== "all") {
        prevWhere.push("category = ?");
        prevParams.push(category);
      }
      const prevRow: any = await getAsync(
        `SELECT COALESCE(SUM(amount),0) as total FROM expenses WHERE ${prevWhere.join(" AND ")}`,
        prevParams,
      );

      const byCategoryRows: any[] = await allAsync(
        `SELECT category, COALESCE(SUM(amount),0) as total, COUNT(*) as count FROM expenses ${whereSql} GROUP BY category ORDER BY total DESC`,
        params,
      );
      const grandTotal = Number(totalRow?.total || 0);
      const byCategory = (byCategoryRows || []).map((row: any) => {
        const meta = metaFor(String(row.category || "overhead"));
        return {
          category: String(row.category || "overhead"),
          label: meta.label,
          icon: meta.icon,
          chart: meta.chart,
          total: Number(row.total || 0),
          count: Number(row.count || 0),
          percent:
            grandTotal > 0 ? (Number(row.total || 0) * 100) / grandTotal : 0,
        };
      });

      const trendStart = to.clone().startOf("month").subtract(5, "months");
      const trendRows: any[] = await allAsync(
        `SELECT substr(expenseDate, 1, 7) as monthKey, COALESCE(SUM(amount),0) as total, COUNT(*) as count
       FROM expenses
       WHERE date(expenseDate) >= date(?) AND date(expenseDate) <= date(?) ${category && category !== "all" ? "AND category = ?" : ""}
       GROUP BY monthKey`,
        category && category !== "all"
          ? [trendStart.format("YYYY-MM-DD"), toKey, category]
          : [trendStart.format("YYYY-MM-DD"), toKey],
      );
      const trendMap = new Map(
        (trendRows || []).map((row: any) => [String(row.monthKey), row]),
      );
      const trend = Array.from({ length: 6 }, (_, index) => {
        const d = trendStart.clone().add(index, "months");
        const key = d.format("YYYY-MM");
        const row: any = trendMap.get(key);
        return {
          key,
          label: d.locale("fa").format("jMMM"),
          total: Number(row?.total || 0),
          count: Number(row?.count || 0),
        };
      });

      const recurringRows: any[] = await allAsync(
        `SELECT * FROM recurring_expenses ORDER BY isActive DESC, nextRunDate ASC, id DESC LIMIT 1000`,
        [],
      );
      const activeRecurring = (recurringRows || []).filter(
        (row: any) => Number(row.isActive) === 1,
      );
      const todayKey = moment().format("YYYY-MM-DD");
      const upcomingRecurring = activeRecurring.slice(0, 5).map((row: any) => {
        const daysRemaining = moment(String(row.nextRunDate), "YYYY-MM-DD")
          .startOf("day")
          .diff(moment().startOf("day"), "days");
        return { ...row, daysRemaining, isOverdue: daysRemaining < 0 };
      });

      const threshold = Math.max(5_000_000, grandTotal * 0.15);
      const importantExpenses: any[] = await allAsync(
        `SELECT * FROM expenses ${whereSql} AND amount >= ? ORDER BY amount DESC, expenseDate DESC LIMIT 6`,
        [...params, threshold],
      );
      const fallbackImportant: any[] = importantExpenses.length
        ? importantExpenses
        : await allAsync(
            `SELECT * FROM expenses ${whereSql} ORDER BY amount DESC, expenseDate DESC LIMIT 4`,
            params,
          );

      const topVendors: any[] = await allAsync(
        `SELECT COALESCE(NULLIF(TRIM(vendor), ''), 'بدون طرف حساب') as vendor, COALESCE(SUM(amount),0) as total, COUNT(*) as count
       FROM expenses ${whereSql}
       GROUP BY COALESCE(NULLIF(TRIM(vendor), ''), 'بدون طرف حساب')
       ORDER BY total DESC
       LIMIT 6`,
        params,
      );

      const recent: any[] = await allAsync(
        `SELECT * FROM expenses ${whereSql} ORDER BY expenseDate DESC, id DESC LIMIT 6`,
        params,
      );

      const previousTotal = Number(prevRow?.total || 0);
      const deltaPercent =
        previousTotal > 0
          ? ((grandTotal - previousTotal) / previousTotal) * 100
          : null;
      const topCategory = byCategory[0];
      const overdueCount = activeRecurring.filter(
        (row: any) => String(row.nextRunDate) < todayKey,
      ).length;
      const insights: any[] = [];
      if (typeof deltaPercent === "number") {
        if (deltaPercent > 15)
          insights.push({
            type: "warning",
            title: "افزایش هزینه نسبت به بازه قبل",
            description: `هزینه‌ها حدود ${Math.abs(deltaPercent).toLocaleString("fa-IR", { maximumFractionDigits: 1 })}٪ بیشتر شده‌اند.`,
            value: grandTotal,
          });
        else if (deltaPercent < -10)
          insights.push({
            type: "success",
            title: "کاهش هزینه نسبت به بازه قبل",
            description: `هزینه‌ها حدود ${Math.abs(deltaPercent).toLocaleString("fa-IR", { maximumFractionDigits: 1 })}٪ کمتر شده‌اند.`,
            value: grandTotal,
          });
      }
      if (topCategory)
        insights.push({
          type: "info",
          title: "بیشترین سهم هزینه",
          description: `${topCategory.label} با سهم ${topCategory.percent.toLocaleString("fa-IR", { maximumFractionDigits: 1 })}٪ بیشترین بخش هزینه‌هاست.`,
          value: topCategory.total,
        });
      if (overdueCount > 0)
        insights.push({
          type: "danger",
          title: "سررسید تکرارشونده عقب‌افتاده",
          description: `${overdueCount.toLocaleString("fa-IR")} مورد هزینه تکرارشونده از سررسید گذشته است.`,
          value: overdueCount,
        });
      if (!insights.length)
        insights.push({
          type: "success",
          title: "وضعیت هزینه‌ها پایدار است",
          description: "با داده‌های فعلی هشدار جدی برای این بازه دیده نمی‌شود.",
          value: grandTotal,
        });

      res.setHeader("Cache-Control", "no-store");
      res.json({
        success: true,
        data: {
          categories: categoryMeta,
          range: { from: fromKey, to: toKey, days },
          totals: {
            total: grandTotal,
            count: Number(totalRow?.count || 0),
            avgDaily: grandTotal / Math.max(1, days),
            avgPerRecord: Number(totalRow?.avgPerRecord || 0),
            todayTotal: Number(todayRow?.total || 0),
            previousTotal,
            deltaPercent,
          },
          recurring: {
            activeCount: activeRecurring.length,
            activeMonthlyTotal: activeRecurring.reduce(
              (sum: number, row: any) => sum + Number(row.amount || 0),
              0,
            ),
            overdueCount,
          },
          byCategory,
          trend,
          upcomingRecurring,
          importantExpenses: fallbackImportant || [],
          topVendors: topVendors || [],
          recent: recent || [],
          insights,
        },
      });
    } catch (e) {
      console.error("GET /api/expenses/dashboard fallback", e);
      res
        .status(500)
        .json({ success: false, message: "خطا در دریافت داشبورد هزینه‌ها" });
    }
  },
);
