app.get(
  "/api/reports/smart-insights",
  authorizeRole(["Admin", "Manager", "Salesperson", "Marketer"]),
  async (req, res, next) => {
    try {
      await ensureSmartInsightDecisionMemory();
      const nowJ = moment().locale("fa");
      const fromJ = String(
        req.query.fromDate ||
          req.query.from ||
          nowJ.clone().startOf("jMonth").format("jYYYY/jMM/jDD"),
      );
      const toJ = String(
        req.query.toDate ||
          req.query.to ||
          nowJ.clone().format("jYYYY/jMM/jDD"),
      );
      const resetAt = String(req.query.resetAt || "").trim() || null;
      const fromISO = fromShamsiStringToISO(fromJ);
      const toISO = fromShamsiStringToISO(toJ);
      if (!fromISO || !toISO)
        return res
          .status(400)
          .json({ success: false, message: "بازه زمانی نامعتبر است." });

      const toMoment = moment(toISO, "YYYY-MM-DD", true).isValid()
        ? moment(toISO, "YYYY-MM-DD")
        : moment();
      const fromMoment = moment(fromISO, "YYYY-MM-DD", true).isValid()
        ? moment(fromISO, "YYYY-MM-DD")
        : toMoment.clone().subtract(30, "day");
      const previousStartISO = fromMoment
        .clone()
        .subtract(Math.max(7, toMoment.diff(fromMoment, "day") + 1), "day")
        .format("YYYY-MM-DD");
      const recent14ISO = toMoment
        .clone()
        .subtract(14, "day")
        .format("YYYY-MM-DD");
      const todayISO = toMoment.format("YYYY-MM-DD");
      const aiEnabled = await getAiFeatureEnabledMap();
      const aiIsEnabled = (key: string) => aiEnabled[key] !== false;

      const insights: any[] = [];
      const hiddenProfitCards: any[] = [];
      const suspiciousInvoiceAudits: any[] = [];
      const addInsight = (raw: any) => {
        const score = Math.max(
          0,
          Math.min(100, Math.round(smartInsightNum(raw.score || 0))),
        );
        const severity = raw.severity || smartInsightSeverityFromScore(score);
        insights.push({
          id: raw.id || `insight-${insights.length + 1}`,
          type: raw.type || "daily_summary",
          category: raw.category || "هوشمند",
          title: raw.title || "Insight فروشگاه",
          summary: raw.summary || "",
          severity,
          score,
          confidence: Math.max(
            0,
            Math.min(100, Math.round(smartInsightNum(raw.confidence ?? 72))),
          ),
          icon: raw.icon || "fa-brain",
          tone: raw.tone || severity,
          reasons: Array.isArray(raw.reasons)
            ? raw.reasons.filter(Boolean)
            : [],
          metrics: Array.isArray(raw.metrics)
            ? raw.metrics.filter(Boolean)
            : [],
          actions: Array.isArray(raw.actions)
            ? raw.actions.filter(Boolean)
            : [],
          target: raw.target || {},
        });
      };

      const salesStats = await smartInsightSafeOne(
        `
      SELECT
        COUNT(*) AS ordersCount,
        COALESCE(SUM(grandTotal), 0) AS totalSales,
        COALESCE(SUM(discount), 0) AS invoiceDiscount,
        COUNT(DISTINCT transactionDate) AS activeDays,
        COUNT(DISTINCT customerId) AS customersCount
      FROM sales_orders
      WHERE date(substr(transactionDate, 1, 10)) BETWEEN date(?) AND date(?)
        AND COALESCE(status, 'active') = 'active'
    `,
        [fromISO, toISO],
      );

      const prevStats = await smartInsightSafeOne(
        `
      SELECT
        COUNT(*) AS ordersCount,
        COALESCE(SUM(grandTotal), 0) AS totalSales,
        COUNT(DISTINCT transactionDate) AS activeDays
      FROM sales_orders
      WHERE date(substr(transactionDate, 1, 10)) BETWEEN date(?) AND date(?)
        AND COALESCE(status, 'active') = 'active'
    `,
        [
          previousStartISO,
          fromMoment.clone().subtract(1, "day").format("YYYY-MM-DD"),
        ],
      );

      const todayStats = await smartInsightSafeOne(
        `
      SELECT COUNT(*) AS ordersCount, COALESCE(SUM(grandTotal), 0) AS totalSales, COALESCE(SUM(discount), 0) AS discount
      FROM sales_orders
      WHERE transactionDate = ? AND COALESCE(status, 'active') = 'active'
    `,
        [todayISO],
      );

      const activeDays = Math.max(1, smartInsightNum(salesStats.activeDays));
      const prevActiveDays = Math.max(1, smartInsightNum(prevStats.activeDays));
      const avgDaily = smartInsightNum(salesStats.totalSales) / activeDays;
      const prevAvgDaily =
        smartInsightNum(prevStats.totalSales) / prevActiveDays;
      const todaySales = smartInsightNum(todayStats.totalSales);
      const trendPct =
        prevAvgDaily > 0 ? ((avgDaily - prevAvgDaily) / prevAvgDaily) * 100 : 0;
      if (prevAvgDaily > 0 && trendPct <= -18) {
        addInsight({
          id: "sales-drop-vs-previous-period",
          type: "sales_drop",
          category: "فروش",
          severity: trendPct <= -35 ? "critical" : "high",
          score: Math.min(100, Math.abs(trendPct) * 1.7),
          confidence: 82,
          icon: "fa-arrow-trend-down",
          title: "افت فروش نسبت به دوره قبل شناسایی شد",
          summary: `میانگین فروش روزانه این بازه حدود ${smartInsightPercent(Math.abs(trendPct))} کمتر از دوره قبل است.`,
          reasons: [
            `میانگین روزانه دوره فعلی: ${smartInsightMoney(avgDaily)}`,
            `میانگین روزانه دوره قبل: ${smartInsightMoney(prevAvgDaily)}`,
            "این مقایسه با تعداد روزهای فعال فروش نرمال‌سازی شده است.",
          ],
          metrics: [
            { label: "افت", value: smartInsightPercent(Math.abs(trendPct)) },
            { label: "میانگین فعلی", value: smartInsightMoney(avgDaily) },
            { label: "میانگین قبل", value: smartInsightMoney(prevAvgDaily) },
          ],
          actions: [
            {
              label: "بررسی فروش غیرگوشی",
              to: "/reports/product-sales",
              icon: "fa-boxes-stacked",
            },
            {
              label: "بررسی فروش موبایل",
              to: "/reports/mobile-sales-analytics",
              icon: "fa-mobile-screen-button",
            },
          ],
        });
      } else if (prevAvgDaily > 0 && trendPct >= 22) {
        addInsight({
          id: "sales-growth-vs-previous-period",
          type: "sales_growth",
          category: "فروش",
          severity: "positive",
          score: Math.min(100, trendPct * 1.4),
          confidence: 80,
          icon: "fa-arrow-trend-up",
          title: "رشد فروش معنادار دیده می‌شود",
          summary: `میانگین فروش روزانه حدود ${smartInsightPercent(trendPct)} بهتر از دوره قبل است.`,
          reasons: [
            "رشد با مقایسه بازه فعلی و بازه قبلی هم‌اندازه محاسبه شده است.",
            "بهتر است کالاهای پرفروش این بازه برای خرید مجدد بررسی شوند.",
          ],
          metrics: [
            { label: "رشد", value: smartInsightPercent(trendPct) },
            { label: "میانگین فعلی", value: smartInsightMoney(avgDaily) },
            {
              label: "فروش امروز/انتهای بازه",
              value: smartInsightMoney(todaySales),
            },
          ],
          actions: [
            {
              label: "مشاهده پیشنهاد خرید",
              to: "/reports/analysis/suggestions",
              icon: "fa-lightbulb",
            },
          ],
        });
      }

      const reorderRows = aiIsEnabled("forecast")
        ? await smartInsightSafeRows(
            `
      SELECT
        p.id AS productId,
        p.name AS productName,
        COALESCE(p.stock_quantity, 0) AS stockQuantity,
        COALESCE(p.threshold, 5) AS thresholdQty,
        COALESCE(SUM(soi.quantity), 0) AS soldQty,
        COALESCE(SUM(soi.totalPrice), 0) AS soldAmount,
        COALESCE(SUM((COALESCE(soi.unitPrice, 0) - COALESCE(NULLIF(soi.buyPrice, 0), p.purchasePrice, 0)) * soi.quantity - COALESCE(soi.discountPerItem, 0)), 0) AS estimatedProfit
      FROM sales_order_items soi
      JOIN sales_orders so ON so.id = soi.orderId
      JOIN products p ON soi.itemType = 'inventory' AND soi.itemId = p.id
      WHERE date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?)
        AND COALESCE(so.status, 'active') = 'active'
      GROUP BY p.id, p.name, p.stock_quantity, p.threshold
      HAVING soldQty > 0 AND (stockQuantity <= thresholdQty OR stockQuantity <= soldQty OR estimatedProfit > 0)
      ORDER BY (CASE WHEN stockQuantity <= thresholdQty THEN 1 ELSE 0 END) DESC, estimatedProfit DESC, soldQty DESC
      LIMIT 5
    `,
            [recent14ISO, toISO],
          )
        : [];

      if (reorderRows.length) {
        const top = reorderRows[0] || {};
        const names = reorderRows
          .slice(0, 3)
          .map((r: any) => String(r.productName || "کالا"))
          .join("، ");
        addInsight({
          id: "smart-reorder-suggestion",
          type: "stock_reorder",
          category: "انبار و خرید",
          severity:
            smartInsightNum(top.stockQuantity) <=
            smartInsightNum(top.thresholdQty)
              ? "high"
              : "medium",
          score: 72 + Math.min(22, reorderRows.length * 4),
          confidence: 78,
          icon: "fa-cart-flatbed",
          title: "پیشنهاد خرید هوشمند برای کالاهای پرفروش",
          summary: `${reorderRows.length.toLocaleString("fa-IR")} قلم کالا در ۱۴ روز اخیر سیگنال خرید مجدد دارند؛ مثل ${names}.`,
          reasons: reorderRows
            .slice(0, 5)
            .map(
              (r: any) =>
                `${r.productName}: فروش ${smartInsightNum(r.soldQty).toLocaleString("fa-IR")} عدد، موجودی ${smartInsightNum(r.stockQuantity).toLocaleString("fa-IR")}، نقطه امن ${smartInsightNum(r.thresholdQty).toLocaleString("fa-IR")}`,
            ),
          metrics: [
            {
              label: "تعداد پیشنهاد",
              value: reorderRows.length.toLocaleString("fa-IR"),
            },
            {
              label: "سود تخمینی ۱۴ روز",
              value: smartInsightMoney(
                reorderRows.reduce(
                  (s: number, r: any) => s + smartInsightNum(r.estimatedProfit),
                  0,
                ),
              ),
            },
            {
              label: "فروش ۱۴ روز",
              value: smartInsightMoney(
                reorderRows.reduce(
                  (s: number, r: any) => s + smartInsightNum(r.soldAmount),
                  0,
                ),
              ),
            },
          ],
          actions: [
            {
              label: "رفتن به پیشنهاد خرید",
              to: "/reports/analysis/suggestions",
              icon: "fa-lightbulb",
            },
            {
              label: "مدیریت کالاها",
              to: "/products",
              icon: "fa-boxes-stacked",
            },
          ],
          target: { rows: reorderRows },
        });
      }

      const discountRows = aiIsEnabled("audit_radar")
        ? await smartInsightSafeRows(
            `
      SELECT
        so.id AS orderId,
        so.transactionDate,
        COALESCE(c.fullName, 'مشتری مهمان') AS customerName,
        COALESCE(so.subtotal, 0) AS subtotal,
        COALESCE(so.grandTotal, 0) AS grandTotal,
        COALESCE(so.discount, 0) AS invoiceDiscount,
        COALESCE(SUM(soi.discountPerItem), 0) AS itemDiscount,
        CASE WHEN COALESCE(so.subtotal, 0) > 0 THEN ((COALESCE(so.discount, 0) + COALESCE(SUM(soi.discountPerItem), 0)) / COALESCE(so.subtotal, 1)) * 100 ELSE 0 END AS discountRate
      FROM sales_orders so
      LEFT JOIN sales_order_items soi ON soi.orderId = so.id
      LEFT JOIN customers c ON c.id = so.customerId
      WHERE date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?)
        AND COALESCE(so.status, 'active') = 'active'
      GROUP BY so.id, so.transactionDate, c.fullName, so.subtotal, so.grandTotal, so.discount
      HAVING discountRate >= 12 OR (invoiceDiscount + itemDiscount) >= 1000000
      ORDER BY discountRate DESC, (invoiceDiscount + itemDiscount) DESC
      LIMIT 8
    `,
            [fromISO, toISO],
          )
        : [];

      if (discountRows.length) {
        const top = discountRows[0] || {};
        addInsight({
          id: "discount-anomaly-watch",
          type: "discount_anomaly",
          category: "کنترل تخفیف",
          severity:
            smartInsightNum(top.discountRate) >= 25 ? "critical" : "high",
          score: Math.min(96, 48 + smartInsightNum(top.discountRate) * 1.5),
          confidence: 86,
          icon: "fa-tags",
          title: "تخفیف‌های غیرعادی نیاز به بررسی دارند",
          summary: `${discountRows.length.toLocaleString("fa-IR")} فاکتور در این بازه تخفیف بالاتر از سطح معمول دارند.`,
          reasons: discountRows
            .slice(0, 5)
            .map(
              (r: any) =>
                `فاکتور ${r.orderId} برای ${r.customerName}: نرخ تخفیف ${smartInsightPercent(r.discountRate)}، مبلغ تخفیف ${smartInsightMoney(smartInsightNum(r.invoiceDiscount) + smartInsightNum(r.itemDiscount))}`,
            ),
          metrics: [
            {
              label: "بالاترین نرخ",
              value: smartInsightPercent(top.discountRate),
            },
            {
              label: "فاکتورهای مشکوک",
              value: discountRows.length.toLocaleString("fa-IR"),
            },
            {
              label: "جمع تخفیف‌های مشکوک",
              value: smartInsightMoney(
                discountRows.reduce(
                  (s: number, r: any) =>
                    s +
                    smartInsightNum(r.invoiceDiscount) +
                    smartInsightNum(r.itemDiscount),
                  0,
                ),
              ),
            },
          ],
          actions: [
            {
              label: "گزارش فروش غیرگوشی",
              to: "/reports/product-sales",
              icon: "fa-magnifying-glass-chart",
            },
          ],
          target: { rows: discountRows },
        });
      }
      const suspiciousRows = aiIsEnabled("audit_radar")
        ? await smartInsightSafeRows(
            `
      WITH order_base AS (
        SELECT orderId, SUM(COALESCE(totalPrice, 0)) AS itemBase, COUNT(*) AS itemCount, SUM(COALESCE(discountPerItem, 0)) AS itemDiscountTotal
        FROM sales_order_items
        GROUP BY orderId
      ), line_audit AS (
        SELECT
          so.id AS orderId,
          so.transactionDate,
          COALESCE(c.fullName, 'مشتری مهمان') AS customerName,
          COALESCE(so.subtotal, 0) AS subtotal,
          COALESCE(so.grandTotal, 0) AS grandTotal,
          COALESCE(so.discount, 0) AS invoiceDiscount,
          COALESCE(ob.itemBase, 0) AS itemBase,
          COALESCE(ob.itemCount, 0) AS itemCount,
          COALESCE(ob.itemDiscountTotal, 0) AS itemDiscountTotal,
          soi.description AS itemTitle,
          soi.itemType,
          COALESCE(soi.quantity, 0) AS qty,
          COALESCE(soi.unitPrice, 0) AS unitPrice,
          COALESCE(soi.totalPrice, 0) AS lineTotal,
          COALESCE(soi.discountPerItem, 0) AS lineDiscount,
          COALESCE(NULLIF(soi.buyPrice, 0), p.purchasePrice, 0) AS costPrice,
          CASE WHEN COALESCE(ob.itemBase, 0) > 0 THEN COALESCE(so.discount, 0) * COALESCE(soi.totalPrice, 0) / COALESCE(ob.itemBase, 1) ELSE 0 END AS allocatedInvoiceDiscount
        FROM sales_orders so
        JOIN sales_order_items soi ON soi.orderId = so.id
        LEFT JOIN products p ON soi.itemType = 'inventory' AND p.id = soi.itemId
        LEFT JOIN customers c ON c.id = so.customerId
        LEFT JOIN order_base ob ON ob.orderId = so.id
        WHERE date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?) AND COALESCE(so.status, 'active') = 'active'
      )
      SELECT
        orderId,
        transactionDate,
        customerName,
        MAX(subtotal) AS subtotal,
        MAX(grandTotal) AS grandTotal,
        MAX(invoiceDiscount) AS invoiceDiscount,
        MAX(itemBase) AS itemBase,
        MAX(itemCount) AS itemCount,
        MAX(itemDiscountTotal) AS itemDiscountTotal,
        SUM(lineTotal - (costPrice * qty) - allocatedInvoiceDiscount) AS estimatedProfitAfterDiscount,
        SUM(CASE WHEN itemType = 'inventory' AND costPrice > 0 AND (lineTotal - (costPrice * qty) - allocatedInvoiceDiscount) < 0 THEN 1 ELSE 0 END) AS negativeProfitLines,
        SUM(CASE WHEN itemType = 'inventory' AND costPrice > 0 AND unitPrice < costPrice THEN 1 ELSE 0 END) AS belowCostLines,
        SUM(CASE WHEN itemType = 'inventory' AND costPrice <= 0 THEN 1 ELSE 0 END) AS missingCostLines,
        SUM(CASE WHEN ABS(lineTotal - ((unitPrice * qty) - lineDiscount)) > 100 THEN 1 ELSE 0 END) AS inconsistentLineTotals,
        SUM(CASE WHEN (unitPrice * qty) > 0 AND (lineDiscount / (unitPrice * qty)) >= 0.15 THEN 1 ELSE 0 END) AS heavyItemDiscountLines,
        MAX(CASE WHEN subtotal > 0 AND invoiceDiscount / subtotal >= 0.12 THEN 1 ELSE 0 END) AS heavyInvoiceDiscount,
        MAX(CASE WHEN itemBase > 0 AND ABS((itemBase - invoiceDiscount) - grandTotal) > 5000 THEN 1 ELSE 0 END) AS totalMismatch,
        GROUP_CONCAT(CASE
          WHEN itemType = 'inventory' AND costPrice > 0 AND (lineTotal - (costPrice * qty) - allocatedInvoiceDiscount) < 0 THEN itemTitle
          WHEN itemType = 'inventory' AND costPrice > 0 AND unitPrice < costPrice THEN itemTitle
          WHEN itemType = 'inventory' AND costPrice <= 0 THEN itemTitle
          ELSE NULL END, '، ') AS riskyItems
      FROM line_audit
      GROUP BY orderId, transactionDate, customerName
      HAVING negativeProfitLines > 0 OR belowCostLines > 0 OR missingCostLines > 0 OR inconsistentLineTotals > 0 OR heavyItemDiscountLines > 0 OR heavyInvoiceDiscount > 0 OR totalMismatch > 0
      ORDER BY (negativeProfitLines * 28 + belowCostLines * 22 + missingCostLines * 14 + inconsistentLineTotals * 18 + heavyItemDiscountLines * 10 + heavyInvoiceDiscount * 16 + totalMismatch * 24) DESC,
               ABS(estimatedProfitAfterDiscount) DESC
      LIMIT 10
    `,
            [fromISO, toISO],
          )
        : [];

      suspiciousRows.forEach((r: any) => {
        const reasonParts = [
          smartInsightNum(r.negativeProfitLines) > 0
            ? `${smartInsightNum(r.negativeProfitLines).toLocaleString("fa-IR")} قلم با سود منفی بعد از تخفیف`
            : "",
          smartInsightNum(r.belowCostLines) > 0
            ? `${smartInsightNum(r.belowCostLines).toLocaleString("fa-IR")} قلم فروش زیر قیمت خرید`
            : "",
          smartInsightNum(r.missingCostLines) > 0
            ? `${smartInsightNum(r.missingCostLines).toLocaleString("fa-IR")} قلم بدون قیمت خرید معتبر`
            : "",
          smartInsightNum(r.inconsistentLineTotals) > 0
            ? "عدم تطابق جمع ردیف با قیمت×تعداد"
            : "",
          smartInsightNum(r.heavyItemDiscountLines) > 0
            ? "تخفیف سنگین روی ردیف کالا"
            : "",
          smartInsightNum(r.heavyInvoiceDiscount) > 0
            ? "تخفیف کلی سنگین روی فاکتور"
            : "",
          smartInsightNum(r.totalMismatch) > 0
            ? "اختلاف بین جمع اقلام و مبلغ نهایی"
            : "",
        ].filter(Boolean);
        const riskScore = Math.min(
          100,
          Math.round(
            smartInsightNum(r.negativeProfitLines) * 28 +
              smartInsightNum(r.belowCostLines) * 22 +
              smartInsightNum(r.missingCostLines) * 14 +
              smartInsightNum(r.inconsistentLineTotals) * 18 +
              smartInsightNum(r.heavyItemDiscountLines) * 10 +
              smartInsightNum(r.heavyInvoiceDiscount) * 16 +
              smartInsightNum(r.totalMismatch) * 24 +
              Math.min(
                18,
                Math.abs(smartInsightNum(r.estimatedProfitAfterDiscount)) /
                  1000000,
              ),
          ),
        );
        suspiciousInvoiceAudits.push({
          id: `audit-invoice-${r.orderId}`,
          orderId: r.orderId,
          transactionDate: r.transactionDate,
          customerName: r.customerName,
          riskScore,
          severity:
            riskScore >= 72 ? "critical" : riskScore >= 48 ? "high" : "medium",
          title: `فاکتور ${Number(r.orderId || 0).toLocaleString("fa-IR")} نیاز به کنترل دارد`,
          subtitle:
            reasonParts.slice(0, 3).join("، ") ||
            "سیگنال حسابداری غیرعادی پیدا شد",
          reasons: reasonParts,
          riskyItems: String(r.riskyItems || "")
            .split("، ")
            .filter(Boolean)
            .slice(0, 5),
          metrics: [
            { label: "فروش نهایی", value: smartInsightMoney(r.grandTotal) },
            {
              label: "تخفیف کل",
              value: smartInsightMoney(
                smartInsightNum(r.invoiceDiscount) +
                  smartInsightNum(r.itemDiscountTotal),
              ),
            },
            {
              label: "سود بعد از تخفیف",
              value: smartInsightMoney(r.estimatedProfitAfterDiscount),
            },
          ],
        });
      });

      if (suspiciousInvoiceAudits.length) {
        const topAudit = suspiciousInvoiceAudits[0] || {};
        const auditReasonCount = (matcher: (text: string) => boolean) =>
          suspiciousInvoiceAudits.reduce((sum: number, row: any) => {
            const reasons = Array.isArray(row.reasons) ? row.reasons : [];
            return (
              sum +
              (reasons.some((reason: any) => matcher(String(reason || "")))
                ? 1
                : 0)
            );
          }, 0);
        const auditDiscountTotal = suspiciousInvoiceAudits.reduce(
          (sum: number, row: any) => {
            const metric = (Array.isArray(row.metrics) ? row.metrics : []).find(
              (m: any) => String(m.label || "").includes("تخفیف"),
            );
            const raw = String(metric?.value || "").replace(/[^0-9.-]/g, "");
            return sum + smartInsightNum(raw);
          },
          0,
        );
        const auditConfidence = Math.max(
          55,
          Math.min(
            96,
            Math.round(
              48 +
                Math.min(24, suspiciousInvoiceAudits.length * 3) +
                Math.min(18, smartInsightNum(salesStats.ordersCount) * 0.9) +
                Math.min(10, activeDays * 1.1),
            ),
          ),
        );
        addInsight({
          id: "invoice-accounting-audit",
          type: "invoice_audit",
          category: "کنترل داخلی",
          severity: topAudit.severity || "high",
          score: Math.max(68, smartInsightNum(topAudit.riskScore)),
          confidence: auditConfidence,
          icon: "fa-shield-halved",
          title: "فاکتورهای مشکوک حسابداری شناسایی شد",
          summary: `${suspiciousInvoiceAudits.length.toLocaleString("fa-IR")} فاکتور از نظر سود منفی، تخفیف، قیمت خرید یا جمع ردیف‌ها نیاز به کنترل دارد.`,
          reasons: suspiciousInvoiceAudits
            .slice(0, 5)
            .map((r: any) => `${r.title}: ${r.subtitle}`),
          metrics: [
            {
              label: "فاکتورهای قابل کنترل",
              value: suspiciousInvoiceAudits.length.toLocaleString("fa-IR"),
            },
            {
              label: "بالاترین ریسک",
              value: `${smartInsightNum(topAudit.riskScore).toLocaleString("fa-IR")} از ۱۰۰`,
            },
            {
              label: "بالاترین تخفیف",
              value:
                auditDiscountTotal > 0
                  ? smartInsightMoney(auditDiscountTotal)
                  : (topAudit.metrics || [])[1]?.value || smartInsightMoney(0),
            },
            {
              label: "سود منفی",
              value: auditReasonCount((text) =>
                text.includes("سود منفی"),
              ).toLocaleString("fa-IR"),
            },
            {
              label: "اختلاف جمع",
              value: auditReasonCount(
                (text) => text.includes("اختلاف") || text.includes("عدم تطابق"),
              ).toLocaleString("fa-IR"),
            },
            {
              label: "تخفیف مشکوک",
              value: auditReasonCount((text) =>
                text.includes("تخفیف"),
              ).toLocaleString("fa-IR"),
            },
          ],
          actions: [
            {
              label: "مشاهده فاکتورها",
              to: "/invoices",
              icon: "fa-file-invoice",
            },
            {
              label: "گزارش فروش",
              to: "/reports/product-sales",
              icon: "fa-chart-column",
            },
          ],
          target: { rows: suspiciousInvoiceAudits },
        });
      }

      const productProfitRows = aiIsEnabled("hidden_profit")
        ? await smartInsightSafeRows(
            `
      SELECT
        p.id AS productId,
        p.name AS productName,
        COALESCE(p.stock_quantity, 0) AS stockQuantity,
        COALESCE(SUM(CASE WHEN so.id IS NOT NULL THEN soi.quantity ELSE 0 END), 0) AS soldQty,
        COALESCE(SUM(CASE WHEN so.id IS NOT NULL THEN soi.totalPrice ELSE 0 END), 0) AS soldAmount,
        COALESCE(SUM(CASE WHEN so.id IS NOT NULL THEN COALESCE(soi.discountPerItem, 0) ELSE 0 END), 0) AS itemDiscount,
        COALESCE(AVG(COALESCE(NULLIF(soi.buyPrice, 0), p.purchasePrice, 0)), 0) AS avgBuyPrice,
        COALESCE(AVG(COALESCE(soi.unitPrice, 0)), 0) AS avgSalePrice,
        COALESCE(SUM(CASE WHEN so.id IS NOT NULL THEN ((COALESCE(soi.unitPrice, 0) - COALESCE(NULLIF(soi.buyPrice, 0), p.purchasePrice, 0)) * COALESCE(soi.quantity, 0) - COALESCE(soi.discountPerItem, 0)) ELSE 0 END), 0) AS grossProfit
      FROM products p
      LEFT JOIN sales_order_items soi ON soi.itemType = 'inventory' AND soi.itemId = p.id
      LEFT JOIN sales_orders so ON so.id = soi.orderId AND date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?) AND COALESCE(so.status, 'active') = 'active'
      GROUP BY p.id, p.name, p.stock_quantity
      HAVING soldAmount > 0 OR stockQuantity > 0
      ORDER BY grossProfit DESC, soldAmount DESC
      LIMIT 80
    `,
            [fromISO, toISO],
          )
        : [];

      const highMarginSleepers = productProfitRows
        .map((r: any) => {
          const soldAmount = smartInsightNum(r.soldAmount);
          const profit = smartInsightNum(r.grossProfit);
          const margin = soldAmount > 0 ? (profit / soldAmount) * 100 : 0;
          const soldQty = smartInsightNum(r.soldQty);
          const stock = smartInsightNum(r.stockQuantity);
          const opportunity = Math.round(
            Math.max(0, margin) * 1.8 +
              Math.min(stock, 50) * 1.2 -
              soldQty * 1.4,
          );
          return { ...r, margin, opportunity };
        })
        .filter(
          (r: any) =>
            smartInsightNum(r.margin) >= 18 &&
            smartInsightNum(r.stockQuantity) > 0 &&
            smartInsightNum(r.soldQty) <= 4,
        )
        .sort(
          (a: any, b: any) =>
            smartInsightNum(b.opportunity) - smartInsightNum(a.opportunity),
        )
        .slice(0, 5);

      const priceLiftRows = productProfitRows
        .map((r: any) => {
          const soldAmount = smartInsightNum(r.soldAmount);
          const profit = smartInsightNum(r.grossProfit);
          const soldQty = smartInsightNum(r.soldQty);
          const discountRate =
            soldAmount > 0
              ? (smartInsightNum(r.itemDiscount) / soldAmount) * 100
              : 0;
          const margin = soldAmount > 0 ? (profit / soldAmount) * 100 : 0;
          const suggestedLiftPct =
            margin >= 22 && discountRate <= 3
              ? 3
              : margin >= 14 && discountRate <= 5
                ? 2
                : 1;
          const extraProfit = soldAmount * (suggestedLiftPct / 100);
          const score = Math.round(
            soldQty * 3 + margin * 1.2 - discountRate * 2,
          );
          return {
            ...r,
            margin,
            discountRate,
            suggestedLiftPct,
            extraProfit,
            score,
          };
        })
        .filter(
          (r: any) =>
            smartInsightNum(r.soldQty) >= 3 &&
            smartInsightNum(r.score) >= 20 &&
            smartInsightNum(r.suggestedLiftPct) >= 2,
        )
        .sort(
          (a: any, b: any) =>
            smartInsightNum(b.extraProfit) - smartInsightNum(a.extraProfit),
        )
        .slice(0, 5);

      const bundleRows = aiIsEnabled("hidden_profit")
        ? await smartInsightSafeRows(
            `
      WITH item_profit AS (
        SELECT
          so.id AS orderId,
          p.id AS productId,
          p.name AS productName,
          COALESCE(soi.totalPrice, 0) AS lineAmount,
          (COALESCE(soi.unitPrice, 0) - COALESCE(NULLIF(soi.buyPrice, 0), p.purchasePrice, 0)) * COALESCE(soi.quantity, 0) - COALESCE(soi.discountPerItem, 0) AS lineProfit
        FROM sales_orders so
        JOIN sales_order_items soi ON soi.orderId = so.id AND soi.itemType = 'inventory'
        JOIN products p ON p.id = soi.itemId
        WHERE date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?) AND COALESCE(so.status, 'active') = 'active'
      )
      SELECT
        a.productId AS productAId,
        a.productName AS productA,
        b.productId AS productBId,
        b.productName AS productB,
        COUNT(DISTINCT a.orderId) AS togetherOrders,
        COALESCE(SUM(a.lineAmount + b.lineAmount), 0) AS bundleSales,
        COALESCE(SUM(a.lineProfit + b.lineProfit), 0) AS bundleProfit
      FROM item_profit a
      JOIN item_profit b ON a.orderId = b.orderId AND a.productId < b.productId
      GROUP BY a.productId, a.productName, b.productId, b.productName
      HAVING togetherOrders >= 2 AND bundleProfit > 0
      ORDER BY togetherOrders DESC, bundleProfit DESC
      LIMIT 6
    `,
            [fromISO, toISO],
          )
        : [];

      if (highMarginSleepers.length) {
        hiddenProfitCards.push({
          id: "high-margin-sleepers",
          title: "کالاهای پرسودِ کم‌نمایش",
          subtitle: "این کالاها سود خوبی دارند اما در فروش دیده نمی‌شوند.",
          icon: "fa-gem",
          tone: "emerald",
          impact: smartInsightMoney(
            highMarginSleepers.reduce(
              (s: number, r: any) =>
                s + Math.max(0, smartInsightNum(r.grossProfit)),
              0,
            ),
          ),
          action: "نمایش در پیشنهاد فروش، کنار صندوق یا باندل مکمل",
          rows: highMarginSleepers.map((r: any) => ({
            productId: r.productId,
            title: r.productName,
            metric: `حاشیه سود ${smartInsightPercent(r.margin)} | موجودی ${smartInsightNum(r.stockQuantity).toLocaleString("fa-IR")}`,
            reason: `فروش کم (${smartInsightNum(r.soldQty).toLocaleString("fa-IR")}) با سود بالقوه بالا`,
          })),
        });
      }
      if (bundleRows.length) {
        hiddenProfitCards.push({
          id: "bundle-candidates",
          title: "باندل‌های طبیعی فروشگاه",
          subtitle: "این کالاها در فاکتورهای واقعی با هم خریداری شده‌اند.",
          icon: "fa-link",
          tone: "indigo",
          impact: smartInsightMoney(
            bundleRows.reduce(
              (s: number, r: any) => s + smartInsightNum(r.bundleProfit),
              0,
            ),
          ),
          action: "ساخت پیشنهاد باندل، برچسب قفسه یا پیشنهاد کنار فاکتور",
          rows: bundleRows.slice(0, 5).map((r: any) => ({
            productId: `${r.productAId}-${r.productBId}`,
            title: `${r.productA} + ${r.productB}`,
            metric: `${smartInsightNum(r.togetherOrders).toLocaleString("fa-IR")} فاکتور مشترک | سود ${smartInsightMoney(r.bundleProfit)}`,
            reason: "هم‌خرید واقعی در فاکتورهای ثبت‌شده",
          })),
        });
      }
      if (priceLiftRows.length) {
        hiddenProfitCards.push({
          id: "safe-price-lift",
          title: "افزایش قیمت کم‌ریسک",
          subtitle: "کالاهایی که ظرفیت تست افزایش قیمت محدود دارند.",
          icon: "fa-arrow-up-right-dots",
          tone: "amber",
          impact: smartInsightMoney(
            priceLiftRows.reduce(
              (s: number, r: any) => s + smartInsightNum(r.extraProfit),
              0,
            ),
          ),
          action: "تست افزایش ۲ تا ۳ درصدی برای یک هفته و ثبت نتیجه",
          rows: priceLiftRows.map((r: any) => ({
            productId: r.productId,
            title: r.productName,
            metric: `پیشنهاد ${smartInsightPercent(r.suggestedLiftPct)} | سود اضافه ${smartInsightMoney(r.extraProfit)}`,
            reason: `فروش مناسب، تخفیف پایین (${smartInsightPercent(r.discountRate)}) و حاشیه سود ${smartInsightPercent(r.margin)}`,
          })),
        });
      }

      if (hiddenProfitCards.length) {
        addInsight({
          id: "hidden-profit-detector",
          type: "hidden_profit",
          category: "فرصت سود",
          severity: hiddenProfitCards.length >= 2 ? "high" : "medium",
          score: Math.min(96, 62 + hiddenProfitCards.length * 10),
          confidence: 79,
          icon: "fa-sack-dollar",
          title: "فرصت‌های سود پنهان شناسایی شد",
          summary: `${hiddenProfitCards.length.toLocaleString("fa-IR")} مسیر افزایش سود از دل داده فروش و موجودی پیدا شد؛ از کالاهای پرسود کم‌نمایش تا باندل‌های طبیعی.`,
          reasons: hiddenProfitCards.map((c: any) => `${c.title}: ${c.action}`),
          metrics: hiddenProfitCards.map((c: any) => ({
            label: c.title,
            value: c.impact,
          })),
          actions: [
            { label: "بررسی فرصت‌های سود", icon: "fa-sack-dollar" },
            {
              label: "مدیریت کالاها",
              to: "/products",
              icon: "fa-boxes-stacked",
            },
          ],
          target: { cards: hiddenProfitCards },
        });
      }

      const hiddenLossRows = aiIsEnabled("profit_engine")
        ? await smartInsightSafeRows(
            `
      WITH order_item_totals AS (
        SELECT orderId, SUM(COALESCE(totalPrice, 0)) AS orderBase
        FROM sales_order_items
        GROUP BY orderId
      )
      SELECT * FROM (
        SELECT
          'نقدی' AS saleType,
          so.id AS saleId,
          so.transactionDate AS saleDate,
          COALESCE(c.fullName, 'مشتری مهمان') AS customerName,
          ph.model AS phoneModel,
          ph.imei AS imei,
          COALESCE(soi.totalPrice, 0) - CASE WHEN COALESCE(oit.orderBase, 0) > 0 THEN COALESCE(so.discount, 0) * (COALESCE(soi.totalPrice, 0) / COALESCE(oit.orderBase, 1)) ELSE 0 END AS saleNet,
          COALESCE(NULLIF(ph.currentPurchasePrice, 0), NULLIF(soi.buyPrice, 0), ph.purchasePrice, 0) AS replacementPrice,
          (COALESCE(soi.totalPrice, 0) - CASE WHEN COALESCE(oit.orderBase, 0) > 0 THEN COALESCE(so.discount, 0) * (COALESCE(soi.totalPrice, 0) / COALESCE(oit.orderBase, 1)) ELSE 0 END) - COALESCE(NULLIF(ph.currentPurchasePrice, 0), NULLIF(soi.buyPrice, 0), ph.purchasePrice, 0) AS realProfit
        FROM sales_order_items soi
        JOIN sales_orders so ON so.id = soi.orderId
        JOIN order_item_totals oit ON oit.orderId = so.id
        JOIN phones ph ON soi.itemType = 'phone' AND soi.itemId = ph.id
        LEFT JOIN customers c ON c.id = so.customerId
        WHERE date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?) AND COALESCE(so.status, 'active') = 'active'
        UNION ALL
        SELECT
          'اقساطی' AS saleType,
          ins.id AS saleId,
          substr(COALESCE(ins.dateCreated, ''), 1, 10) AS saleDate,
          COALESCE(c.fullName, 'مشتری مهمان') AS customerName,
          ph.model AS phoneModel,
          ph.imei AS imei,
          COALESCE(ins.actualSalePrice, 0) AS saleNet,
          COALESCE(NULLIF(ph.currentPurchasePrice, 0), ph.purchasePrice, 0) AS replacementPrice,
          COALESCE(ins.actualSalePrice, 0) - COALESCE(NULLIF(ph.currentPurchasePrice, 0), ph.purchasePrice, 0) AS realProfit
        FROM installment_sales ins
        JOIN phones ph ON ph.id = ins.phoneId
        LEFT JOIN customers c ON c.id = ins.customerId
        WHERE substr(COALESCE(ins.dateCreated, ''), 1, 10) BETWEEN ? AND ?
      ) x
      WHERE realProfit < 0
      ORDER BY realProfit ASC
      LIMIT 8
    `,
            [fromISO, toISO, fromISO, toISO],
          )
        : [];

      if (hiddenLossRows.length) {
        const totalLoss = hiddenLossRows.reduce(
          (s: number, r: any) =>
            s + Math.abs(Math.min(0, smartInsightNum(r.realProfit))),
          0,
        );
        addInsight({
          id: "hidden-loss-mobile-replacement-price",
          type: "hidden_loss",
          category: "سود واقعی گوشی",
          severity: totalLoss >= 5000000 ? "critical" : "high",
          score: Math.min(98, 58 + totalLoss / 250000),
          confidence: 84,
          icon: "fa-mobile-screen-button",
          title: "ضرر پنهان بر اساس قیمت خرید روز دیده شد",
          summary: `${hiddenLossRows.length.toLocaleString("fa-IR")} فروش گوشی با قیمت جایگزینی فعلی سود واقعی منفی دارد.`,
          reasons: hiddenLossRows
            .slice(0, 5)
            .map(
              (r: any) =>
                `${r.saleType} ${r.phoneModel || ""} (${r.imei || "بدون IMEI"}): فروش خالص ${smartInsightMoney(r.saleNet)}، قیمت خرید روز ${smartInsightMoney(r.replacementPrice)}، نتیجه ${smartInsightMoney(r.realProfit)}`,
            ),
          metrics: [
            {
              label: "تعداد فروش زیان‌ده",
              value: hiddenLossRows.length.toLocaleString("fa-IR"),
            },
            { label: "زیان پنهان", value: smartInsightMoney(totalLoss) },
            {
              label: "بدترین فروش",
              value: smartInsightMoney(hiddenLossRows[0]?.realProfit),
            },
          ],
          actions: [
            {
              label: "تحلیل گوشی نقد و اقساط",
              to: "/reports/mobile-sales-analytics",
              icon: "fa-mobile-screen-button",
            },
          ],
          target: { rows: hiddenLossRows },
        });
      }

      try {
        const collections = await buildProductSalesCollectionsReport(
          fromISO,
          toISO,
        );
        const risk = await buildProductSalesCollectionRisk(
          collections.rows || [],
          collections.docs || [],
          10,
        );
        const riskItems = await enrichCollectionCenterItems(
          Array.isArray(risk?.items) ? risk.items : [],
        );
        const actionableRiskItems = riskItems.filter((x: any) => {
          const stage = String(x.kanbanStage || "");
          if (x.touchedToday) return false;
          if (stage === "settled" || stage === "promise" || stage === "waiting")
            return false;
          return ["critical", "urgent"].includes(String(x.level));
        });
        const critical = actionableRiskItems.slice(0, 5);
        if (critical.length) {
          const totalOutstanding = critical.reduce(
            (s: number, r: any) => s + smartInsightNum(r.outstandingAmount),
            0,
          );
          addInsight({
            id: "collection-risk-critical",
            type: "collection_risk",
            category: "وصول مطالبات",
            severity: "critical",
            score: Math.min(
              99,
              Math.max(...critical.map((x: any) => smartInsightNum(x.score))),
            ),
            confidence: 88,
            icon: "fa-headset",
            title: "پرونده‌های وصول فوری/بحرانی شناسایی شد",
            summary: `${critical.length.toLocaleString("fa-IR")} سند نیازمند پیگیری فوری است و مانده آن‌ها ${smartInsightMoney(totalOutstanding)} است.`,
            reasons: critical.map(
              (r: any) =>
                `${r.customerName || "مشتری"} | سند ${r.orderId}: ${r.label || "ریسک بالا"}، مانده ${smartInsightMoney(r.outstandingAmount)}، وصول ${smartInsightPercent(r.collectionRate)}`,
            ),
            metrics: [
              {
                label: "پرونده فوری",
                value: critical.length.toLocaleString("fa-IR"),
              },
              {
                label: "مانده فوری",
                value: smartInsightMoney(totalOutstanding),
              },
              {
                label: "بالاترین امتیاز",
                value: Math.max(
                  ...critical.map((x: any) => smartInsightNum(x.score)),
                ).toLocaleString("fa-IR"),
              },
            ],
            actions: [
              {
                label: "مرکز پیگیری وصول",
                to: "/reports/collection-center",
                icon: "fa-headset",
              },
            ],
            target: { rows: critical },
          });
        }

        const totalProfit = smartInsightNum(collections.summary?.totalProfit);
        const realizedProfit = smartInsightNum(
          collections.summary?.realizedProfit,
        );
        const profitCollectionRate =
          totalProfit > 0 ? (realizedProfit / totalProfit) * 100 : 100;
        if (totalProfit > 0 && profitCollectionRate < 65) {
          addInsight({
            id: "profit-quality-realized-profit",
            type: "profit_quality",
            category: "کیفیت سود",
            severity: profitCollectionRate < 40 ? "high" : "medium",
            score: 100 - profitCollectionRate,
            confidence: 76,
            icon: "fa-scale-balanced",
            title: "کیفیت سود نیاز به کنترل دارد",
            summary: `بخش قابل توجهی از سود این بازه هنوز وصول نشده؛ نرخ سود وصول‌شده ${smartInsightPercent(profitCollectionRate)} است.`,
            reasons: [
              `سود کل برآوردی: ${smartInsightMoney(totalProfit)}`,
              `سود وصول‌شده: ${smartInsightMoney(realizedProfit)}`,
              `سود وصول‌نشده: ${smartInsightMoney(totalProfit - realizedProfit)}`,
            ],
            metrics: [
              {
                label: "نرخ سود وصول‌شده",
                value: smartInsightPercent(profitCollectionRate),
              },
              {
                label: "سود وصول‌نشده",
                value: smartInsightMoney(totalProfit - realizedProfit),
              },
            ],
            actions: [
              {
                label: "فروش غیرگوشی",
                to: "/reports/product-sales",
                icon: "fa-boxes-stacked",
              },
              {
                label: "مرکز وصول",
                to: "/reports/collection-center",
                icon: "fa-headset",
              },
            ],
          });
        }
      } catch (e: any) {
        console.error("SmartInsight collection risk failed:", e?.message || e);
      }

      if (!insights.length) {
        addInsight({
          id: "daily-positive-summary",
          type: "daily_summary",
          category: "خلاصه روز",
          severity: "positive",
          score: 55,
          confidence: 68,
          icon: "fa-circle-check",
          title: "در بازه فعلی هشدار جدی دیده نشد",
          summary:
            "سیستم افت شدید، تخفیف غیرعادی سنگین یا ریسک وصول بحرانی در بازه انتخابی پیدا نکرده است.",
          reasons: [
            "داده‌های فعلی در محدوده هشدارهای تعریف‌شده قرار نگرفته‌اند.",
            "با افزایش داده فروش، دقت یادگیری سیستم بالاتر می‌رود.",
          ],
          metrics: [
            {
              label: "فروش کل",
              value: smartInsightMoney(salesStats.totalSales),
            },
            {
              label: "تعداد فاکتور",
              value: smartInsightNum(salesStats.ordersCount).toLocaleString(
                "fa-IR",
              ),
            },
            { label: "بازه", value: `${fromJ} تا ${toJ}` },
          ],
          actions: [
            {
              label: "داشبورد گزارشات",
              to: "/reports",
              icon: "fa-chart-column",
            },
          ],
        });
      }

      // --- Customer Intelligence Engine + Auto Pricing Engine (applied, not placeholder) ---
      const customerIntelligenceRows = aiIsEnabled("customer_intelligence")
        ? await smartInsightSafeRows(
            `
      WITH customer_sales AS (
        SELECT
          c.id AS customerId,
          c.fullName AS customerName,
          c.phoneNumber AS phoneNumber,
          COUNT(DISTINCT so.id) AS ordersCount,
          COALESCE(SUM(so.grandTotal), 0) AS totalSpend,
          COALESCE(SUM(so.discount), 0) + COALESCE(SUM(soi.discountPerItem), 0) AS totalDiscount,
          COALESCE(SUM((COALESCE(soi.unitPrice,0) - COALESCE(NULLIF(soi.buyPrice,0), p.purchasePrice, 0)) * COALESCE(soi.quantity,0) - COALESCE(soi.discountPerItem,0)), 0) AS estimatedProfit,
          MIN(so.transactionDate) AS periodFirstPurchaseAt,
          MAX(so.transactionDate) AS periodLastPurchaseAt,
          SUM(CASE WHEN COALESCE(so.paymentMethod,'cash') IN ('credit','installment','mixed') THEN 1 ELSE 0 END) AS creditOrders,
          COUNT(DISTINCT so.transactionDate) AS activeDays
        FROM customers c
        JOIN sales_orders so ON so.customerId = c.id AND COALESCE(so.status, 'active') = 'active'
        LEFT JOIN sales_order_items soi ON soi.orderId = so.id
        LEFT JOIN products p ON soi.itemType = 'inventory' AND soi.itemId = p.id
        WHERE date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?)
        GROUP BY c.id, c.fullName, c.phoneNumber
      ), last_before AS (
        SELECT customerId, MAX(transactionDate) AS prevPurchaseAt
        FROM sales_orders
        WHERE transactionDate < ? AND customerId IS NOT NULL AND COALESCE(status, 'active') = 'active'
        GROUP BY customerId
      ), last_purchase AS (
        SELECT customerId, MAX(transactionDate) AS lastPurchaseAt
        FROM sales_orders
        WHERE customerId IS NOT NULL
          AND COALESCE(status, 'active') = 'active'
          AND date(substr(transactionDate, 1, 10)) <= date(?)
        GROUP BY customerId
      )
      SELECT cs.*, lb.prevPurchaseAt, lp.lastPurchaseAt AS absoluteLastPurchaseAt
      FROM customer_sales cs
      LEFT JOIN last_before lb ON lb.customerId = cs.customerId
      LEFT JOIN last_purchase lp ON lp.customerId = cs.customerId
      ORDER BY estimatedProfit DESC, totalSpend DESC
      LIMIT 12
    `,
            [fromISO, toISO, fromISO, toISO],
          )
        : [];

      const customerIntelligence = (customerIntelligenceRows || []).map(
        (r: any) => {
          const totalSpend = smartInsightNum(r.totalSpend);
          const profit = smartInsightNum(r.estimatedProfit);
          const discountRate =
            totalSpend > 0
              ? (smartInsightNum(r.totalDiscount) / totalSpend) * 100
              : 0;
          const creditRate =
            smartInsightNum(r.ordersCount) > 0
              ? (smartInsightNum(r.creditOrders) /
                  smartInsightNum(r.ordersCount)) *
                100
              : 0;
          const lastDateRaw = String(
            r.absoluteLastPurchaseAt ||
              r.periodLastPurchaseAt ||
              r.lastPurchaseAt ||
              "",
          );
          const lastDateIso = lastDateRaw ? lastDateRaw.slice(0, 10) : "";
          const lastPurchaseMoment = lastDateIso
            ? moment(lastDateIso, "YYYY-MM-DD", true)
            : null;
          const daysSinceLast = lastPurchaseMoment?.isValid()
            ? Math.max(0, toMoment.diff(lastPurchaseMoment, "day"))
            : 999;
          const lastPurchaseLabel =
            daysSinceLast >= 999
              ? "نامشخص"
              : daysSinceLast === 0
                ? "امروز"
                : daysSinceLast === 1
                  ? "دیروز"
                  : `${daysSinceLast.toLocaleString("fa-IR")} روز قبل`;
          const recencyRisk = Math.min(45, Math.max(0, daysSinceLast - 14));
          const riskScore = Math.min(
            100,
            Math.round(discountRate * 1.15 + creditRate * 0.55 + recencyRisk),
          );
          const profitScore = Math.min(
            100,
            Math.round(
              (profit / Math.max(1, totalSpend)) * 180 +
                Math.min(35, smartInsightNum(r.ordersCount) * 5) +
                Math.min(25, profit / 2000000),
            ),
          );
          const segments = [
            profitScore >= 70 ? "مشتری طلایی" : "",
            profitScore >= 48 ? "سودآور" : "",
            riskScore >= 62 ? "پرریسک" : "",
            discountRate >= 12 ? "تخفیف‌گیر حرفه‌ای" : "",
            creditRate >= 45 ? "کندپرداخت/اعتباری" : "",
            daysSinceLast >= 35 ? "در حال ریزش" : "",
          ].filter(Boolean);
          const action =
            riskScore >= 62
              ? "قبل از فروش اعتباری بعدی سقف بدهی و تضمین را کنترل کن."
              : daysSinceLast >= 35
                ? "یک پیشنهاد بازگشت کوتاه و شخصی‌سازی‌شده ارسال کن."
                : discountRate >= 12
                  ? "تخفیف را به باندل سودآور تبدیل کن، نه کاهش مستقیم قیمت."
                  : profitScore >= 70
                    ? "برای این مشتری پیشنهاد VIP یا باندل پریمیوم بساز."
                    : "رفتار خرید را زیر نظر بگیر و پیشنهاد مکمل بده.";
          return {
            customerId: r.customerId,
            customerName: r.customerName || "مشتری بدون نام",
            phoneNumber: r.phoneNumber || "",
            segment: segments[0] || "عادی",
            segments,
            riskScore,
            profitScore,
            totalSpend: smartInsightRound(totalSpend),
            estimatedProfit: smartInsightRound(profit),
            discountRate: smartInsightRound(discountRate),
            creditRate: smartInsightRound(creditRate),
            daysSinceLast,
            lastPurchaseAt: lastDateIso,
            lastPurchaseLabel,
            action,
          };
        },
      );

      for (const c of customerIntelligence) {
        if (!c.customerId) continue;
        await runAsync(
          `
        INSERT INTO customer_scores (customerId, segment, riskScore, profitScore, lastCalculatedAt)
        VALUES (?, ?, ?, ?, strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc'))
        ON CONFLICT(customerId) DO UPDATE SET
          segment = excluded.segment,
          riskScore = excluded.riskScore,
          profitScore = excluded.profitScore,
          lastCalculatedAt = excluded.lastCalculatedAt
      `,
          [
            c.customerId,
            c.segment || "عادی",
            smartInsightNum(c.riskScore),
            smartInsightNum(c.profitScore),
          ],
        ).catch(() => null as any);
      }

      const topCustomerRisk = customerIntelligence.find(
        (c: any) =>
          smartInsightNum(c.riskScore) >= 62 ||
          String(c.segment).includes("ریزش"),
      );
      if (topCustomerRisk) {
        addInsight({
          id: "customer-intelligence-risk",
          type: "customer_intelligence",
          category: "مشتری",
          severity:
            smartInsightNum(topCustomerRisk.riskScore) >= 72
              ? "high"
              : "medium",
          score: Math.max(58, smartInsightNum(topCustomerRisk.riskScore)),
          confidence: Math.min(92, 60 + customerIntelligence.length * 3),
          icon: "fa-user-shield",
          title: "شخصیت مشتری نیازمند اقدام شناسایی شد",
          summary: `${topCustomerRisk.customerName} در سگمنت «${topCustomerRisk.segment}» قرار گرفته و بهتر است رفتار فروش/وصول برای او کنترل شود.`,
          reasons: [
            `ریسک: ${smartInsightPercent(topCustomerRisk.riskScore)}`,
            `تخفیف دریافتی: ${smartInsightPercent(topCustomerRisk.discountRate)}`,
            `نرخ خرید اعتباری: ${smartInsightPercent(topCustomerRisk.creditRate)}`,
            `آخرین خرید: ${topCustomerRisk.lastPurchaseLabel || (smartInsightNum(topCustomerRisk.daysSinceLast) >= 999 ? "نامشخص" : `${smartInsightNum(topCustomerRisk.daysSinceLast).toLocaleString("fa-IR")} روز قبل`)}`,
          ],
          metrics: [
            {
              label: "ریسک",
              value: smartInsightPercent(topCustomerRisk.riskScore),
            },
            {
              label: "سودآوری",
              value: smartInsightPercent(topCustomerRisk.profitScore),
            },
            {
              label: "سود تخمینی",
              value: smartInsightMoney(topCustomerRisk.estimatedProfit),
            },
          ],
          actions: [
            { label: "مشاهده مشتریان", to: "/customers", icon: "fa-users" },
          ],
          target: { customers: customerIntelligence.slice(0, 8) },
        });
      }

      const pricingRows = aiIsEnabled("auto_pricing")
        ? await smartInsightSafeRows(
            `
      WITH product_sales AS (
        SELECT
          p.id AS productId,
          p.name AS productName,
          COALESCE(p.purchasePrice, 0) AS purchasePrice,
          COALESCE(p.sellingPrice, 0) AS currentPrice,
          COALESCE(p.stock_quantity, 0) AS stockQuantity,
          COALESCE(p.threshold, 5) AS thresholdQty,
          COALESCE(SUM(CASE WHEN date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?) THEN soi.quantity ELSE 0 END), 0) AS sold7,
          COALESCE(SUM(CASE WHEN date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?) THEN soi.quantity ELSE 0 END), 0) AS sold30,
          COALESCE(SUM(CASE WHEN date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?) THEN soi.totalPrice ELSE 0 END), 0) AS revenue30,
          COALESCE(SUM(CASE WHEN date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?) THEN soi.discountPerItem ELSE 0 END), 0) AS discount30,
          COALESCE(SUM(CASE WHEN date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?) THEN (COALESCE(soi.unitPrice,0) - COALESCE(NULLIF(soi.buyPrice,0), p.purchasePrice, 0)) * COALESCE(soi.quantity,0) - COALESCE(soi.discountPerItem,0) ELSE 0 END), 0) AS profit30
        FROM products p
        LEFT JOIN sales_order_items soi ON soi.itemType = 'inventory' AND soi.itemId = p.id
        LEFT JOIN sales_orders so ON so.id = soi.orderId AND COALESCE(so.status, 'active') = 'active'
        GROUP BY p.id, p.name, p.purchasePrice, p.sellingPrice, p.stock_quantity, p.threshold
        HAVING currentPrice > 0 AND (sold30 > 0 OR stockQuantity > 0)
        ORDER BY profit30 DESC, sold30 DESC
        LIMIT 18
      )
      SELECT * FROM product_sales
    `,
            [
              toMoment.clone().subtract(7, "day").format("YYYY-MM-DD"),
              toISO,
              fromISO,
              toISO,
              fromISO,
              toISO,
              fromISO,
              toISO,
              fromISO,
              toISO,
            ],
          )
        : [];

      const pricingRecommendations = (pricingRows || [])
        .map((r: any) => {
          const currentPrice = smartInsightNum(r.currentPrice);
          const purchasePrice = smartInsightNum(r.purchasePrice);
          const stock = smartInsightNum(r.stockQuantity);
          const sold7 = smartInsightNum(r.sold7);
          const sold30 = smartInsightNum(r.sold30);
          const velocity =
            sold30 / Math.max(1, toMoment.diff(fromMoment, "day") + 1);
          const marginPct =
            currentPrice > 0
              ? ((currentPrice - purchasePrice) / currentPrice) * 100
              : 0;
          const discountRate =
            smartInsightNum(r.revenue30) > 0
              ? (smartInsightNum(r.discount30) / smartInsightNum(r.revenue30)) *
                100
              : 0;
          const daysToStockout = velocity > 0 ? stock / velocity : 999;
          const elasticityScore = Math.max(
            -2.5,
            Math.min(
              0.5,
              -0.55 -
                discountRate / 35 +
                (sold7 > sold30 / 4 ? 0.18 : -0.12) +
                (marginPct > 28 ? 0.16 : 0),
            ),
          );
          const safeMinPrice = Math.max(
            purchasePrice * 1.08,
            currentPrice * 0.92,
          );
          const lift =
            daysToStockout < 7
              ? 0.06
              : marginPct > 25 && discountRate < 8
                ? 0.04
                : discountRate > 15
                  ? -0.03
                  : sold7 > Math.max(1, sold30 / 4)
                    ? 0.03
                    : 0;
          const rawOptimal = currentPrice * (1 + lift);
          const optimalPrice = Math.max(
            safeMinPrice,
            Math.round(rawOptimal / 1000) * 1000,
          );
          const volumeDelta =
            lift > 0
              ? Math.round(elasticityScore * lift * 100)
              : Math.round(Math.abs(elasticityScore) * Math.abs(lift) * 45);
          const profitDelta = Math.round(
            (optimalPrice - purchasePrice - (currentPrice - purchasePrice)) *
              Math.max(1, Math.min(sold30, stock || sold30 || 1)),
          );
          const risk =
            lift > 0.045 && elasticityScore < -1.1
              ? "بالا"
              : lift < 0
                ? "کنترل فروش"
                : "کم";
          const action =
            lift > 0
              ? "افزایش قیمت کنترل‌شده ۷ روزه"
              : lift < 0
                ? "کاهش قیمت/تخلیه موجودی کنترل‌شده"
                : "حفظ قیمت و پایش";
          return {
            productId: r.productId,
            productName: r.productName,
            currentPrice: smartInsightRound(currentPrice),
            purchasePrice: smartInsightRound(purchasePrice),
            safeMinPrice: smartInsightRound(safeMinPrice),
            optimalPrice: smartInsightRound(optimalPrice),
            aggressivePrice: smartInsightRound(
              Math.max(safeMinPrice, currentPrice * 0.96),
            ),
            marginPct: smartInsightRound(marginPct),
            elasticityScore: smartInsightRound(elasticityScore),
            sold7: smartInsightRound(sold7),
            sold30: smartInsightRound(sold30),
            daysToStockout:
              daysToStockout >= 999 ? 999 : smartInsightRound(daysToStockout),
            expectedProfitDelta: smartInsightRound(profitDelta),
            expectedVolumeDelta: volumeDelta,
            confidence: Math.max(
              45,
              Math.min(
                92,
                Math.round(
                  52 +
                    Math.min(22, sold30 * 2) +
                    Math.min(14, Math.max(0, marginPct)) -
                    Math.max(0, discountRate - 12),
                ),
              ),
            ),
            risk,
            action,
          };
        })
        .sort(
          (a: any, b: any) =>
            Math.abs(smartInsightNum(b.expectedProfitDelta)) -
            Math.abs(smartInsightNum(a.expectedProfitDelta)),
        )
        .slice(0, 8);

      const topPricing = pricingRecommendations.find(
        (p: any) =>
          Math.abs(smartInsightNum(p.expectedProfitDelta)) > 0 ||
          smartInsightNum(p.sold30) > 0,
      );
      if (topPricing) {
        addInsight({
          id: "auto-pricing-opportunity",
          type: "auto_pricing",
          category: "قیمت‌گذاری",
          severity:
            smartInsightNum(topPricing.expectedProfitDelta) > 0
              ? "medium"
              : "low",
          score: Math.min(
            92,
            50 +
              smartInsightNum(topPricing.confidence) * 0.35 +
              Math.min(
                18,
                Math.abs(smartInsightNum(topPricing.expectedProfitDelta)) /
                  1000000,
              ),
          ),
          confidence: topPricing.confidence,
          icon: "fa-tags",
          title: "قیمت‌گذاری هوشمند پیشنهاد جدید دارد",
          summary: `برای ${topPricing.productName} قیمت پیشنهادی ${smartInsightMoney(topPricing.optimalPrice)} است؛ قیمت فعلی ${smartInsightMoney(topPricing.currentPrice)}.`,
          reasons: [
            `حاشیه سود: ${smartInsightPercent(topPricing.marginPct)}`,
            `کشش قیمت تخمینی: ${topPricing.elasticityScore}`,
            `فروش ۳۰ روز: ${smartInsightNum(topPricing.sold30).toLocaleString("fa-IR")}`,
            `ریسک اجرا: ${topPricing.risk}`,
          ],
          metrics: [
            {
              label: "قیمت فعلی",
              value: smartInsightMoney(topPricing.currentPrice),
            },
            {
              label: "قیمت پیشنهادی",
              value: smartInsightMoney(topPricing.optimalPrice),
            },
            {
              label: "اثر سود",
              value: smartInsightMoney(topPricing.expectedProfitDelta),
            },
          ],
          actions: [
            { label: "مدیریت کالاها", to: "/products", icon: "fa-tags" },
          ],
          target: { pricing: pricingRecommendations },
        });
      }

      // --- AI Sales Agent: active selling / collection playbook based on customer intelligence, pricing and purchase history ---
      const customerIdsForAgent = customerIntelligence
        .map((c: any) => String(c.customerId || ""))
        .filter(Boolean)
        .slice(0, 20);
      const lastCustomerItems =
        aiIsEnabled("sales_agent") && customerIdsForAgent.length
          ? await smartInsightSafeRows(
              `
      SELECT
        so.customerId,
        p.id AS productId,
        p.name AS productName,
        MAX(so.transactionDate) AS lastBoughtAt,
        SUM(COALESCE(soi.quantity, 0)) AS boughtQty,
        SUM(COALESCE(soi.totalPrice, 0)) AS boughtAmount
      FROM sales_orders so
      JOIN sales_order_items soi ON soi.orderId = so.id AND soi.itemType = 'inventory'
      LEFT JOIN products p ON p.id = soi.itemId
      WHERE so.customerId IN (${customerIdsForAgent.map(() => "?").join(",")})
        AND COALESCE(so.status, 'active') = 'active'
      GROUP BY so.customerId, p.id, p.name
      ORDER BY MAX(so.transactionDate) DESC, SUM(COALESCE(soi.totalPrice, 0)) DESC
    `,
              customerIdsForAgent,
            )
          : [];
      const lastItemByCustomer = new Map();
      for (const row of lastCustomerItems || []) {
        const key = String(row.customerId || "");
        if (!lastItemByCustomer.has(key) && row.productName)
          lastItemByCustomer.set(key, row);
      }
      const bestPricingProduct =
        pricingRecommendations.find(
          (p: any) =>
            smartInsightNum(p.expectedProfitDelta) >= 0 &&
            smartInsightNum(p.optimalPrice) > 0,
        ) ||
        pricingRecommendations[0] ||
        null;
      const salesAgentLeads = aiIsEnabled("sales_agent")
        ? customerIntelligence
            .filter(
              (c: any) =>
                c.customerId &&
                (smartInsightNum(c.profitScore) >= 45 ||
                  smartInsightNum(c.riskScore) >= 45 ||
                  smartInsightNum(c.daysSinceLast) >= 21 ||
                  smartInsightNum(c.discountRate) >= 10),
            )
            .map((c: any) => {
              const lastItem =
                lastItemByCustomer.get(String(c.customerId)) || {};
              const isCollection =
                smartInsightNum(c.creditRate) >= 45 ||
                smartInsightNum(c.riskScore) >= 68;
              const isWinback = smartInsightNum(c.daysSinceLast) >= 35;
              const isDiscountSeeker = smartInsightNum(c.discountRate) >= 12;
              const isVip = smartInsightNum(c.profitScore) >= 70;
              const targetProduct =
                lastItem.productName ||
                bestPricingProduct?.productName ||
                "محصولات تازه فروشگاه";
              const intent = isCollection
                ? "collection"
                : isWinback
                  ? "winback"
                  : isVip
                    ? "vip_upsell"
                    : isDiscountSeeker
                      ? "bundle_offer"
                      : "cross_sell";
              const title =
                intent === "collection"
                  ? "پیگیری وصول بدون از دست دادن مشتری"
                  : intent === "winback"
                    ? "بازگرداندن مشتری در حال ریزش"
                    : intent === "vip_upsell"
                      ? "پیشنهاد VIP برای مشتری سودآور"
                      : intent === "bundle_offer"
                        ? "تبدیل تخفیف به باندل سودآور"
                        : "فروش مکمل شخصی‌سازی‌شده";
              const message =
                intent === "collection"
                  ? `سلام ${c.customerName} عزیز، برای هماهنگی تسویه حساب قبلی و ادامه خریدهای بعدی در خدمتتون هستیم. اگر مایل باشید امروز وضعیت حساب رو با هم نهایی کنیم.`
                  : intent === "winback"
                    ? `سلام ${c.customerName} عزیز، ${targetProduct} و چند قلم تازه فروشگاه موجود شده. اگر دوست داشتید، امروز می‌تونیم یک پیشنهاد مناسب بر اساس خرید قبلی‌تون آماده کنیم.`
                    : intent === "vip_upsell"
                      ? `سلام ${c.customerName} عزیز، برای شما یک پیشنهاد ویژه روی ${targetProduct} آماده کردیم؛ ترکیب تازه و باکیفیت با اولویت موجودی امروز.`
                      : intent === "bundle_offer"
                        ? `سلام ${c.customerName} عزیز، به جای تخفیف مستقیم، یک ترکیب اقتصادی و به‌صرفه از ${targetProduct} براتون آماده کردیم که ارزش خرید بالاتری داره.`
                        : `سلام ${c.customerName} عزیز، با توجه به خرید قبلی شما از ${targetProduct}، چند گزینه مکمل تازه داریم که می‌تونه انتخاب خوبی برای خرید بعدی باشه.`;
              const priority = Math.round(
                smartInsightNum(c.profitScore) * 0.62 +
                  smartInsightNum(c.riskScore) * 0.38 +
                  Math.min(24, smartInsightNum(c.daysSinceLast) / 2) +
                  (intent === "collection"
                    ? 22
                    : intent === "vip_upsell"
                      ? 18
                      : intent === "winback"
                        ? 14
                        : 8),
              );
              return {
                id: `sales-agent-${c.customerId}-${intent}`,
                customerId: c.customerId,
                customerName: c.customerName,
                phoneNumber: c.phoneNumber || "",
                segment: c.segment || "عادی",
                intent,
                title,
                priority: Math.min(100, Math.max(1, priority)),
                recommendedChannel: c.phoneNumber
                  ? "تماس / پیامک / تلگرام"
                  : "تماس حضوری یا ثبت شماره",
                targetProduct,
                message,
                reason:
                  intent === "collection"
                    ? "ریسک اعتباری یا خرید نسیه بالا است."
                    : intent === "winback"
                      ? "فاصله آخرین خرید زیاد شده و احتمال ریزش وجود دارد."
                      : intent === "vip_upsell"
                        ? "سودآوری مشتری بالاست و ارزش پیشنهاد ویژه دارد."
                        : intent === "bundle_offer"
                          ? "رفتار مشتری تخفیف‌محور است؛ باندل بهتر از کاهش قیمت است."
                          : "رفتار خرید، ظرفیت فروش مکمل را نشان می‌دهد.",
                expectedImpact:
                  intent === "collection"
                    ? "کاهش ریسک وصول"
                    : intent === "winback"
                      ? "بازگشت مشتری"
                      : intent === "vip_upsell"
                        ? "افزایش سود فاکتور"
                        : intent === "bundle_offer"
                          ? "حفظ حاشیه سود"
                          : "افزایش فروش مکمل",
                ctaLabel:
                  intent === "collection"
                    ? "پیگیری وصول"
                    : "آماده‌سازی پیام فروش",
                to: c.customerId ? `/customers/${c.customerId}` : "/customers",
              };
            })
            .sort(
              (a: any, b: any) =>
                smartInsightNum(b.priority) - smartInsightNum(a.priority),
            )
            .slice(0, 8)
        : [];

      if (salesAgentLeads.length) {
        const topLead = salesAgentLeads[0];
        addInsight({
          id: "ai-sales-agent-active-lead",
          type: "ai_sales_agent",
          category: "فروش فعال",
          severity: smartInsightNum(topLead.priority) >= 78 ? "high" : "medium",
          score: topLead.priority,
          confidence: Math.min(92, 58 + salesAgentLeads.length * 5),
          icon: "fa-headset",
          title: "دستیار فروش فعال، مشتری آماده اقدام پیدا کرد",
          summary: `${topLead.customerName} برای «${topLead.title}» اولویت دارد؛ پیام آماده و مسیر اقدام ساخته شد.`,
          reasons: [
            topLead.reason,
            `سگمنت: ${topLead.segment}`,
            `کانال پیشنهادی: ${topLead.recommendedChannel}`,
            `اثر مورد انتظار: ${topLead.expectedImpact}`,
          ],
          metrics: [
            { label: "اولویت", value: smartInsightPercent(topLead.priority) },
            {
              label: "لید فعال",
              value: salesAgentLeads.length.toLocaleString("fa-IR"),
            },
            { label: "هدف", value: topLead.expectedImpact },
          ],
          actions: [{ label: "مشاهده مشتری", to: topLead.to, icon: "fa-user" }],
          target: { salesAgent: salesAgentLeads },
        });
      }

      // --- Real Profit Engine: سود واقعی، سود وصول‌شده و سود در خطر ---
      const profitRows = aiIsEnabled("profit_engine")
        ? await smartInsightSafeRows(
            `
      SELECT
        so.id AS orderId,
        so.transactionDate,
        COALESCE(so.paymentMethod, 'cash') AS paymentMethod,
        COALESCE(so.subtotal, 0) AS subtotal,
        COALESCE(so.grandTotal, 0) AS grandTotal,
        COALESCE(so.discount, 0) AS invoiceDiscount,
        COALESCE(SUM(COALESCE(soi.quantity,0) * COALESCE(soi.unitPrice,0)), 0) AS lineGross,
        COALESCE(SUM(COALESCE(soi.discountPerItem,0)), 0) AS itemDiscount,
        COALESCE(SUM(COALESCE(soi.totalPrice,0)), 0) AS lineNet,
        COALESCE(SUM(COALESCE(soi.totalPrice,0) - (COALESCE(NULLIF(soi.buyPrice,0), p.purchasePrice, 0) * COALESCE(soi.quantity,0))), 0) AS lineProfitBeforeInvoiceDiscount
      FROM sales_orders so
      LEFT JOIN sales_order_items soi ON soi.orderId = so.id
      LEFT JOIN products p ON soi.itemType = 'inventory' AND soi.itemId = p.id
      WHERE date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?) AND COALESCE(so.status, 'active') = 'active'
      GROUP BY so.id, so.transactionDate, so.paymentMethod, so.subtotal, so.grandTotal, so.discount
    `,
            [fromISO, toISO],
          )
        : [];

      const profitInvoices = (profitRows || []).map((r: any) => {
        const grandTotal = smartInsightNum(r.grandTotal);
        const subtotal =
          smartInsightNum(r.subtotal) ||
          smartInsightNum(r.lineGross) ||
          grandTotal;
        const invoiceDiscount = smartInsightNum(r.invoiceDiscount);
        const lineProfitBeforeInvoiceDiscount = smartInsightNum(
          r.lineProfitBeforeInvoiceDiscount,
        );
        const invoiceDiscountShare =
          invoiceDiscount > 0
            ? invoiceDiscount
            : Math.max(0, subtotal - grandTotal);
        const realProfit =
          lineProfitBeforeInvoiceDiscount - invoiceDiscountShare;
        const isDeferred = ["credit", "installment", "mixed"].includes(
          String(r.paymentMethod || "").toLowerCase(),
        );
        const recognitionRate = isDeferred ? 0.5 : 1;
        const recognizedProfit = realProfit * recognitionRate;
        const profitAtRisk = realProfit - recognizedProfit;
        const marginPct = grandTotal > 0 ? (realProfit / grandTotal) * 100 : 0;
        const riskScore = Math.min(
          100,
          Math.max(
            0,
            (realProfit < 0 ? 55 : 0) +
              (marginPct < 8 ? 22 : 0) +
              (invoiceDiscountShare > 0 && subtotal > 0
                ? Math.min(24, (invoiceDiscountShare / subtotal) * 100)
                : 0) +
              (isDeferred ? 14 : 0),
          ),
        );
        return {
          orderId: r.orderId,
          transactionDate: r.transactionDate,
          paymentMethod: r.paymentMethod,
          grandTotal: smartInsightRound(grandTotal),
          invoiceDiscount: smartInsightRound(invoiceDiscountShare),
          realProfit: smartInsightRound(realProfit),
          recognizedProfit: smartInsightRound(recognizedProfit),
          profitAtRisk: smartInsightRound(profitAtRisk),
          marginPct: smartInsightRound(marginPct),
          riskScore: Math.round(riskScore),
          label:
            realProfit < 0
              ? "زیان‌ده"
              : marginPct < 8
                ? "حاشیه سود ضعیف"
                : isDeferred
                  ? "سود وصول‌نشده"
                  : "سود سالم",
          to: "/invoices/" + r.orderId,
        };
      });

      const profitSummary = profitInvoices.reduce(
        (acc: any, r: any) => {
          acc.grossSales += smartInsightNum(r.grandTotal);
          acc.realProfit += smartInsightNum(r.realProfit);
          acc.recognizedProfit += smartInsightNum(r.recognizedProfit);
          acc.profitAtRisk += smartInsightNum(r.profitAtRisk);
          acc.negativeProfitCount += smartInsightNum(r.realProfit) < 0 ? 1 : 0;
          acc.lowMarginCount +=
            smartInsightNum(r.realProfit) >= 0 &&
            smartInsightNum(r.marginPct) < 8
              ? 1
              : 0;
          acc.deferredCount += smartInsightNum(r.profitAtRisk) > 0 ? 1 : 0;
          return acc;
        },
        {
          grossSales: 0,
          realProfit: 0,
          recognizedProfit: 0,
          profitAtRisk: 0,
          negativeProfitCount: 0,
          lowMarginCount: 0,
          deferredCount: 0,
        },
      );
      profitSummary.marginPct =
        profitSummary.grossSales > 0
          ? smartInsightRound(
              (profitSummary.realProfit / profitSummary.grossSales) * 100,
            )
          : 0;
      profitSummary.qualityScore = Math.max(
        0,
        Math.min(
          100,
          Math.round(
            64 +
              Math.min(22, smartInsightNum(profitSummary.marginPct)) -
              smartInsightNum(profitSummary.negativeProfitCount) * 12 -
              smartInsightNum(profitSummary.lowMarginCount) * 4 -
              (profitSummary.realProfit > 0
                ? Math.min(
                    18,
                    (profitSummary.profitAtRisk /
                      Math.max(1, profitSummary.realProfit)) *
                      28,
                  )
                : 0),
          ),
        ),
      );
      const profitEngine = {
        summary: {
          grossSales: smartInsightRound(profitSummary.grossSales),
          realProfit: smartInsightRound(profitSummary.realProfit),
          recognizedProfit: smartInsightRound(profitSummary.recognizedProfit),
          profitAtRisk: smartInsightRound(profitSummary.profitAtRisk),
          marginPct: smartInsightRound(profitSummary.marginPct),
          qualityScore: profitSummary.qualityScore,
          negativeProfitCount: profitSummary.negativeProfitCount,
          lowMarginCount: profitSummary.lowMarginCount,
          deferredCount: profitSummary.deferredCount,
        },
        riskyInvoices: profitInvoices
          .filter(
            (r: any) =>
              smartInsightNum(r.riskScore) >= 20 ||
              smartInsightNum(r.realProfit) < 0 ||
              smartInsightNum(r.profitAtRisk) > 0,
          )
          .sort(
            (a: any, b: any) =>
              smartInsightNum(b.riskScore) - smartInsightNum(a.riskScore),
          )
          .slice(0, 8),
      };

      if (profitInvoices.length) {
        await runAsync(
          `
        INSERT INTO profit_engine_snapshots (periodFrom, periodTo, grossSales, realProfit, recognizedProfit, profitAtRisk, marginPct, userId)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?)
      `,
          [
            fromISO,
            toISO,
            profitEngine.summary.grossSales,
            profitEngine.summary.realProfit,
            profitEngine.summary.recognizedProfit,
            profitEngine.summary.profitAtRisk,
            profitEngine.summary.marginPct,
            req.user?.id || null,
          ],
        );
      }

      if (
        profitEngine.summary.negativeProfitCount > 0 ||
        profitEngine.summary.lowMarginCount > 0 ||
        profitEngine.summary.profitAtRisk > 0
      ) {
        addInsight({
          id: "real-profit-engine-watch",
          type: "real_profit",
          category: "سود واقعی",
          severity:
            profitEngine.summary.negativeProfitCount > 0
              ? "critical"
              : profitEngine.summary.qualityScore < 58
                ? "high"
                : "medium",
          score: Math.min(99, 100 - profitEngine.summary.qualityScore + 42),
          confidence: 88,
          icon: "fa-sack-dollar",
          title: "موتور سود واقعی، نقاط حساس سود را پیدا کرد",
          summary:
            "سود واقعی بازه " +
            smartInsightMoney(profitEngine.summary.realProfit) +
            " است؛ " +
            profitEngine.summary.negativeProfitCount.toLocaleString("fa-IR") +
            " فاکتور زیان‌ده و " +
            profitEngine.summary.deferredCount.toLocaleString("fa-IR") +
            " فاکتور با سود در خطر دیده شد.",
          reasons: [
            "حاشیه سود واقعی: " +
              smartInsightPercent(profitEngine.summary.marginPct),
            "سود شناسایی‌شده: " +
              smartInsightMoney(profitEngine.summary.recognizedProfit),
            "سود در خطر/وصول‌نشده: " +
              smartInsightMoney(profitEngine.summary.profitAtRisk),
            "تخفیف کلی فاکتور از سود واقعی کسر شده و فروش اعتباری با شناسایی محافظه‌کارانه دیده می‌شود.",
          ],
          metrics: [
            {
              label: "سود واقعی",
              value: smartInsightMoney(profitEngine.summary.realProfit),
            },
            {
              label: "کیفیت سود",
              value: smartInsightPercent(profitEngine.summary.qualityScore),
            },
            {
              label: "در خطر",
              value: smartInsightMoney(profitEngine.summary.profitAtRisk),
            },
          ],
          actions: [
            {
              label: "بررسی فاکتورهای حساس",
              to: "/reports/product-sales",
              icon: "fa-scale-balanced",
            },
          ],
          target: { profitEngine },
        });
      }

      insights.sort((a, b) => {
        const rank: any = {
          critical: 5,
          high: 4,
          medium: 3,
          low: 2,
          positive: 1,
        };
        return (
          (rank[b.severity] || 0) - (rank[a.severity] || 0) ||
          smartInsightNum(b.score) - smartInsightNum(a.score)
        );
      });

      const soldProductCountRow = await smartInsightSafeOne(
        `
      SELECT COUNT(DISTINCT itemId) AS soldProducts
      FROM sales_order_items soi
      JOIN sales_orders so ON so.id = soi.orderId
      WHERE date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?) AND soi.itemType IN ('inventory', 'service', 'phone') AND COALESCE(so.status, 'active') = 'active'
    `,
        [fromISO, toISO],
      );
      const totalProductsRow = await smartInsightSafeOne(
        `SELECT COUNT(*) AS productsCount FROM products`,
      );
      const totalCustomersRow = await smartInsightSafeOne(
        `SELECT COUNT(*) AS customersCount FROM customers`,
      );
      const ordersCount = smartInsightNum(salesStats.ordersCount);
      const soldProducts = smartInsightNum(soldProductCountRow.soldProducts);
      const customersCount = smartInsightNum(totalCustomersRow.customersCount);
      const signalsScore = Math.min(
        100,
        Math.round(
          ordersCount * 1.6 +
            activeDays * 2.2 +
            soldProducts * 3 +
            Math.min(customersCount, 80) * 0.28,
        ),
      );
      const learningLevel =
        signalsScore >= 86
          ? "excellent"
          : signalsScore >= 62
            ? "reliable"
            : signalsScore >= 28
              ? "learning"
              : "no_data";
      const learningLabel =
        learningLevel === "excellent"
          ? "بسیار قابل اعتماد"
          : learningLevel === "reliable"
            ? "قابل اعتماد"
            : learningLevel === "learning"
              ? "در حال یادگیری"
              : "داده کافی ندارد";
      const learningDescription =
        learningLevel === "excellent"
          ? "سیستم داده کافی برای تشخیص الگوهای فروش، تخفیف، موجودی و وصول دارد."
          : learningLevel === "reliable"
            ? "داده‌ها برای پیشنهادهای عملیاتی قابل اتکا هستند؛ با فروش بیشتر دقت بالاتر می‌رود."
            : learningLevel === "learning"
              ? "سیستم هنوز در حال شناخت رفتار فروشگاه است و پیشنهادها محافظه‌کارانه ارائه می‌شوند."
              : "برای تحلیل هوشمند واقعی، فروش و تراکنش بیشتری لازم است.";

      let memoryRows: any[] = [];
      if (aiIsEnabled("decision_memory")) {
        for (const insight of insights) {
          await runAsync(
            `
          INSERT INTO smart_insight_decisions (insightId, type, title, severity, score, confidence, occurrenceCount, lastGeneratedAt, updatedAt)
          VALUES (?, ?, ?, ?, ?, ?, 1, strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc'), strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc'))
          ON CONFLICT(insightId) DO UPDATE SET
            type = excluded.type,
            title = excluded.title,
            severity = excluded.severity,
            score = excluded.score,
            confidence = excluded.confidence,
            occurrenceCount = COALESCE(smart_insight_decisions.occurrenceCount, 0) + 1,
            lastGeneratedAt = excluded.lastGeneratedAt,
            updatedAt = excluded.updatedAt
        `,
            [
              insight.id,
              insight.type,
              insight.title,
              insight.severity,
              insight.score,
              insight.confidence,
            ],
          );
        }
        memoryRows = await smartInsightSafeRows(
          `SELECT * FROM smart_insight_decisions ORDER BY updatedAt DESC LIMIT 500`,
        );
        const memoryById = new Map(
          (memoryRows || []).map((r: any) => [String(r.insightId), r]),
        );
        for (const insight of insights) {
          const memory: any = memoryById.get(String(insight.id)) || {};
          insight.decision = {
            status: memory.status || "open",
            userDecision: memory.userDecision || "pending",
            outcome: memory.outcome || "unknown",
            note: memory.note || "",
            actionLabel: memory.actionLabel || "",
            occurrenceCount: smartInsightNum(memory.occurrenceCount),
            firstGeneratedAt: memory.firstGeneratedAt || null,
            lastGeneratedAt: memory.lastGeneratedAt || null,
            decidedAt: memory.decidedAt || null,
            outcomeAt: memory.outcomeAt || null,
            ...smartDecisionCopy(memory),
          };
        }
      }
      const severityWeight: any = {
        critical: 120,
        high: 95,
        medium: 70,
        low: 45,
        positive: 25,
      };
      const decisionPenalty: any = {
        accepted: 28,
        rejected: 60,
        snoozed: 12,
        pending: 0,
      };
      const typeBoost: any = {
        collection_risk: 18,
        invoice_audit: 20,
        hidden_loss: 16,
        stock_reorder: 14,
        discount_anomaly: 12,
        profit_quality: 10,
        sales_drop: 8,
      };
      const todayActions = aiIsEnabled("today_actions")
        ? insights
            .filter(
              (i: any) =>
                String(i.severity) !== "positive" &&
                String(i.type) !== "daily_summary" &&
                String(i.decision?.userDecision || "pending") !== "rejected",
            )
            .map((i: any) => {
              const firstAction =
                Array.isArray(i.actions) && i.actions.length
                  ? i.actions[0]
                  : {};
              const repeatBoost = Math.min(
                18,
                smartInsightNum(i.decision?.occurrenceCount) * 2,
              );
              const outcomeBoost =
                String(i.decision?.outcome || "unknown") === "positive"
                  ? 8
                  : String(i.decision?.outcome || "unknown") === "negative"
                    ? -10
                    : 0;
              const priority = Math.max(
                1,
                Math.round(
                  (severityWeight[i.severity] || 50) +
                    smartInsightNum(i.score) * 0.42 +
                    smartInsightNum(i.confidence) * 0.18 +
                    (typeBoost[i.type] || 0) +
                    repeatBoost +
                    outcomeBoost -
                    (decisionPenalty[i.decision?.userDecision || "pending"] ||
                      0),
                ),
              );
              return {
                id: "today-action-" + i.id,
                insightId: i.id,
                title:
                  i.type === "collection_risk"
                    ? "اول وصول فوری را پیگیری کن"
                    : i.type === "stock_reorder"
                      ? "خرید مجدد کالاهای پرفروش را بررسی کن"
                      : i.type === "invoice_audit"
                        ? "فاکتورهای مشکوک را کنترل کن"
                        : i.type === "hidden_loss"
                          ? "جلوی ضرر پنهان را بگیر"
                          : i.type === "discount_anomaly"
                            ? "تخفیف‌های غیرعادی را کنترل کن"
                            : i.type === "profit_quality"
                              ? "کیفیت سود وصول‌شده را بررسی کن"
                              : i.title,
                summary: i.summary,
                priority,
                severity: i.severity,
                icon: i.icon,
                actionLabel: firstAction.label || "باز کردن اقدام",
                to: firstAction.to || "",
                decision: i.decision || {},
              };
            })
            .sort(
              (a: any, b: any) =>
                smartInsightNum(b.priority) - smartInsightNum(a.priority),
            )
            .slice(0, 3)
        : [];
      const memorySummary = (memoryRows || []).reduce(
        (acc: any, r: any) => {
          const decision = String(r.userDecision || "pending");
          const outcome = String(r.outcome || "unknown");
          acc.total += 1;
          acc[decision] = (acc[decision] || 0) + 1;
          acc["outcome_" + outcome] = (acc["outcome_" + outcome] || 0) + 1;
          return acc;
        },
        {
          total: 0,
          pending: 0,
          accepted: 0,
          rejected: 0,
          snoozed: 0,
          outcome_positive: 0,
          outcome_negative: 0,
          outcome_neutral: 0,
          outcome_unknown: 0,
        },
      );

      const summaryCounts = insights.reduce(
        (acc: any, i: any) => {
          acc[i.severity] = (acc[i.severity] || 0) + 1;
          return acc;
        },
        { critical: 0, high: 0, medium: 0, low: 0, positive: 0 },
      );

      // Smart Insight Engine: executive-grade decision layer
      // این لایه بعد از ساخت همه Insightها اجرا می‌شود تا از فروش، سود، وصول، موجودی، ممیزی و حافظه تصمیمات
      // یک خروجی مدیریتی قابل اقدام بسازد؛ نه فقط نمایش عدد خام.
      const urgentCount =
        smartInsightNum(summaryCounts.critical) +
        smartInsightNum(summaryCounts.high);
      const avgConfidence = insights.length
        ? Math.round(
            insights.reduce(
              (sum: number, i: any) => sum + smartInsightNum(i.confidence),
              0,
            ) / insights.length,
          )
        : 0;
      const profitQuality = smartInsightNum(
        profitEngine?.summary?.qualityScore || 0,
      );
      const realMargin = smartInsightNum(profitEngine?.summary?.marginPct || 0);
      const auditRiskCount =
        suspiciousInvoiceAudits.length +
        insights.filter((i: any) =>
          ["invoice_audit", "hidden_loss", "discount_anomaly"].includes(
            String(i.type),
          ),
        ).length;
      const collectionRiskCount = insights.filter(
        (i: any) => String(i.type) === "collection_risk",
      ).length;
      const inventoryRiskCount = insights.filter(
        (i: any) => String(i.type) === "stock_reorder",
      ).length;
      const decisionWinRate =
        smartInsightNum(memorySummary.accepted) > 0
          ? Math.round(
              (smartInsightNum(memorySummary.outcome_positive) /
                Math.max(1, smartInsightNum(memorySummary.accepted))) *
                100,
            )
          : 0;
      const executiveScore = Math.max(
        0,
        Math.min(
          100,
          Math.round(
            signalsScore * 0.22 +
              avgConfidence * 0.18 +
              Math.max(0, 100 - urgentCount * 11) * 0.18 +
              (profitQuality || Math.max(0, Math.min(100, realMargin * 4))) *
                0.18 +
              Math.max(0, 100 - auditRiskCount * 9) * 0.14 +
              (decisionWinRate || 55) * 0.1,
          ),
        ),
      );
      const executiveStatus =
        executiveScore >= 86
          ? "excellent"
          : executiveScore >= 70
            ? "healthy"
            : executiveScore >= 52
              ? "watch"
              : "risk";
      const executiveStatusLabel =
        executiveStatus === "excellent"
          ? "عالی و قابل اتکا"
          : executiveStatus === "healthy"
            ? "سالم"
            : executiveStatus === "watch"
              ? "نیازمند پایش"
              : "پرریسک";
      const executiveNarrative =
        executiveStatus === "excellent"
          ? "فروشگاه از نظر داده، سود و کنترل ریسک در وضعیت قابل اتکاست؛ تمرکز بعدی روی رشد سود و افزایش فروش تکراری باشد."
          : executiveStatus === "healthy"
            ? "وضعیت کلی خوب است، اما چند سیگنال مالی/عملیاتی نیاز به اقدام دارد تا سود واقعی افت نکند."
            : executiveStatus === "watch"
              ? "سیستم چند ریسک قابل توجه در سود، وصول یا موجودی دیده؛ قبل از تصمیم خرید یا تخفیف، موارد فوری بررسی شوند."
              : "ریسک گزارشات بالاست؛ بهتر است امروز اول اختلاف فاکتور، وصولی‌ها و فروش زیر قیمت کنترل شود.";
      const rankedActionPool = [...todayActions, ...insights]
        .map((item: any) => ({
          id: String(
            item.id || item.insightId || `engine-action-${Math.random()}`,
          ),
          title: item.title || "اقدام مدیریتی",
          summary: item.summary || "",
          severity: item.severity || "medium",
          priority:
            smartInsightNum(item.priority) || smartInsightNum(item.score) || 40,
          to: item.to || item.actions?.[0]?.to || "",
          actionLabel: item.actionLabel || item.actions?.[0]?.label || "بررسی",
        }))
        .sort(
          (a: any, b: any) =>
            smartInsightNum(b.priority) - smartInsightNum(a.priority),
        );
      const seenEngineActions = new Set<string>();
      const nextBestActions = rankedActionPool
        .filter((a: any) => {
          const key = `${a.title}-${a.to}`;
          if (seenEngineActions.has(key)) return false;
          seenEngineActions.add(key);
          return true;
        })
        .slice(0, 5);
      const executiveBrain = {
        score: executiveScore,
        status: executiveStatus,
        statusLabel: executiveStatusLabel,
        narrative: executiveNarrative,
        confidence: avgConfidence,
        winRate: decisionWinRate,
        focusAreas: [
          {
            key: "profit",
            label: "کیفیت سود",
            value:
              profitQuality ||
              Math.round(Math.max(0, Math.min(100, realMargin * 4))),
            tone:
              (profitQuality || realMargin * 4) >= 70 ? "positive" : "warning",
          },
          {
            key: "audit",
            label: "ریسک اختلاف",
            value: auditRiskCount,
            tone: auditRiskCount > 0 ? "danger" : "positive",
          },
          {
            key: "collection",
            label: "ریسک وصول",
            value: collectionRiskCount,
            tone: collectionRiskCount > 0 ? "warning" : "positive",
          },
          {
            key: "inventory",
            label: "ریسک موجودی",
            value: inventoryRiskCount,
            tone: inventoryRiskCount > 0 ? "warning" : "positive",
          },
        ],
        nextBestActions,
        command:
          nextBestActions[0]?.title ||
          (urgentCount
            ? "موارد فوری گزارشات را بررسی کن"
            : "وضعیت پایدار است؛ روی رشد سود تمرکز کن"),
      };
      const dailyBrief = [
        `فروش بازه: ${smartInsightMoney(salesStats.totalSales)} از ${smartInsightNum(salesStats.ordersCount).toLocaleString("fa-IR")} سند.`,
        trendPct
          ? `روند نسبت به دوره قبل: ${trendPct >= 0 ? "رشد" : "افت"} ${smartInsightPercent(Math.abs(trendPct))}.`
          : "برای مقایسه روند، داده دوره قبل محدود است.",
        `${urgentCount.toLocaleString("fa-IR")} Insight فوری/مهم برای اقدام مدیریتی وجود دارد.`,
        `وضعیت موتور تصمیم‌ساز: ${executiveStatusLabel} با امتیاز ${executiveScore.toLocaleString("fa-IR")} از ۱۰۰.`,
      ];

      res.json({
        success: true,
        data: {
          from: fromJ,
          to: toJ,
          generatedAt: new Date().toISOString(),
          currencyBase: SMART_INSIGHT_CURRENCY_BASE,
          displayCurrency: SMART_INSIGHT_DISPLAY_CURRENCY,
          moneyDivisor: 10,
          learning: {
            level: learningLevel,
            label: learningLabel,
            description: learningDescription,
            confidence: signalsScore,
            lastResetAt: resetAt,
            signals: [
              {
                label: "سندهای بررسی‌شده",
                value: ordersCount.toLocaleString("fa-IR"),
              },
              {
                label: "روزهای فعال فروش",
                value: activeDays.toLocaleString("fa-IR"),
              },
              {
                label: "اقلام دارای فروش",
                value: soldProducts.toLocaleString("fa-IR"),
              },
              {
                label: "مشتریان ثبت‌شده",
                value: customersCount.toLocaleString("fa-IR"),
              },
              {
                label: "تصمیم‌های ثبت‌شده",
                value: smartInsightNum(memorySummary.accepted).toLocaleString(
                  "fa-IR",
                ),
              },
            ],
          },
          summary: {
            totalInsights: insights.length,
            ...summaryCounts,
            totalSales: smartInsightRound(salesStats.totalSales),
            ordersCount,
            avgDaily: smartInsightRound(avgDaily),
            trendPct: smartInsightRound(trendPct),
            decisionMemory: memorySummary,
          },
          dailyBrief,
          executiveBrain,
          todayActions,
          hiddenProfit: hiddenProfitCards,
          suspiciousAudit: suspiciousInvoiceAudits,
          customerIntelligence,
          pricingRecommendations,
          salesAgentLeads,
          profitEngine,
          insights,
        },
      });
    } catch (err) {
      next(err);
    }
  },
);

// Financial Brain: executive financial decision layer
// این endpoint مستقل است تا گزارشات فقط به متن Smart Insight وابسته نباشند و خروجی تصمیم‌ساز مالی قابل تست داشته باشند.
app.get(
  "/api/brain/financial",
  authorizeRole(["Admin", "Manager", "Salesperson", "Marketer"]),
  async (req, res, next) => {
    try {
      const nowJ = moment().locale("fa");
      const fromJ = String(
        req.query.fromDate ||
          req.query.from ||
          nowJ.clone().startOf("jMonth").format("jYYYY/jMM/jDD"),
      );
      const toJ = String(
        req.query.toDate ||
          req.query.to ||
          nowJ.clone().format("jYYYY/jMM/jDD"),
      );
      const fromISO =
        fromShamsiStringToISO(fromJ) ||
        moment(fromJ, ["YYYY-MM-DD", "YYYY/MM/DD"], true).format("YYYY-MM-DD");
      const toISO =
        fromShamsiStringToISO(toJ) ||
        moment(toJ, ["YYYY-MM-DD", "YYYY/MM/DD"], true).format("YYYY-MM-DD");
      if (
        !fromISO ||
        !toISO ||
        !moment(fromISO, "YYYY-MM-DD", true).isValid() ||
        !moment(toISO, "YYYY-MM-DD", true).isValid()
      ) {
        return res.status(400).json({
          success: false,
          message: "بازه زمانی Financial Brain نامعتبر است.",
        });
      }
      const start = fromISO <= toISO ? fromISO : toISO;
      const end = fromISO <= toISO ? toISO : fromISO;
      const n = (v: any) => (Number.isFinite(Number(v)) ? Number(v) : 0);

      const sales = await getAsync(
        `
      SELECT COUNT(*) AS ordersCount,
             COALESCE(SUM(grandTotal), 0) AS totalSales,
             COALESCE(SUM(discount), 0) AS invoiceDiscount,
             COALESCE(AVG(grandTotal), 0) AS avgTicket
      FROM sales_orders
      WHERE date(substr(transactionDate, 1, 10)) BETWEEN date(?) AND date(?)
        AND COALESCE(status, 'active') = 'active'
    `,
        [start, end],
      ).catch(() => ({}) as any);

      const profit = await getAsync(
        `
      SELECT COALESCE(SUM(COALESCE(soi.totalPrice, 0)), 0) AS lineRevenue,
             COALESCE(SUM(
               COALESCE(soi.totalPrice, 0)
               - (
                 CASE
                   WHEN soi.itemType = 'phone' THEN COALESCE(NULLIF(ph.currentPurchasePrice, 0), NULLIF(soi.buyPrice, 0), ph.purchasePrice, 0)
                   WHEN soi.itemType = 'inventory' THEN COALESCE(NULLIF(soi.buyPrice, 0), p.purchasePrice, 0)
                   ELSE COALESCE(soi.buyPrice, 0)
                 END
               ) * COALESCE(soi.quantity, 1)
               - COALESCE(soi.discountPerItem, 0)
             ), 0) AS grossProfit,
             COALESCE(SUM(CASE
               WHEN soi.itemType = 'phone' AND COALESCE(NULLIF(ph.currentPurchasePrice, 0), 0) = 0 THEN 1
               WHEN soi.itemType = 'inventory' AND COALESCE(NULLIF(soi.buyPrice, 0), NULLIF(p.purchasePrice, 0), 0) = 0 THEN 1
               ELSE 0
             END), 0) AS missingCostRows
      FROM sales_order_items soi
      JOIN sales_orders so ON so.id = soi.orderId
      LEFT JOIN products p ON soi.itemType = 'inventory' AND p.id = soi.itemId
      LEFT JOIN phones ph ON soi.itemType = 'phone' AND ph.id = soi.itemId
      WHERE date(substr(so.transactionDate, 1, 10)) BETWEEN date(?) AND date(?)
        AND COALESCE(so.status, 'active') = 'active'
    `,
        [start, end],
      ).catch(() => ({}) as any);

      const collections = await getAsync(`
      SELECT COALESCE(SUM(COALESCE(remainingAmount, 0)), 0) AS openCredit,
             COALESCE(SUM(CASE WHEN dueDate IS NOT NULL AND date(substr(dueDate, 1, 10)) < date('now') THEN COALESCE(remainingAmount, 0) ELSE 0 END), 0) AS overdueAmount,
             COALESCE(SUM(CASE WHEN dueDate IS NOT NULL AND date(substr(dueDate, 1, 10)) < date('now') THEN 1 ELSE 0 END), 0) AS overdueCount
      FROM installment_sales
      WHERE COALESCE(status, 'active') NOT IN ('settled', 'cancelled')
    `).catch(() => ({}) as any);

      const stock = await getAsync(`
      SELECT COALESCE(SUM(CASE WHEN COALESCE(stock_quantity, 0) <= COALESCE(threshold, 5) THEN 1 ELSE 0 END), 0) AS lowStockCount,
             COALESCE(SUM(CASE WHEN COALESCE(stock_quantity, 0) < 0 THEN 1 ELSE 0 END), 0) AS negativeStockCount
      FROM products
    `).catch(() => ({}) as any);

      const revenue = n(sales?.totalSales);
      const grossProfit = n(profit?.grossProfit);
      const marginPct = revenue > 0 ? (grossProfit / revenue) * 100 : 0;
      const missingCosts = n(profit?.missingCostRows);
      const overdueAmount = n(collections?.overdueAmount);
      const lowStockCount = n(stock?.lowStockCount);
      const negativeStockCount = n(stock?.negativeStockCount);
      const risks: any[] = [];
      const opportunities: any[] = [];
      const actions: any[] = [];

      if (missingCosts > 0)
        risks.push({
          id: "missing-cost",
          severity: "high",
          title: "بهای تمام‌شده ناقص",
          summary: `${missingCosts.toLocaleString("fa-IR")} ردیف فروش قیمت خرید/قیمت خرید روز کامل ندارد.`,
          to: "/reports/financial-audit",
        });
      if (marginPct > 0 && marginPct < 12)
        risks.push({
          id: "low-margin",
          severity: "medium",
          title: "حاشیه سود پایین",
          summary: `حاشیه سود بازه حدود ${Math.round(marginPct).toLocaleString("fa-IR")}٪ است.`,
          to: "/reports/product-profit-real",
        });
      if (overdueAmount > 0)
        risks.push({
          id: "collection-pressure",
          severity: "high",
          title: "فشار وصول",
          summary: `وصول معوق حدود ${formatReportMoneyText(overdueAmount)} است.`,
          to: "/reports/aging-receivables",
        });
      if (lowStockCount > 0 || negativeStockCount > 0)
        risks.push({
          id: "stock-risk",
          severity: negativeStockCount > 0 ? "critical" : "medium",
          title: "ریسک موجودی",
          summary: `${lowStockCount.toLocaleString("fa-IR")} کالا کم‌موجودی و ${negativeStockCount.toLocaleString("fa-IR")} کالا موجودی منفی دارد.`,
          to: "/reports/analysis/inventory",
        });

      if (revenue > 0 && n(sales?.ordersCount) > 0)
        opportunities.push({
          id: "ticket-growth",
          title: "افزایش میانگین فاکتور",
          summary: `میانگین فاکتور فعلی ${formatReportMoneyText(n(sales?.avgTicket))} است؛ گزارش اقلام پرفروش را برای باندل بررسی کن.`,
          to: "/reports/product-sales",
        });
      if (marginPct >= 18)
        opportunities.push({
          id: "healthy-margin",
          title: "حاشیه سود قابل اتکا",
          summary: "سود بازه برای توسعه فروش کالاهای مشابه مناسب است.",
          to: "/reports/product-profit-real",
        });

      actions.push(
        ...risks.slice(0, 3).map((r) => ({
          id: "fix-" + r.id,
          title: r.title,
          summary: r.summary,
          actionLabel: "بررسی",
          to: r.to,
          severity: r.severity,
        })),
      );
      if (!actions.length)
        actions.push({
          id: "grow-profit",
          title: "تمرکز روی رشد سود",
          summary:
            "ریسک بحرانی دیده نشد؛ گزارش سود واقعی و اقلام پرفروش را برای رشد حاشیه بررسی کن.",
          actionLabel: "مشاهده سود واقعی",
          to: "/reports/product-profit-real",
          severity: "positive",
        });

      const riskPenalty = risks.reduce(
        (sum, r: any) =>
          sum +
          (r.severity === "critical" ? 18 : r.severity === "high" ? 13 : 8),
        0,
      );
      const dataPenalty = missingCosts > 0 ? Math.min(18, missingCosts * 3) : 0;
      const score = Math.max(
        0,
        Math.min(
          100,
          Math.round(
            86 + Math.min(10, marginPct / 3) - riskPenalty - dataPenalty,
          ),
        ),
      );
      const confidence = Math.max(
        55,
        Math.min(
          98,
          Math.round(96 - dataPenalty - Math.min(18, risks.length * 4)),
        ),
      );

      res.json({
        success: true,
        data: {
          range: { from: fromJ, to: toJ, fromISO: start, toISO: end },
          currencyBase: REPORT_CURRENCY_CONTRACT.currencyBase,
          displayCurrency: REPORT_CURRENCY_CONTRACT.displayCurrency,
          moneyDivisor: REPORT_CURRENCY_CONTRACT.moneyDivisor,
          summary: {
            totalSales: Math.round(revenue),
            ordersCount: n(sales?.ordersCount),
            avgTicket: Math.round(n(sales?.avgTicket)),
            grossProfit: Math.round(grossProfit),
            marginPct: Math.round(marginPct * 10) / 10,
            invoiceDiscount: Math.round(n(sales?.invoiceDiscount)),
            openCredit: Math.round(n(collections?.openCredit)),
            overdueAmount: Math.round(overdueAmount),
            lowStockCount,
            negativeStockCount,
            missingCostRows: missingCosts,
          },
          executiveBrain: {
            score,
            status:
              score >= 85
                ? "excellent"
                : score >= 70
                  ? "healthy"
                  : score >= 52
                    ? "watch"
                    : "risk",
            statusLabel:
              score >= 85
                ? "عالی و قابل اتکا"
                : score >= 70
                  ? "سالم"
                  : score >= 52
                    ? "نیازمند پایش"
                    : "پرریسک",
            confidence,
            command: actions[0]?.title || "وضعیت مالی پایدار است",
            narrative:
              actions[0]?.summary || "داده‌ها برای تصمیم مدیریتی آماده است.",
            nextBestActions: actions,
          },
          risks,
          opportunities,
          actions,
          confidence,
        },
      });
    } catch (err) {
      next(err);
    }
  },
);

// Predictive Engine: forward-looking financial brain layer
// پیش‌بینی را جدا از Insightهای توصیفی نگه می‌داریم تا تصمیم آینده‌نگر با confidence و دلیل قابل ممیزی باشد.
app.get(
  "/api/brain/predictive",
  authorizeRole(["Admin", "Manager", "Salesperson", "Marketer"]),
  async (req, res, next) => {
    try {
      const nowJ = moment().locale("fa");
      const fromJ = String(
        req.query.fromDate ||
          req.query.from ||
          nowJ.clone().startOf("jMonth").format("jYYYY/jMM/jDD"),
      );
      const toJ = String(
        req.query.toDate ||
          req.query.to ||
          nowJ.clone().format("jYYYY/jMM/jDD"),
      );
      const fromISO =
        fromShamsiStringToISO(fromJ) ||
        moment(fromJ, ["YYYY-MM-DD", "YYYY/MM/DD"], true).format("YYYY-MM-DD");
      const toISO =
        fromShamsiStringToISO(toJ) ||
        moment(toJ, ["YYYY-MM-DD", "YYYY/MM/DD"], true).format("YYYY-MM-DD");
      if (
        !fromISO ||
        !toISO ||
        !moment(fromISO, "YYYY-MM-DD", true).isValid() ||
        !moment(toISO, "YYYY-MM-DD", true).isValid()
      ) {
        return res.status(400).json({
          success: false,
          message: "بازه زمانی پیش‌بینی نامعتبر است.",
        });
      }

      const end = moment(toISO, "YYYY-MM-DD");
      const historyStartISO = end
        .clone()
        .subtract(55, "day")
        .format("YYYY-MM-DD");
      const recentStartISO = end
        .clone()
        .subtract(6, "day")
        .format("YYYY-MM-DD");
      const previousStartISO = end
        .clone()
        .subtract(13, "day")
        .format("YYYY-MM-DD");
      const previousEndISO = end
        .clone()
        .subtract(7, "day")
        .format("YYYY-MM-DD");

      const dailyRows = await allAsync(
        `
      SELECT substr(transactionDate, 1, 10) AS day,
             COUNT(*) AS ordersCount,
             COALESCE(SUM(grandTotal), 0) AS totalSales,
             COALESCE(SUM(discount), 0) AS discountTotal
      FROM sales_orders
      WHERE substr(transactionDate, 1, 10) BETWEEN ? AND ?
        AND COALESCE(status, 'active') = 'active'
      GROUP BY substr(transactionDate, 1, 10)
      ORDER BY day ASC
    `,
        [historyStartISO, toISO],
      ).catch(() => []);

      const recent7 = await getAsync(
        `
      SELECT COUNT(DISTINCT substr(transactionDate, 1, 10)) AS activeDays,
             COUNT(*) AS ordersCount,
             COALESCE(SUM(grandTotal), 0) AS totalSales,
             COALESCE(SUM(discount), 0) AS discountTotal
      FROM sales_orders
      WHERE substr(transactionDate, 1, 10) BETWEEN ? AND ?
        AND COALESCE(status, 'active') = 'active'
    `,
        [recentStartISO, toISO],
      ).catch(() => ({}) as any);

      const prev7 = await getAsync(
        `
      SELECT COUNT(DISTINCT substr(transactionDate, 1, 10)) AS activeDays,
             COUNT(*) AS ordersCount,
             COALESCE(SUM(grandTotal), 0) AS totalSales,
             COALESCE(SUM(discount), 0) AS discountTotal
      FROM sales_orders
      WHERE substr(transactionDate, 1, 10) BETWEEN ? AND ?
        AND COALESCE(status, 'active') = 'active'
    `,
        [previousStartISO, previousEndISO],
      ).catch(() => ({}) as any);

      const num = (v: any) => (Number.isFinite(Number(v)) ? Number(v) : 0);
      const activeDays = Math.max(1, num(recent7?.activeDays));
      const prevActiveDays = Math.max(1, num(prev7?.activeDays));
      const recentAvgDaily = num(recent7?.totalSales) / activeDays;
      const prevAvgDaily = num(prev7?.totalSales) / prevActiveDays;
      const trendPct =
        prevAvgDaily > 0
          ? ((recentAvgDaily - prevAvgDaily) / prevAvgDaily) * 100
          : 0;
      const boundedTrend = Math.max(-0.35, Math.min(0.35, trendPct / 100));
      const tomorrowSalesForecast = Math.max(
        0,
        Math.round(recentAvgDaily * (1 + boundedTrend * 0.45)),
      );
      const next7SalesForecast = Math.max(
        0,
        Math.round(recentAvgDaily * 7 * (1 + boundedTrend * 0.35)),
      );
      const avgTicket =
        num(recent7?.ordersCount) > 0
          ? num(recent7?.totalSales) / Math.max(1, num(recent7?.ordersCount))
          : 0;
      const forecastOrders =
        avgTicket > 0
          ? Math.max(0, Math.round(tomorrowSalesForecast / avgTicket))
          : 0;

      const stockRows = await allAsync(
        `
      SELECT p.id AS productId,
             p.name AS productName,
             COALESCE(p.stock_quantity, 0) AS stockQuantity,
             COALESCE(p.threshold, 5) AS thresholdQty,
             COALESCE(SUM(soi.quantity), 0) AS soldQty14,
             COALESCE(SUM(soi.totalPrice), 0) AS soldAmount14
      FROM products p
      LEFT JOIN sales_order_items soi ON soi.itemType = 'inventory' AND soi.itemId = p.id
      LEFT JOIN sales_orders so ON so.id = soi.orderId
        AND substr(so.transactionDate, 1, 10) BETWEEN ? AND ?
        AND COALESCE(so.status, 'active') = 'active'
      GROUP BY p.id, p.name, p.stock_quantity, p.threshold
      HAVING soldQty14 > 0 OR stockQuantity <= thresholdQty
      ORDER BY (CASE WHEN stockQuantity <= thresholdQty THEN 1 ELSE 0 END) DESC, soldQty14 DESC, soldAmount14 DESC
      LIMIT 12
    `,
        [end.clone().subtract(13, "day").format("YYYY-MM-DD"), toISO],
      ).catch(() => []);

      const stockoutRisks = (stockRows || [])
        .map((r: any) => {
          const avgDailySold = num(r.soldQty14) / 14;
          const daysToStockout =
            avgDailySold > 0
              ? num(r.stockQuantity) / avgDailySold
              : num(r.stockQuantity) <= num(r.thresholdQty)
                ? 0
                : 999;
          const severity =
            daysToStockout <= 2
              ? "critical"
              : daysToStockout <= 5
                ? "high"
                : daysToStockout <= 9
                  ? "medium"
                  : "low";
          const suggestedBuyQty = Math.max(
            0,
            Math.ceil(avgDailySold * 21 - num(r.stockQuantity)),
          );
          return {
            productId: r.productId,
            productName: r.productName || "کالا",
            stockQuantity: num(r.stockQuantity),
            thresholdQty: num(r.thresholdQty),
            soldQty14: num(r.soldQty14),
            avgDailySold: Math.round(avgDailySold * 100) / 100,
            daysToStockout:
              daysToStockout >= 999
                ? null
                : Math.round(daysToStockout * 10) / 10,
            suggestedBuyQty,
            severity,
            actionLabel:
              suggestedBuyQty > 0 ? "بررسی خرید مجدد" : "کنترل موجودی",
            to: "/reports/analysis/suggestions",
          };
        })
        .filter((r: any) => r.severity !== "low" || r.suggestedBuyQty > 0)
        .slice(0, 8);

      const overdue = await getAsync(
        `
      SELECT COUNT(*) AS overdueCount, COALESCE(SUM(amountDue), 0) AS overdueAmount
      FROM installment_payments
      WHERE COALESCE(status, 'پرداخت نشده') <> 'پرداخت شده'
        AND REPLACE(dueDate, '/', '-') < ?
    `,
        [toISO],
      ).catch(() => ({ overdueCount: 0, overdueAmount: 0 }) as any);

      const dueSoon = await getAsync(
        `
      SELECT COUNT(*) AS dueSoonCount, COALESCE(SUM(amountDue), 0) AS dueSoonAmount
      FROM installment_payments
      WHERE COALESCE(status, 'پرداخت نشده') <> 'پرداخت شده'
        AND REPLACE(dueDate, '/', '-') BETWEEN ? AND ?
    `,
        [toISO, end.clone().add(7, "day").format("YYYY-MM-DD")],
      ).catch(() => ({ dueSoonCount: 0, dueSoonAmount: 0 }) as any);

      const discountPressure =
        num(recent7?.totalSales) > 0
          ? (num(recent7?.discountTotal) /
              Math.max(1, num(recent7?.totalSales))) *
            100
          : 0;
      const dataPoints = Array.isArray(dailyRows) ? dailyRows.length : 0;
      const baseConfidence = Math.min(
        94,
        Math.max(
          38,
          42 + dataPoints * 2.1 + Math.min(20, num(recent7?.ordersCount) * 0.8),
        ),
      );
      const confidence = Math.round(
        Math.max(
          25,
          Math.min(
            96,
            baseConfidence -
              Math.min(14, Math.abs(trendPct) * 0.12) -
              (discountPressure > 18 ? 6 : 0),
          ),
        ),
      );

      const alerts: any[] = [];
      if (trendPct <= -18)
        alerts.push({
          id: "predicted-sales-drop",
          severity: trendPct <= -35 ? "critical" : "high",
          title: "ریسک افت فروش فردا",
          summary: `روند ۷ روز اخیر نسبت به ۷ روز قبل حدود ${Math.abs(Math.round(trendPct)).toLocaleString("fa-IR")}٪ افت دارد.`,
          actionLabel: "بررسی گزارش فروش",
          to: "/reports/sales",
        });
      if (
        stockoutRisks.some((r: any) =>
          ["critical", "high"].includes(r.severity),
        )
      )
        alerts.push({
          id: "stockout-next-days",
          severity: "high",
          title: "ریسک اتمام موجودی در چند روز آینده",
          summary: `${stockoutRisks.filter((r: any) => ["critical", "high"].includes(r.severity)).length.toLocaleString("fa-IR")} کالا سیگنال خرید فوری دارد.`,
          actionLabel: "مشاهده پیشنهاد خرید",
          to: "/reports/analysis/suggestions",
        });
      if (num(overdue?.overdueCount) > 0 || num(dueSoon?.dueSoonCount) > 0)
        alerts.push({
          id: "collection-pressure-next-week",
          severity: num(overdue?.overdueCount) > 0 ? "high" : "medium",
          title: "فشار وصول هفته آینده",
          summary: `${num(overdue?.overdueCount).toLocaleString("fa-IR")} قسط معوق و ${num(dueSoon?.dueSoonCount).toLocaleString("fa-IR")} قسط نزدیک سررسید وجود دارد.`,
          actionLabel: "مرکز پیگیری وصول",
          to: "/reports/collection-center",
        });
      if (discountPressure >= 18)
        alerts.push({
          id: "discount-pressure",
          severity: "medium",
          title: "احتمال فشار روی حاشیه سود",
          summary: `نسبت تخفیف به فروش ۷ روز اخیر حدود ${Math.round(discountPressure).toLocaleString("fa-IR")}٪ است.`,
          actionLabel: "بررسی سود واقعی",
          to: "/reports/product-profit-real",
        });

      res.json({
        success: true,
        data: {
          from: fromJ,
          to: toJ,
          generatedAt: new Date().toISOString(),
          confidence,
          horizon: {
            tomorrow: end.clone().add(1, "day").format("YYYY-MM-DD"),
            next7DaysUntil: end.clone().add(7, "day").format("YYYY-MM-DD"),
          },
          forecast: {
            tomorrowSales: tomorrowSalesForecast,
            next7Sales: next7SalesForecast,
            tomorrowOrders: forecastOrders,
            avgTicket: Math.round(avgTicket),
            trendPct: Math.round(trendPct * 10) / 10,
            discountPressure: Math.round(discountPressure * 10) / 10,
          },
          risks: {
            stockout: stockoutRisks,
            collection: {
              overdueCount: num(overdue?.overdueCount),
              overdueAmount: Math.round(num(overdue?.overdueAmount)),
              dueSoonCount: num(dueSoon?.dueSoonCount),
              dueSoonAmount: Math.round(num(dueSoon?.dueSoonAmount)),
            },
          },
          alerts,
          method: {
            label:
              "میانگین متحرک ۷ روزه + مقایسه ۷ روز قبل + ریسک موجودی بر اساس نرخ مصرف ۱۴ روزه",
            dataPoints,
            warning:
              dataPoints < 10
                ? "داده تاریخی کم است؛ پیش‌بینی را به‌عنوان جهت روند ببین، نه عدد قطعی."
                : "",
          },
        },
      });
    } catch (err) {
      next(err);
    }
  },
);

app.post(
  "/api/reports/smart-insights/decisions",
  authorizeRole(["Admin", "Manager", "Salesperson", "Marketer"]),
  async (req, res, next) => {
    try {
      const featureMap = await getAiFeatureEnabledMap();
      if (featureMap.decision_memory === false)
        return res.status(409).json({
          success: false,
          message: "حافظه تصمیمات در تنظیمات هوشمندسازی خاموش است.",
        });
      await ensureSmartInsightDecisionMemory();
      const body = req.body || {};
      const insightId = String(body.insightId || "").trim();
      if (!insightId)
        return res
          .status(400)
          .json({ success: false, message: "شناسه Insight نامعتبر است." });
      const userDecision = normalizeSmartDecisionValue(
        body.userDecision,
        ["pending", "accepted", "rejected", "snoozed"],
        "pending",
      );
      const outcome = normalizeSmartDecisionValue(
        body.outcome,
        ["unknown", "positive", "negative", "neutral"],
        "unknown",
      );
      const status = normalizeSmartDecisionValue(
        body.status,
        ["open", "closed", "dismissed", "snoozed"],
        userDecision === "rejected"
          ? "dismissed"
          : userDecision === "snoozed"
            ? "snoozed"
            : "open",
      );
      const note = String(body.note || "")
        .trim()
        .slice(0, 1000);
      const actionLabel = String(body.actionLabel || "")
        .trim()
        .slice(0, 180);
      await runAsync(
        `
      INSERT INTO smart_insight_decisions (insightId, type, title, severity, score, confidence, status, userDecision, outcome, note, actionLabel, decidedAt, outcomeAt, updatedAt, userId)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, CASE WHEN ? != 'pending' THEN strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc') ELSE NULL END, CASE WHEN ? != 'unknown' THEN strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc') ELSE NULL END, strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc'), ?)
      ON CONFLICT(insightId) DO UPDATE SET
        type = COALESCE(NULLIF(excluded.type, ''), smart_insight_decisions.type), title = COALESCE(NULLIF(excluded.title, ''), smart_insight_decisions.title),
        severity = COALESCE(NULLIF(excluded.severity, ''), smart_insight_decisions.severity), score = excluded.score, confidence = excluded.confidence,
        status = excluded.status, userDecision = excluded.userDecision, outcome = excluded.outcome, note = excluded.note, actionLabel = excluded.actionLabel,
        decidedAt = CASE WHEN excluded.userDecision != 'pending' THEN strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc') ELSE smart_insight_decisions.decidedAt END,
        outcomeAt = CASE WHEN excluded.outcome != 'unknown' THEN strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc') ELSE smart_insight_decisions.outcomeAt END,
        updatedAt = excluded.updatedAt, userId = excluded.userId
    `,
        [
          insightId,
          String(body.type || "")
            .trim()
            .slice(0, 80),
          String(body.title || "")
            .trim()
            .slice(0, 240),
          String(body.severity || "")
            .trim()
            .slice(0, 40),
          smartInsightNum(body.score),
          smartInsightNum(body.confidence),
          status,
          userDecision,
          outcome,
          note,
          actionLabel,
          userDecision,
          outcome,
          req.user?.id || null,
        ],
      );
      const featureKey = insightTypeToAiFeatureKey(
        body.type || "decision_memory",
      );
      await recordAiFeatureImpactEvent(
        featureKey,
        outcome === "positive"
          ? "positive_outcome"
          : outcome === "negative"
            ? "negative_outcome"
            : userDecision === "accepted"
              ? "accepted_decision"
              : userDecision === "rejected"
                ? "rejected_decision"
                : "decision_update",
        {
          impactAmount:
            outcome === "positive"
              ? smartInsightNum(body.score) * 10000
              : outcome === "negative"
                ? -smartInsightNum(body.score) * 10000
                : 0,
          success: outcome !== "negative",
          context: { insightId, title: body.title, actionLabel },
          userId: req.user?.id || null,
        },
      );
      const row = await smartInsightSafeOne(
        `SELECT * FROM smart_insight_decisions WHERE insightId = ?`,
        [insightId],
      );
      res.json({ success: true, data: { ...row, ...smartDecisionCopy(row) } });
    } catch (err) {
      next(err);
    }
  },
);
