app.post(
  "/api/telegram/admin/send-customer-menu",
  authorizeRole(["Admin", "Manager"]),
  async (req, res, next) => {
    try {
      const chatId = String(req.body?.chatId || req.query?.chatId || "").trim();
      const customerIdRaw = String(
        req.body?.customerId || req.query?.customerId || "",
      ).trim();
      const phoneRaw = String(req.body?.phone || req.query?.phone || "").trim();
      if (!chatId)
        return res
          .status(400)
          .json({ success: false, message: "Chat ID الزامی است." });
      let customer: any = null;
      if (customerIdRaw) {
        customer = await getAsync(
          `SELECT id, fullName, phoneNumber FROM customers WHERE id=? LIMIT 1`,
          [Number(customerIdRaw)],
        );
      } else if (phoneRaw) {
        const normalizedPhone = normalizeIranPhone(phoneRaw);
        const rows = await allAsync(
          `SELECT id, fullName, phoneNumber FROM customers WHERE COALESCE(phoneNumber,'') != ''`,
        ).catch(() => [] as any[]);
        customer =
          (rows || []).find(
            (r: any) =>
              normalizeIranPhone(String(r?.phoneNumber || "")) ===
              normalizedPhone,
          ) || null;
      }
      if (!customer?.id)
        return res.status(404).json({
          success: false,
          message: "مشتری با این شماره موبایل/شناسه پیدا نشد.",
        });
      const customerId = Number(customer.id);

      try {
        await runAsync(
          `UPDATE customers
         SET telegramChatId=?, telegram_chat_id=?, telegram_user_id=?, telegram_linked_at=strftime('%Y-%m-%dT%H:%M:%SZ','now','utc'), telegram_opted_out=0
         WHERE id=?`,
          [chatId, chatId, chatId, customerId],
        );
      } catch {
        await runAsync(`UPDATE customers SET telegramChatId=? WHERE id=?`, [
          chatId,
          customerId,
        ]);
      }

      // Prevent the same Telegram chat from also being treated as a partner.
      await runAsync(
        `UPDATE partners SET telegramChatId=NULL WHERE telegramChatId=?`,
        [chatId],
      ).catch(() => {});
      await runAsync(
        `UPDATE partners SET telegram_chat_id=NULL WHERE telegram_chat_id=?`,
        [chatId],
      ).catch(() => {});

      await ensureTelegramPersistentMenu().catch(() => {});
      await handleTelegramUpdate({
        update_id: Date.now(),
        message: {
          message_id: Date.now(),
          chat: { id: chatId, type: "private" },
          from: { id: chatId, is_bot: false },
          text: "/menu",
          date: Math.floor(Date.now() / 1000),
        },
      });

      res.json({
        success: true,
        message: `منوی واقعی مشتری برای ${customer.fullName || "مشتری"} ارسال و همین Chat ID به پرونده مشتری وصل شد.`,
      });
    } catch (e) {
      next(e);
    }
  },
);

