app.get(
  "/api/telegram/partner-deeplink/:partnerId",
  authorizeRole(["Admin", "Manager"]),
  async (req, res, next) => {
    try {
      const partnerId = Number(req.params.partnerId || 0);
      if (!partnerId)
        return res
          .status(400)
          .json({ success: false, message: "partnerId الزامی است." });
      const partner = await getAsync(
        `SELECT id, partnerName, phoneNumber, telegramChatId FROM partners WHERE id=? LIMIT 1`,
        [partnerId],
      );
      if (!partner)
        return res
          .status(404)
          .json({ success: false, message: "همکار پیدا نشد." });
      const settings = await getAllSettingsAsObject();
      let botUsername = String((settings as any).telegram_bot_username || "")
        .trim()
        .replace(/^@+/, "");
      const botToken = String(
        (settings as any).telegram_bot_token || "",
      ).trim();
      if (!botUsername && botToken) {
        try {
          const me = await getTelegramBotInfo(botToken);
          const fetchedUsername = String(
            (me as any)?.result?.username ||
              (me as any)?.data?.result?.username ||
              (me as any)?.data?.username ||
              "",
          )
            .trim()
            .replace(/^@+/, "");
          if (fetchedUsername) {
            botUsername = fetchedUsername;
            await updateSetting("telegram_bot_username", fetchedUsername);
          }
        } catch (err: any) {
          return res.status(502).json({
            success: false,
            message:
              err?.message ||
              "دریافت نام کاربری ربات از تلگرام عملیات ناعملیات با موفقیت انجام شد بود بود.",
          });
        }
      }
      if (!botUsername) {
        return res.status(400).json({
          success: false,
          message:
            "نام کاربری ربات تلگرام ثبت نشده است. در تنظیمات تلگرام، نام کاربری ربات را بدون @ وارد کنید.",
        });
      }
      const deepLink = `https://t.me/${botUsername}?start=${encodeURIComponent(`partner_${partnerId}`)}`;
      return res.json({
        success: true,
        data: {
          partnerId,
          partnerName: String((partner as any).partnerName || ""),
          botUsername,
          deepLink,
          qrData: deepLink,
          linked: !!(partner as any).telegramChatId,
        },
      });
    } catch (e) {
      next(e);
    }
  },
);
app.post(
  "/api/telegram/link-token",
  authorizeRole(["Admin", "Manager"]),
  async (req, res, next) => {
    try {
      const customerId = Number(req.body?.customerId || 0);
      const minutes = Number(req.body?.expiresMinutes ?? 60);
      if (!customerId)
        return res
          .status(400)
          .json({ success: false, message: "customerId الزامی است." });
      const created = await createTelegramLinkToken({
        customerId,
        expiresMinutes: minutes,
      });
      const settings = await getAllSettingsAsObject();
      const publicBase = String(
        (settings as any).public_app_base_url || "",
      ).trim(); // e.g. https://your.app
      let botUsername = String((settings as any).telegram_bot_username || "")
        .trim()
        .replace(/^@+/, "");
      const botToken = String(
        (settings as any).telegram_bot_token || "",
      ).trim();
      if (!botUsername && botToken) {
        try {
          const me = await getTelegramBotInfo(botToken);
          const fetchedUsername = String((me as any)?.result?.username || "")
            .trim()
            .replace(/^@+/, "");
          if (fetchedUsername) {
            botUsername = fetchedUsername;
            await updateSetting("telegram_bot_username", fetchedUsername);
          }
        } catch {}
      }
      const deepLink = botUsername
        ? `https://t.me/${botUsername}?start=link_${created.token}`
        : "";
      res.json({
        success: true,
        data: {
          token: created.token,
          deepLink,
          expiresAt: created.expiresAtISO,
          expectedPhone: created.expectedPhone,
          publicBase,
          botUsername,
        },
      });
    } catch (e) {
      next(e);
    }
  },
);
