// بررسی گروهی چند پترن انتخابی (Bulk Check)
app.post(
  "/api/sms/bulk-check",
  authorizeRole(["Admin", "Manager"]),
  async (req, res, next) => {
    try {
      const settings = await getAllSettingsAsObject();
      const provider: string = (
        settings.sms_provider || "meli_payamak"
      ).toLowerCase();
      if (provider !== "meli_payamak") {
        return res.status(400).json({
          success: false,
          message: "بررسی گروهی فعلاً فقط برای «ملی پیامک» فعال است.",
        });
      }
      const username = settings.meli_payamak_username;
      const password = settings.meli_payamak_password;
      if (!username || !password) {
        return res.status(400).json({
          success: false,
          message: "نام کاربری/رمز عبور ملی پیامک در تنظیمات وارد نشده است.",
        });
      }
      const { to, checks } = req.body || {};
      const recipient = String(to || "").trim();
      if (!recipient || recipient.length < 10) {
        return res
          .status(400)
          .json({ success: false, message: "شماره گیرنده نامعتبر است." });
      }
      const arr: any[] = Array.isArray(checks) ? checks : [];
      if (!arr.length) {
        return res.status(400).json({
          success: false,
          message: "هیچ پیامکی برای بررسی انتخاب نشده است.",
        });
      }
      const results: any[] = [];
      for (const t of arr) {
        const bodyId = Number(t?.bodyId);
        const key = String(t?.key || "").trim();
        const label = String(t?.label || key || "پیامک");
        const tokenArr: string[] = Array.isArray(t?.tokens)
          ? t.tokens.map((x: any) => String(x ?? ""))
          : [];
        if (!bodyId || isNaN(bodyId) || bodyId <= 0) {
          results.push({
            key,
            label,
            bodyId,
            success: false,
            message: "BodyId نامعتبر است.",
          });
          continue;
        }
        const smsResult = await sendMeliPayamakPatternSms(
          recipient,
          bodyId,
          tokenArr,
          username,
          password,
        );
        await insertSmsLog({
          reqUser: req.user,
          provider,
          eventType: "TEST_BULK",
          entityType: "settings",
          recipient,
          patternId: String(bodyId),
          tokens: tokenArr,
          success: !!smsResult?.success,
          response: smsResult,
          error: smsResult?.success ? undefined : smsResult?.message,
        });
        results.push({
          key,
          label,
          bodyId,
          success: !!smsResult?.success,
          message: smsResult?.success
            ? "ارسال شد"
            : smsResult?.message || "عملیات ناعملیات با موفقیت انجام شد بود",
          data: smsResult,
        });
      }
      return res.json({ success: true, provider, to: recipient, results });
    } catch (e) {
      next(e);
    }
  },
);
// =====================================================
// Notification Outbox (Queue/Retry) + Auto-Send Rules
// =====================================================
type OutboxStatus = "pending" | "processing" | "done" | "failed";
type OutboxChannel = "sms" | "telegram";
type OutboxRow = {
  id: number;
  channel: OutboxChannel;
  provider?: string | null;
  eventType?: string | null;
  entityType?: string | null;
  entityId?: number | null;
  recipient: string;
  payloadJson: string;
  status: OutboxStatus;
  attempts: number;
  maxAttempts: number;
  nextAttemptAt?: string | null;
  lastError?: string | null;
  createdAt: string;
  updatedAt: string;
};
const ensureNotificationOutboxTables = async () => {
  await runAsync(`
    CREATE TABLE IF NOT EXISTS notification_outbox (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      channel TEXT NOT NULL,
      provider TEXT,
      eventType TEXT,
      entityType TEXT,
      entityId INTEGER,
      recipient TEXT NOT NULL,
      payloadJson TEXT NOT NULL,
      eventKey TEXT,
      capCustomerId INTEGER,
      status TEXT NOT NULL DEFAULT 'pending',
      attempts INTEGER NOT NULL DEFAULT 0,
      maxAttempts INTEGER NOT NULL DEFAULT 6,
      nextAttemptAt TEXT,
      lastError TEXT,
      supportStatus TEXT,
      supportNote TEXT,
      supportUpdatedAt TEXT,
      createdAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc')),
      updatedAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc'))
    );
  `);
  // Lightweight migrations for older DBs (SQLite doesn't support IF NOT EXISTS on ADD COLUMN).
  try {
    const cols = await allAsync(`PRAGMA table_info(notification_outbox)`);
    const has = (name: string) =>
      (cols || []).some((c: any) => String(c?.name) === name);
    if (!has("supportStatus"))
      await runAsync(
        `ALTER TABLE notification_outbox ADD COLUMN supportStatus TEXT`,
      ).catch(() => {});
    if (!has("supportNote"))
      await runAsync(
        `ALTER TABLE notification_outbox ADD COLUMN supportNote TEXT`,
      ).catch(() => {});
    if (!has("supportUpdatedAt"))
      await runAsync(
        `ALTER TABLE notification_outbox ADD COLUMN supportUpdatedAt TEXT`,
      ).catch(() => {});
    if (!has("eventKey"))
      await runAsync(
        `ALTER TABLE notification_outbox ADD COLUMN eventKey TEXT`,
      ).catch(() => {});
    if (!has("capCustomerId"))
      await runAsync(
        `ALTER TABLE notification_outbox ADD COLUMN capCustomerId INTEGER`,
      ).catch(() => {});
    if (!has("telegramMessageId"))
      await runAsync(
        `ALTER TABLE notification_outbox ADD COLUMN telegramMessageId INTEGER`,
      ).catch(() => {});
  } catch {
    // ignore
  }
  await runAsync(`
    CREATE TABLE IF NOT EXISTS notification_sent_log (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      dayKey TEXT NOT NULL,
      channel TEXT NOT NULL,
      eventType TEXT,
      entityType TEXT,
      entityId INTEGER,
      recipient TEXT,
      createdAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc'))
    );
  `);
  await runAsync(`
    CREATE UNIQUE INDEX IF NOT EXISTS idx_notification_sent_dedupe
    ON notification_sent_log(dayKey, channel, eventType, entityType, entityId, recipient);
  `);
  await runAsync(`
    CREATE TABLE IF NOT EXISTS notification_event_dedupe (
      eventKey TEXT PRIMARY KEY,
      lastQueuedAt TEXT,
      lastSentAt TEXT
    );
  `);
  await runAsync(
    `CREATE INDEX IF NOT EXISTS idx_notification_event_dedupe_lastQueued ON notification_event_dedupe(lastQueuedAt);`,
  );
};
// =====================================================
// Reminder Rules (CRM-style Rule Builder for Installments)
// =====================================================
type ReminderMatchType = "days_until" | "overdue_days";
type ReminderChannel = "telegram" | "sms";
type ReminderTargetType = "both" | "installment" | "check";
type ReminderRuleRow = {
  id: number;
  name: string;
  enabled: number;
  channel: ReminderChannel;
  matchType: ReminderMatchType;
  value: number;
  template: string;
  installmentTemplate?: string;
  checkTemplate?: string;
  targetType?: ReminderTargetType;
  createdAt: string;
  updatedAt: string;
  matchedCount?: number;
};
type ReminderConfigRow = {
  id: number;
  sendStartHour: number;
  sendEndHour: number;
  maxPerDayPerCustomer: number;
  timezone: string;
};
const ensureReminderRulesTables = async () => {
  await runAsync(`
    CREATE TABLE IF NOT EXISTS reminder_config (
      id INTEGER PRIMARY KEY CHECK (id = 1),
      sendStartHour INTEGER NOT NULL DEFAULT 10,
      sendEndHour INTEGER NOT NULL DEFAULT 21,
      maxPerDayPerCustomer INTEGER NOT NULL DEFAULT 1,
      timezone TEXT NOT NULL DEFAULT 'Asia/Tehran',
      updatedAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc'))
    );
  `);
  await runAsync(`INSERT OR IGNORE INTO reminder_config (id) VALUES (1);`);
  await runAsync(`
    CREATE TABLE IF NOT EXISTS reminder_rules (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL,
      enabled INTEGER NOT NULL DEFAULT 1,
      channel TEXT NOT NULL DEFAULT 'telegram',
      matchType TEXT NOT NULL,
      value INTEGER NOT NULL,
      template TEXT NOT NULL,
      installmentTemplate TEXT,
      checkTemplate TEXT,
      targetType TEXT NOT NULL DEFAULT 'both',
      createdAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc')),
      updatedAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc'))
    );
  `);
  try {
    const cols: any[] = await allAsync(
      `PRAGMA table_info(reminder_rules)`,
    ).catch(() => []);
    const has = (name: string) =>
      cols.some(
        (c: any) => String(c?.name || "").toLowerCase() === name.toLowerCase(),
      );
    if (!has("installmentTemplate"))
      await runAsync(
        `ALTER TABLE reminder_rules ADD COLUMN installmentTemplate TEXT`,
      ).catch(() => {});
    if (!has("checkTemplate"))
      await runAsync(
        `ALTER TABLE reminder_rules ADD COLUMN checkTemplate TEXT`,
      ).catch(() => {});
    if (!has("targetType"))
      await runAsync(
        `ALTER TABLE reminder_rules ADD COLUMN targetType TEXT NOT NULL DEFAULT 'both'`,
      ).catch(() => {});
  } catch {}
  // Daily cap log (successful sends)
  await runAsync(`
    CREATE TABLE IF NOT EXISTS reminder_daily_cap (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      dayKey TEXT NOT NULL,
      channel TEXT NOT NULL,
      customerId INTEGER NOT NULL,
      createdAt TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now', 'utc')),
      UNIQUE(dayKey, channel, customerId)
    );
  `);
};
const getReminderConfig = async (): Promise<ReminderConfigRow> => {
  const row = await getAsync(
    `SELECT * FROM reminder_config WHERE id=1 LIMIT 1`,
    [],
  ).catch(() => null);
  return {
    id: 1,
    sendStartHour: Number(row?.sendStartHour ?? 10),
    sendEndHour: Number(row?.sendEndHour ?? 21),
    maxPerDayPerCustomer: Math.max(1, Number(row?.maxPerDayPerCustomer ?? 1)),
    timezone: String(row?.timezone || "Asia/Tehran"),
  };
};
const getReminderRules = async (): Promise<ReminderRuleRow[]> => {
  const rows = await allAsync(
    `SELECT * FROM reminder_rules ORDER BY id DESC`,
    [],
  ).catch(() => []);
  return (rows || []) as any;
};
const getEnabledReminderRules = async (
  channel: ReminderChannel,
): Promise<ReminderRuleRow[]> => {
  const rows = await allAsync(
    `SELECT * FROM reminder_rules WHERE enabled=1 AND channel=? ORDER BY id ASC`,
    [channel],
  ).catch(() => []);
  return (rows || []) as any;
};
const normalizeReminderTargetType = (value: any): ReminderTargetType => {
  const v = String(value || "").trim();
  if (v === "installment" || v === "check" || v === "both")
    return v as ReminderTargetType;
  return "both";
};
const reminderTargetsInstallments = (
  rule: Pick<ReminderRuleRow, "targetType">,
) => normalizeReminderTargetType((rule as any).targetType) !== "check";
const reminderTargetsChecks = (rule: Pick<ReminderRuleRow, "targetType">) =>
  normalizeReminderTargetType((rule as any).targetType) !== "installment";
const countRuleMatches = async (
  rule: Pick<ReminderRuleRow, "matchType" | "value">,
): Promise<number> => {
  const now = moment();
  const today = now.clone().startOf("day");
  const allUnpaid = await getOverdueInstallmentsFromDb();
  const allChecks = await getPendingInstallmentChecksWithCustomer().catch(
    () => [],
  );
  const matchedCustomerIds = new Set<number>();
  const scanDueItems = (items: any[] | undefined) => {
    for (const item of items || []) {
      const due = parseAnyDate(item?.dueDate);
      if (!due) continue;
      const daysUntil = due.clone().startOf("day").diff(today, "days");
      const matched =
        rule.matchType === "days_until"
          ? Number(daysUntil) === Number(rule.value)
          : Number(daysUntil) === -Math.abs(Number(rule.value));
      if (!matched) continue;
      const customerId = Number(item?.customerId || 0);
      if (customerId > 0) matchedCustomerIds.add(customerId);
    }
  };
  if (reminderTargetsInstallments(rule as any))
    scanDueItems(allUnpaid as any[]);
  if (reminderTargetsChecks(rule as any)) scanDueItems(allChecks as any[]);
  return matchedCustomerIds.size;
};
// Store dayKey in UTC to match createdAt timestamps (which are saved in UTC).
const getDayKeyUtc = () => moment().utc().format("YYYY-MM-DD");
const hasCustomerDailyCap = async (
  channel: ReminderChannel,
  customerId: number,
) => {
  const dayKey = getDayKeyUtc();
  const row = await getAsync(
    `SELECT 1 as ok FROM reminder_daily_cap WHERE dayKey=? AND channel=? AND customerId=? LIMIT 1`,
    [dayKey, channel, customerId],
  ).catch(() => null);
  return !!row;
};
const hasPendingCustomerCapInOutbox = async (
  channel: ReminderChannel,
  customerId: number,
) => {
  // Prevent enqueue spam before success is logged.
  const dayKey = getDayKeyUtc();
  const row = await getAsync(
    `SELECT 1 as ok
       FROM notification_outbox
      WHERE channel=?
        AND status IN ('pending','processing')
        AND createdAt >= ?
        AND IFNULL(capCustomerId,0)=?
      LIMIT 1`,
    [channel, `${dayKey}T00:00:00Z`, customerId],
  ).catch(() => null);
  return !!row;
};
