// Send check (immediate) using the same payload text + chatId (helps debug blocked/chat/proxy)
app.post(
  "/api/telegram/outbox/:id/send-check",
  authorizeRole(["Admin", "Manager"]),
  async (req, res, next) => {
    try {
      await ensureNotificationOutboxTables();
      const id = Number(req.params.id);
      const row: any = await getAsync(
        `SELECT * FROM notification_outbox WHERE id=? AND channel='telegram' LIMIT 1`,
        [id],
      );
      if (!row)
        return res
          .status(404)
          .json({ success: false, message: "پیام پیدا نشد." });

      let payload: any = {};
      try {
        payload = JSON.parse(String(row.payloadJson || "{}"));
      } catch {
        payload = {};
      }

      const msgType = String(payload?.type || "message");
      const text = String(
        payload?.text ||
          payload?.message ||
          payload?.body ||
          payload?.caption ||
          "",
      ).trim();
      const replyMarkup = payload?.reply_markup || payload?.replyMarkup || null;
      const parseMode = payload?.parse_mode || payload?.parseMode || "HTML";
      const replyToMessageId = Number(payload?.replyToMessageId || 0) || 0;
      const mimeType = payload?.mimeType || undefined;
      const fileRelPath =
        payload?.fileRelPath || payload?.filePath || payload?.relPath || null;

      let effectiveChatId = String(
        payload?.chatId || payload?.recipient || "",
      ).trim();
      if (!effectiveChatId && row.recipient === "telegram_chat") {
        const capCustomerId = Number(
          payload?.capCustomerId ??
            payload?.meta?.capCustomerId ??
            row.capCustomerId ??
            0,
        );
        if (capCustomerId)
          effectiveChatId = await lookupCustomerTelegramChatId(capCustomerId);
      }
      if (!effectiveChatId && row.recipient === "telegram_partner_chat") {
        const partnerId = Number(
          payload?.partnerId ?? payload?.meta?.partnerId ?? row.entityId ?? 0,
        );
        if (partnerId)
          effectiveChatId = await lookupPartnerTelegramChatId(partnerId);
      }
      if (
        !effectiveChatId &&
        String(row.recipient || "").trim() &&
        !["telegram_chat", "telegram_partner_chat"].includes(
          String(row.recipient),
        )
      ) {
        effectiveChatId = String(row.recipient || "").trim();
      }

      if (!effectiveChatId)
        return res.json({
          success: false,
          message:
            "Chat ID مقصد پیدا نشد. اگر پیام مربوط به مشتری/همکار است، ابتدا اتصال تلگرام او را بررسی کنید.",
        });
      if (!text && !(msgType === "photo" || msgType === "document"))
        return res.json({ success: false, message: "متن پیام خالی است." });

      let r: any;
      if (msgType === "photo" || msgType === "document") {
        if (!fileRelPath) {
          r = {
            success: false,
            message: "مسیر فایل برای ارسال تلگرام پیدا نشد.",
          };
        } else {
          r = await trySendTelegramMediaNow(
            msgType as any,
            String(fileRelPath),
            text,
            effectiveChatId || null,
            {
              parseMode,
              replyMarkup,
              replyToMessageId: replyToMessageId || undefined,
              mimeType,
            },
          );
        }
      } else {
        r = await trySendTelegramNow(text, effectiveChatId, {
          parseMode,
          replyMarkup,
        });
      }

      try {
        await insertSmsLog({
          reqUser: req.user,
          provider: "telegram",
          eventType: "OUTBOX_SEND_TEST",
          entityType: row.entityType || "telegram",
          entityId: row.entityId ?? null,
          recipient: effectiveChatId,
          patternId: "TELEGRAM_TEST",
          tokens: [text],
          success: !!r?.success,
          response: r,
          error: r?.success ? undefined : r?.message,
        });
      } catch {}

      if (r?.success) {
        const telegramMessageId =
          Number((r as any)?.data?.result?.message_id || 0) || null;
        await runAsync(
          `UPDATE notification_outbox SET status='done', lastError=NULL, telegramMessageId=COALESCE(?, telegramMessageId), updatedAt=strftime('%Y-%m-%dT%H:%M:%SZ','now','utc') WHERE id=?`,
          [telegramMessageId, id],
        ).catch(() => {});
        return res.json({
          success: true,
          message: "پیام بررسی ارسال شد.",
          data: r,
        });
      }

      await runAsync(
        `UPDATE notification_outbox SET status='failed', attempts=COALESCE(attempts,0)+1, lastError=?, nextAttemptAt=?, updatedAt=strftime('%Y-%m-%dT%H:%M:%SZ','now','utc') WHERE id=?`,
        [
          String(r?.message || "ارسال بررسی انجام نشد."),
          moment().add(30, "seconds").toISOString(),
          id,
        ],
      ).catch(() => {});
      return res.json({
        success: false,
        message: r?.message || "ارسال بررسی انجام نشد.",
        data: r,
      });
    } catch (e: any) {
      return res.json({
        success: false,
        message: e?.message || "ارسال بررسی انجام نشد.",
      });
    }
  },
);
// Telegram Inbox list
app.get(
  "/api/telegram/inbox",
  authorizeRole(["Admin", "Manager"]),
  async (req, res, next) => {
    try {
      await ensureTelegramInboxTable();
      await ensureCustomerTelegramColumns();
      const limit = Math.min(
        parseInt(String(req.query.limit || "200"), 10) || 200,
        500,
      );
      const chatId = String(req.query.chatId || "").trim();
      const from = String(req.query.from || "").trim();
      const to = String(req.query.to || "").trim();
      const q = String(req.query.q || "")
        .trim()
        .toLowerCase();
      const where: string[] = [];
      const args: any[] = [];
      if (chatId) {
        where.push(`ti.chatId=?`);
        args.push(chatId);
      }
      if (from) {
        where.push(`datetime(ti.createdAt) >= datetime(?)`);
        args.push(from);
      }
      if (to) {
        where.push(`datetime(ti.createdAt) <= datetime(?)`);
        args.push(to);
      }
      const rows: any[] = await allAsync(
        `SELECT
          ti.id, ti.chatId, ti.fromId, ti.kind, ti.text, ti.createdAt,
          c.id AS customerId,
          c.fullName AS customerName,
          c.phoneNumber AS customerPhone,
          COALESCE(c.telegram_opted_out,0) AS telegramOptedOut
       FROM telegram_inbox ti
       LEFT JOIN customers c
         ON (COALESCE(c.telegram_chat_id, c.telegramChatId) = ti.chatId)
       ${where.length ? `WHERE ${where.join(" AND ")}` : ""}
       ORDER BY ti.id DESC
       LIMIT ?`,
        [...args, limit],
      );
      const filtered = (rows || []).filter((r) => {
        if (!q) return true;
        const hay = [
          r.id,
          r.chatId,
          r.fromId,
          r.kind,
          r.text,
          r.customerId,
          r.customerName,
          r.customerPhone,
        ]
          .filter(Boolean)
          .join(" ")
          .toLowerCase();
        return hay.includes(q);
      });
      res.json({ success: true, data: filtered });
    } catch (e) {
      next(e);
    }
  },
);
// Telegram Conversation (Inbox + Outbox merged) for a specific customer or partner
app.get(
  "/api/telegram/conversation",
  authorizeRole(["Admin", "Manager"]),
  async (req, res, next) => {
    try {
      await ensureTelegramInboxTable();
      await ensureNotificationOutboxTables();
      await ensureCustomerTelegramColumns();
      const customerId = Number(req.query.customerId || 0);
      const partnerId = Number(req.query.partnerId || 0);
      const limit = Math.min(
        parseInt(String(req.query.limit || "250"), 10) || 250,
        800,
      );
      if (!customerId && !partnerId)
        return res.status(400).json({
          success: false,
          message: "شناسه مشتری یا همکار نامعتبر است.",
        });

      let chatId = "";
      let c: any = null;
      let p: any = null;
      if (partnerId) {
        p = await getAsync(
          `SELECT id, partnerName, phoneNumber, telegramChatId
         FROM partners WHERE id=? LIMIT 1`,
          [partnerId],
        );
        if (!p)
          return res
            .status(404)
            .json({ success: false, message: "همکار پیدا نشد." });
        chatId = String(p?.telegramChatId || "").trim();
      } else {
        c = await getAsync(
          `SELECT id, fullName, phoneNumber,
                COALESCE(telegram_chat_id, telegramChatId) AS telegramChatId,
                COALESCE(telegram_opted_out,0) AS telegramOptedOut,
                COALESCE(telegram_invalid,0) AS telegramInvalid,
                telegram_invalid_reason AS telegramInvalidReason
         FROM customers WHERE id=? LIMIT 1`,
          [customerId],
        );
        if (!c)
          return res
            .status(404)
            .json({ success: false, message: "مشتری پیدا نشد." });
        chatId = String(c?.telegramChatId || "").trim();
      }
      const inboxRows: any[] = chatId
        ? await allAsync(
            `SELECT id, chatId, fromId, kind, text, payloadJson, createdAt
           FROM telegram_inbox
           WHERE chatId=?
           ORDER BY id DESC
           LIMIT ?`,
            [chatId, Math.floor(limit / 2)],
          )
        : [];
      const outboxRows: any[] = partnerId
        ? await allAsync(
            `SELECT id, channel, eventType, entityType, entityId, recipient, payloadJson, status, attempts, lastError, telegramMessageId, createdAt, updatedAt
           FROM notification_outbox
           WHERE channel='telegram' AND entityType='partner' AND entityId=?
           ORDER BY id DESC
           LIMIT ?`,
            [partnerId, Math.floor(limit / 2)],
          )
        : await allAsync(
            `SELECT id, channel, eventType, entityType, entityId, recipient, payloadJson, status, attempts, lastError, telegramMessageId, createdAt, updatedAt
           FROM notification_outbox
           WHERE channel='telegram' AND capCustomerId=?
           ORDER BY id DESC
           LIMIT ?`,
            [customerId, Math.floor(limit / 2)],
          );
      const safeJson = (s: any) => {
        try {
          return s ? JSON.parse(String(s)) : null;
        } catch {
          return null;
        }
      };
      const classifyError = (msg: string) => {
        const m = String(msg || "").toLowerCase();
        if (!m) return undefined;
        if (m.includes("blocked") || m.includes("bot was blocked"))
          return "blocked";
        if (m.includes("chat not found") || m.includes("user not found"))
          return "chat_not_found";
        if (
          m.includes("proxy") ||
          m.includes("socks") ||
          m.includes("econnrefused") ||
          m.includes("timeout")
        )
          return "proxy_error";
        return "other";
      };
      const inbox = (inboxRows || []).map((r) => {
        const p = safeJson(r.payloadJson);
        // Telegram update payload usually has update.message.message_id
        const messageId =
          Number(
            p?.message?.message_id ||
              p?.edited_message?.message_id ||
              p?.callback_query?.message?.message_id ||
              p?.message_id ||
              0,
          ) || null;
        const hasPhoto =
          Array.isArray(p?.message?.photo) && p.message.photo.length > 0;
        const hasDoc = !!p?.message?.document;
        const kind = hasPhoto
          ? "photo"
          : hasDoc
            ? "document"
            : r.kind || "message";
        return {
          id: `in_${r.id}`,
          direction: "in",
          kind,
          text: String(r.text || ""),
          telegramMessageId: messageId,
          createdAt: r.createdAt,
        };
      });
      const outbox = (outboxRows || []).map((r) => {
        const payload = safeJson(r.payloadJson) || {};
        const msgType = String(payload?.type || "message");
        const text = String(
          payload?.text ??
            payload?.caption ??
            payload?.message ??
            payload?.body ??
            payload?.tokens?.[0] ??
            "",
        );
        const parseMode = payload?.parse_mode || payload?.parseMode;
        const fileRelPath =
          payload?.fileRelPath || payload?.filePath || payload?.relPath || null;
        const mediaUrl = fileRelPath
          ? String(fileRelPath).startsWith("/")
            ? String(fileRelPath)
            : `/${String(fileRelPath)}`
          : null;
        return {
          id: `out_${r.id}`,
          direction: "out",
          kind:
            msgType === "photo" || msgType === "document" ? msgType : "message",
          text,
          mediaUrl,
          parseMode,
          telegramMessageId: Number(r.telegramMessageId || 0) || null,
          status: r.status,
          attempts: Number(r.attempts || 0),
          lastError: r.lastError || null,
          errorCategory: classifyError(r.lastError),
          createdAt: r.createdAt,
          updatedAt: r.updatedAt,
        };
      });
      const merged = [...inbox, ...outbox]
        .filter((x) => x?.createdAt)
        .sort((a: any, b: any) => {
          const ta = +new Date(a.createdAt);
          const tb = +new Date(b.createdAt);
          if (ta === tb) return String(a.id).localeCompare(String(b.id));
          return ta - tb;
        });
      const summary = {
        total: merged.length,
        inbox: inbox.length,
        outbox: outbox.length,
        failed: outbox.filter((x: any) => String(x.status || "") === "failed")
          .length,
        pending: outbox.filter((x: any) =>
          ["pending", "processing"].includes(String(x.status || "")),
        ).length,
        lastInteractionAt: merged.length
          ? merged[merged.length - 1]?.createdAt
          : null,
      };

      res.json({
        success: true,
        meta: partnerId
          ? {
              partnerId,
              chatId,
              partnerName: p?.partnerName || "",
              phoneNumber: p?.phoneNumber || "",
              telegramOptedOut: false,
              telegramInvalid: false,
              telegramInvalidReason: null,
              summary,
            }
          : {
              customerId,
              chatId,
              telegramOptedOut: Number(c.telegramOptedOut || 0) === 1,
              telegramInvalid: Number(c.telegramInvalid || 0) === 1,
              telegramInvalidReason: c.telegramInvalidReason || null,
              summary,
            },
        data: merged,
      });
    } catch (e) {
      next(e);
    }
  },
);
/**
 * Telegram ↔ Customer quick actions (for Inbox support UX)
 * - link: assign chatId to a customer (and clear it from any other customer)
 * - unlink: remove chatId/userId and opt-out (optional)
 * - optout: toggle opt-out flag
 */
app.post(
  "/api/telegram/customers/link",
  authorizeRole(["Admin", "Manager"]),
  async (req, res, next) => {
    try {
      await ensureCustomerTelegramColumns();
      const customerId = Number(req.body?.customerId || 0);
      const chatId = String(req.body?.chatId || "").trim();
      const fromId = String(req.body?.fromId || "").trim();
      if (!customerId)
        return res
          .status(400)
          .json({ success: false, message: "customerId نامعتبر است." });
      if (!chatId)
        return res
          .status(400)
          .json({ success: false, message: "chatId خالی است." });
      // Ensure customer exists
      const c = await getAsync(`SELECT id FROM customers WHERE id=? LIMIT 1`, [
        customerId,
      ]);
      if (!c)
        return res
          .status(404)
          .json({ success: false, message: "مشتری پیدا نشد." });
      // Clear chatId from other customers to keep 1:1 mapping
      await runAsync(
        `UPDATE customers
       SET telegram_chat_id=NULL, telegramChatId=NULL, telegram_user_id=NULL, telegram_linked_at=NULL
       WHERE COALESCE(telegram_chat_id, telegramChatId)=? AND id<>?`,
        [chatId, customerId],
      );
      await runAsync(
        `UPDATE customers
       SET telegram_chat_id=?,
           telegramChatId=?,
           telegram_user_id=?,
           telegram_linked_at=strftime('%Y-%m-%dT%H:%M:%SZ','now','utc'),
           telegram_opted_out=0
       WHERE id=?`,
        [chatId, chatId, fromId || null, customerId],
      );
      res.json({ success: true });
    } catch (e) {
      next(e);
    }
  },
);
