// Send a check message for a template to topic chat ids
app.post(
  "/api/telegram/topic-config/:topic/check",
  authorizeRole(["Admin", "Manager"]),
  async (req, res, next) => {
    try {
      const topic = String(req.params.topic || "").trim();
      if (!TOPIC_CHATID_KEYS[topic])
        return res
          .status(400)
          .json({ success: false, message: "Topic نامعتبر است." });
      const type = String(req.body?.type || "").trim();
      const tpl = String(req.body?.template || "").trim();
      if (!type)
        return res
          .status(400)
          .json({ success: false, message: "نوع پیام مشخص نیست." });
      const settings = await getAllSettingsAsObject();
      setTelegramProxy((settings as any).telegram_proxy);
      const botToken = String(settings.telegram_bot_token || "").trim();
      if (!botToken)
        return res
          .status(400)
          .json({ success: false, message: "توکن تلگرام تنظیم نشده است." });
      const { chatIds } = await getTelegramTargetsForTopic(topic as any);
      if (!chatIds.length)
        return res.status(400).json({
          success: false,
          message: "Chat ID مقصد برای این بخش تنظیم نشده است.",
        });
      const sample = await getSampleVarsForTopic(topic);
      const baseUrl = String(settings.app_base_url || "").trim();
      const link =
        topic === "sales"
          ? `${baseUrl}/#/sales`
          : topic === "installments"
            ? `${baseUrl}/#/installment-sales`
            : `${baseUrl}/#/reports`;
      const vars = {
        ...sample,
        link,
        now: moment().locale("fa").format("jYYYY/jMM/jDD HH:mm"),
      };
      const text = safeReplaceTemplate(tpl, vars);
      const results: any[] = [];
      let sent = 0;
      for (const cid of chatIds) {
        const r = await sendTelegramMessage(
          botToken,
          cid,
          sanitizeTelegramHtml(markdownishToHtml(text)),
          { parseMode: "HTML" },
        );
        results.push({
          chatId: cid,
          success: !!(r as any)?.success,
          message: (r as any)?.message,
        });
        if ((r as any)?.success) sent++;
      }
      return res.json({
        success: true,
        data: { sent, total: chatIds.length, results },
      });
    } catch (e) {
      next(e);
    }
  },
);
// ارسال بررسی پیام تلگرام (متن ساده)
app.post(
  "/api/telegram/check-message",
  authorizeRole(["Admin", "Manager"]),
  async (req, res, next) => {
    try {
      const { text, parseMode } = req.body || {};
      const settings = await getAllSettingsAsObject();
      setTelegramProxy((settings as any).telegram_proxy);
      const botToken = String(settings.telegram_bot_token || "").trim();
      const chatId = String(settings.telegram_chat_id || "").trim();
      if (!botToken || !chatId)
        return res.status(400).json({
          success: false,
          message: "توکن ربات یا Chat ID تلگرام تنظیم نشده است.",
        });
      const correlationId = makeCorrId();
      const pmRaw = String(parseMode || "").trim();
      const pm =
        pmRaw === "HTML" || pmRaw === "Markdown" || pmRaw === "MarkdownV2"
          ? (pmRaw as any)
          : undefined;
      let msg = String(text || "").trim();
      if (!msg)
        return res
          .status(400)
          .json({ success: false, message: "متن پیام خالی است." });
      if (pm === "HTML") msg = sanitizeTelegramHtml(msg);
      // for Markdown modes, at least drop raw tags
      if (pm === "Markdown" || pm === "MarkdownV2") msg = stripTags(msg);
      const result = await sendTelegramMessage(botToken, chatId, msg, {
        parseMode: pm,
      });
      // log like sms_logs for uniform audit
      try {
        await insertSmsLog({
          reqUser: req.user,
          provider: "telegram",
          eventType: "TEST_MESSAGE",
          entityType: "telegram",
          entityId: null as any,
          recipient: chatId,
          patternId: `TELEGRAM_${pm || "TEXT"}`,
          tokens: [msg],
          success: !!result?.success,
          response: result,
          correlationId,
          request: {
            action: "sendMessage",
            chatId,
            parseMode: pm || "TEXT",
            textLength: msg.length,
          },
          httpStatus:
            (result as any)?.details?.httpStatus ?? (result as any)?.status,
          rawResponseText:
            (result as any)?.details?.rawResponseText ??
            (result as any)?.rawText,
          durationMs: (result as any)?.details?.durationMs,
          error: result?.success ? undefined : result?.message,
        });
      } catch {}
      if (result?.success)
        return res.json({
          success: true,
          message: "پیام تلگرام ارسال شد.",
          data: result,
        });
      return res.json({
        success: false,
        message: result?.message || "خطا در ارسال تلگرام",
        data: result,
      });
    } catch (e) {
      next(e);
    }
  },
);
// Telegram Logs (بر اساس sms_logs اما فقط provider=telegram)
// =====================================================
// Customer Telegram Actions (Customer Card)
// =====================================================
app.post(
  "/api/telegram/customer-actions/retry-outbox",
  authorizeRole(["Admin", "Manager"]),
  async (req, res, next) => {
    try {
      await ensureNotificationOutboxTables();
      const outboxIdRaw = String(req.body?.outboxId || "")
        .trim()
        .replace(/^out_/, "");
      const outboxId = Number(outboxIdRaw || 0);
      if (!outboxId)
        return res
          .status(400)
          .json({ success: false, message: "شناسه پیام نامعتبر است." });

      const row = (await getAsync(
        `SELECT id, channel, entityType, entityId, recipient, payloadJson, status, attempts, lastError
         FROM notification_outbox
        WHERE id=? AND channel='telegram'
        LIMIT 1`,
        [outboxId],
      )) as any;
      if (!row)
        return res
          .status(404)
          .json({ success: false, message: "پیام تلگرام یافت نشد." });

      const safeJson = (s: any) => {
        try {
          return s ? JSON.parse(String(s)) : null;
        } catch {
          return null;
        }
      };
      const payload = safeJson(row.payloadJson) || {};
      const chatId = String(row.recipient || payload.chatId || "").trim();
      if (!chatId)
        return res.status(400).json({
          success: false,
          message: "Chat ID برای ارسال مجدد موجود نیست.",
        });

      await runAsync(
        `UPDATE notification_outbox
          SET status='pending', attempts=0, nextAttemptAt=strftime('%Y-%m-%dT%H:%M:%SZ','now','utc'), lastError=NULL, updatedAt=strftime('%Y-%m-%dT%H:%M:%SZ','now','utc')
        WHERE id=?`,
        [outboxId],
      );

      const delivered = await tryDeliverQueuedTelegramNow(
        { id: outboxId, queued: true },
        payload,
        chatId,
      );
      try {
        addAuditLog(
          req.user?.id,
          req.user?.username,
          req.user?.roleName,
          "retry",
          "telegram_outbox",
          outboxId,
          "ارسال مجدد پیام تلگرام",
        );
      } catch {}

      res.json({ success: true, data: delivered });
    } catch (e) {
      next(e);
    }
  },
);

app.post(
  "/api/telegram/customer-actions/send-manual",
  authorizeRole(["Admin", "Manager"]),
  async (req, res, next) => {
    try {
      await ensureNotificationOutboxTables();
      await ensureCustomerTelegramColumns();
      const customerId = Number(req.body?.customerId || 0);
      const textRaw = String(req.body?.text || "").trim();
      const parseModeRaw = String(req.body?.parseMode || "").trim();
      const parseMode =
        parseModeRaw === "HTML" ||
        parseModeRaw === "Markdown" ||
        parseModeRaw === "MarkdownV2"
          ? (parseModeRaw as any)
          : "HTML";
      const attachment = (req.body as any)?.attachment || null;
      const replyToMessageId =
        Number((req.body as any)?.replyToMessageId || 0) || 0;
      if (!customerId)
        return res
          .status(400)
          .json({ success: false, message: "customerId نامعتبر است." });
      if (!textRaw && !attachment)
        return res.status(400).json({
          success: false,
          message: "متن پیام یا فایل باید ارسال شود.",
        });
      const c = (await getAsync(
        `SELECT id, fullName, phoneNumber,
              COALESCE(telegram_opted_out,0) AS telegram_opted_out,
              COALESCE(telegram_chat_id, telegramChatId) AS tg_chat_id
       FROM customers WHERE id=? LIMIT 1`,
        [customerId],
      )) as any;
      if (!c)
        return res
          .status(404)
          .json({ success: false, message: "مشتری یافت نشد." });
      if (Number(c.telegram_opted_out || 0) === 1)
        return res.status(400).json({
          success: false,
          message: "این مشتری از تلگرام opt-out کرده است.",
        });
      const chatId = String(c?.tg_chat_id || "").trim();
      if (!chatId)
        return res.status(400).json({
          success: false,
          message: "این مشتری به تلگرام لینک نشده است.",
        });
      let text = textRaw;
      if (parseMode === "HTML") text = sanitizeTelegramHtml(text);
      if (parseMode === "Markdown" || parseMode === "MarkdownV2")
        text = stripTags(text);
      // Attachment support (photo/document) + reply-to
      const hasAtt = attachment && typeof attachment === "object";
      const attType = hasAtt ? String(attachment.type || "").toLowerCase() : "";
      const attRelPath = hasAtt
        ? String(attachment.relPath || attachment.path || "").trim()
        : "";
      const attMime = hasAtt ? String(attachment.mimeType || "").trim() : "";
      const attOriginal = hasAtt
        ? String(attachment.originalName || "").trim()
        : "";
      const payload: any = {
        chatId,
        parseMode,
        capCustomerId: customerId,
        replyToMessageId: replyToMessageId || undefined,
      };
      if (hasAtt) {
        if (!(attType === "photo" || attType === "document")) {
          return res
            .status(400)
            .json({ success: false, message: "نوع فایل نامعتبر است." });
        }
        if (!attRelPath) {
          return res
            .status(400)
            .json({ success: false, message: "مسیر فایل ارسال نشده است." });
        }
        payload.type = attType;
        payload.fileRelPath = attRelPath;
        payload.mimeType = attMime || undefined;
        payload.originalName = attOriginal || undefined;
        payload.caption = text || "";
      } else {
        payload.type = "message";
        payload.text = text;
      }
      const queued = await enqueueOutbox({
        channel: "telegram",
        provider: "telegram",
        eventType: "CUSTOMER_MANUAL",
        entityType: "customer",
        entityId: customerId,
        recipient: chatId,
        payload,
        dedupeToday: false,
        maxAttempts: 6,
        skipCustomerRateLimit: true,
        skipInvalidChatCheck: true,
      });
      const delivered = await tryDeliverQueuedTelegramNow(
        queued,
        payload,
        chatId,
      );
      return res.json({ success: true, data: delivered });
    } catch (e) {
      next(e);
    }
  },
);
